/* 七訣鬥法題庫 · 236 題（每日試煉 49 + 快問快答 28 + 心之深淵闖關站轉入 159）
   h = 習慣索引 0-6；每題四選項 q 0(正解)/1(差一層)/2(誘答)/3(墮道) 各一，tag=柯維講評 */
window.DUEL_QS=[{"h": 0, "text": "月考成績發下，你低於預期。同窗都在抱怨題目太難、老師教得爛。", "c": [{"t": "跟著同學一起罵題目太刁，先求心裡痛快", "q": 2, "tag": "罵完痛快一時，問題原封不動——你把力氣花在管不動的「關注圈」，而非自己能改變的「影響圈」。"}, {"t": "先找出錯在哪，列三個弱點排進本週複習", "q": 0, "tag": "✓ 這就是主動積極：不怪環境，把焦點收回到自己能負責、能改變的事情上。"}, {"t": "把考卷收進抽屜假裝沒事，眼不見為淨", "q": 3, "tag": "⚠ 逃避看似輕鬆，卻是把成長的機會親手丟掉——下次同樣的坑你還會再掉一次。"}, {"t": "告訴自己下次再努力，但沒排具體計畫", "q": 1, "tag": "◐ 心態對了，差在沒落地。主動不只是想法，更是「現在就做一件具體的事」。"}]}, {"h": 0, "text": "走廊上有人故意撞你還嗆聲，圍觀的人都在看你怎麼反應。", "c": [{"t": "當場回嗆回去，氣勢上絕不能輸他", "q": 2, "tag": "回嗆看似不吃虧，其實你已被對方牽著走——你的反應由他決定，主動權拱手讓人。"}, {"t": "約人放學堵他，讓他知道惹你的下場", "q": 3, "tag": "⚠ 以暴制暴，看似出氣，卻可能釀成更大的禍，把自己也賠進去。"}, {"t": "深吸一口氣選擇不動怒，事後循正當管道處理", "q": 0, "tag": "✓ 刺激與回應之間，永遠有一段空隙，那裡住著你的選擇權——這就是主動積極。"}, {"t": "當下忍住，但整天悶悶不樂，回家越想越氣", "q": 1, "tag": "◐ 忍住是好的開始，但情緒仍被他綁架。真正的主動，是把怒氣轉成下一步行動。"}]}, {"h": 0, "text": "一份報告下週要交，你卻遲遲不想動手，總覺得「明天再說」。", "c": [{"t": "等到比較有靈感的那天，再一次寫完", "q": 2, "tag": "把開工的鑰匙交給「靈感」，等於把人生交給運氣——主動的人創造心情，而非等待心情。"}, {"t": "排好完整計畫表，但今天仍一個字沒寫", "q": 1, "tag": "◐ 計畫是準備，不是行動。再美的表格，沒有第一個字，都還停在原地。"}, {"t": "今天先動手寫開頭十分鐘，破除拖延慣性", "q": 0, "tag": "✓ 主動積極不必等情緒到位——先動起來，動力往往是「做了之後」才出現的。"}, {"t": "反正最後一晚爆肝也生得出來，先玩", "q": 3, "tag": "⚠ 賭最後一晚，看似輕鬆，實則把品質與健康一起押上賭桌，常常翻車。"}]}, {"h": 1, "text": "開學要選社團，朋友揪你進最熱鬧的那個，但你其實另有想學的東西。", "c": [{"t": "哪個社團朋友多就選哪個，反正不孤單", "q": 2, "tag": "以「熱鬧」為準，而非以「你想去的終點」為準——熱鬧散場後，你離想成為的自己更遠了。"}, {"t": "先想清楚自己想成為什麼樣的人，再決定", "q": 0, "tag": "✓ 以終為始：先看見終點，再回推今天該怎麼選，每一步才會走在自己的方向上。"}, {"t": "全部都報名，到時再看心情翹掉幾個", "q": 3, "tag": "⚠ 看似保留彈性，其實心力被攤平稀釋，最後哪個都沒投入，也辜負了名額。"}, {"t": "列了想學的清單，最後仍隨朋友起鬨決定", "q": 1, "tag": "◐ 你已看見終點，卻在最後一刻被當下帶走——以終為始，貴在「真的依它而行」。"}]}, {"h": 1, "text": "你每天都很忙，唸了很多卻不知道為什麼念，成效也普通。", "c": [{"t": "跟著進度表一頁頁念，念到哪算到哪", "q": 2, "tag": "有行程不等於有方向——沒有終點的努力，像划船卻不看岸，划得越久偏得越遠。"}, {"t": "哪科老師兇就念哪科，其餘全隨緣", "q": 3, "tag": "⚠ 用恐懼當導航，方向錯亂；你忙的是別人給的壓力，不是自己要去的地方。"}, {"t": "知道該設目標，卻一直拖著沒寫下來", "q": 1, "tag": "◐ 認同要設終點，卻遲遲不肯定下來——目標不寫下，就只是模糊的願望。"}, {"t": "先定下這學期的具體目標，再安排讀法", "q": 0, "tag": "✓ 以終為始：先確立想抵達的終點，努力才有羅盤，每分力氣都用在刀口上。"}]}, {"h": 1, "text": "你存了一陣子的零用錢，剛好看到限定款的東西很想買。", "c": [{"t": "先想自己真正想用這筆錢成就什麼再決定", "q": 0, "tag": "✓ 以終為始：讓今天的每一筆花費，都服務於你心裡更想望的那個未來。"}, {"t": "趁限定還在先買，之後再煩惱錢的事", "q": 2, "tag": "被「限定」兩個字綁架，正是衝動消費的圈套——你買的常是焦慮，不是真需要。"}, {"t": "刷掉所有存款，沒錢再跟人借就好", "q": 3, "tag": "⚠ 透支未來換當下快感，看似豪爽，實則親手挖了一個更深的坑給自己。"}, {"t": "心裡有更想要的，卻還是先買了眼前這個", "q": 1, "tag": "◐ 終點看得清，卻被眼前的衝動蓋過——以終為始，難在抵住「現在就要」的拉力。"}]}, {"h": 2, "text": "回家後有重要作業要做，但手機一直跳出有趣的訊息與影片。", "c": [{"t": "先回完所有訊息，覺得清空了再開始", "q": 2, "tag": "訊息緊急卻不重要——你被「急」綁住，把真正重要的事一直往後推。"}, {"t": "先把重要作業完成，再安心享受娛樂", "q": 0, "tag": "✓ 要事第一：先做重要而不緊急的事，娛樂才會變成獎賞，而不是逃避。"}, {"t": "今天先放鬆，作業留到明天早自習趕", "q": 3, "tag": "⚠ 把要事一直延後，債只會越滾越大，最後在最慌的時刻草草交差。"}, {"t": "一邊寫作業一邊滑手機，兩件都不專心", "q": 1, "tag": "◐ 想兼顧，結果都打折。要事第一的關鍵，是「一次只專注一件最重要的事」。"}]}, {"h": 2, "text": "段考、比賽報名、家事同時壓來，你不知從何下手。", "c": [{"t": "挑最簡單的先做，享受劃掉的快感", "q": 2, "tag": "用「難易」而非「重要性」排序，是最甜的陷阱——劃掉一堆小事，最重要的卻動都沒動。"}, {"t": "樣樣都想做，結果每件都只做一半", "q": 3, "tag": "⚠ 不分輕重全抓，心力被撕碎，最後全盤皆輸——這是沒有要事第一的下場。"}, {"t": "分辨輕重緩急，先處理最重要的一兩件", "q": 0, "tag": "✓ 要事第一：依「重要性」而非「緊急或難易」排序，把第一塊大石頭先放進瓶子。"}, {"t": "列了待辦清單，卻沒標出哪件最重要", "q": 1, "tag": "◐ 有清單是好的，但沒有優先序，清單只會讓你更焦慮。重點是「先做哪一件」。"}]}, {"h": 2, "text": "你早就排好今晚要準備明天的重要報告，朋友臨時揪你出去玩。", "c": [{"t": "婉拒並約改天，守住自己排定的要事", "q": 0, "tag": "✓ 要事第一最難的一課，是對「不重要但誘人的事」勇敢說不，才能對重要的事說是。"}, {"t": "想說人情難卻，先去一下下就好了", "q": 2, "tag": "「就一下下」常是破口——被人情推著走，原訂的要事就這樣被擠掉了。"}, {"t": "報告哪算什麼，玩一整晚明天再說", "q": 3, "tag": "⚠ 放棄要事換一時熱鬧，明天的慌亂與後悔，會把今晚的快樂全部討回去。"}, {"t": "去玩但心裡掛念，回來累到草草做完", "q": 1, "tag": "◐ 沒守住界線，玩也玩不安心，做也做不好——兩頭落空，正因要事沒擺第一。"}]}, {"h": 3, "text": "小組報告要分工，大家都想避開最麻煩的資料整理。", "c": [{"t": "搶先挑走最輕鬆的，剩下讓別人分", "q": 2, "tag": "利己損人，是「我贏你輸」的思維——這次你佔了便宜，下次沒人願意跟你同組。"}, {"t": "提出讓大家發揮所長、共同受益的分工", "q": 0, "tag": "✓ 雙贏思維：不是分餅，而是一起把餅做大，找出彼此都更好的第三條路。"}, {"t": "擺爛拖到最後，逼別人替你收尾", "q": 3, "tag": "⚠ 兩敗俱傷：報告做不好，關係也毀了——這是雙輸，傷得最重的其實是你。"}, {"t": "自己默默扛下最難的，心裡卻很委屈", "q": 1, "tag": "◐ 犧牲自己成全別人是「損己利人」，不是雙贏；長期委屈會讓合作走不遠。"}]}, {"h": 3, "text": "你和同學都想借唯一一本參考書，期限只能一人先借。", "c": [{"t": "用各種理由說服自己應該先拿", "q": 2, "tag": "一心只想自己贏，便會替「我先」找出一堆藉口——這是匱乏心態，怕別人多拿就是自己少拿。"}, {"t": "偷偷先藏起來，讓對方根本借不到", "q": 3, "tag": "⚠ 你贏了一本書，卻輸掉了人品與信任，代價比那本書貴太多了。"}, {"t": "商量輪流借閱的時段，讓兩人都用得到", "q": 0, "tag": "✓ 雙贏思維：資源看似有限，但用點巧思，常能找到讓彼此都受益的安排。"}, {"t": "禮讓對方先借，自己乾等卻有點不甘", "q": 1, "tag": "◐ 退讓是善意，但心不甘情不願就不是真雙贏；雙贏是兩邊都覺得好，不是一方忍。"}]}, {"h": 3, "text": "班際比賽，隔壁隊實力強，有人提議去打聽並破壞對方準備。", "c": [{"t": "偷瞄對方戰術，好讓自己佔點便宜", "q": 2, "tag": "把心思放在「比贏對方」而非「讓自己更強」，贏了也虛——你錯過了真正變強的機會。"}, {"t": "專注把自己這隊練到最好，光明對決", "q": 0, "tag": "✓ 真正的競爭仍守正道：把對手當成讓自己更強的磨刀石，這才是雙贏的精神。"}, {"t": "加入扯後腿的計畫，先搞垮對方隊", "q": 3, "tag": "⚠ 贏得骯髒，既學不到真本事，也輸掉了品格——這種勝利不值一文。"}, {"t": "不參與破壞，但也提不起勁好好練", "q": 1, "tag": "◐ 不害人是底線，但消極不投入，等於放棄了和對手互相成全、一起變強的可能。"}]}, {"h": 4, "text": "朋友難過地跟你說他的煩惱，你腦中已經冒出一堆建議。", "c": [{"t": "馬上打斷給一堆建議，要他照做", "q": 2, "tag": "急著給答案，是急著「被理解」而非「先理解」——他要的常是被聽見，不是被指導。"}, {"t": "先專心聽完、理解他的感受，再回應", "q": 0, "tag": "✓ 知彼解己：先求理解，再求被理解。聽懂對方，比急著表達自己重要得多。"}, {"t": "敷衍兩句叫他想開點，轉頭滑手機", "q": 3, "tag": "⚠ 看似省事，卻讓朋友覺得不被在乎——關係就是這樣一次次被疏遠的。"}, {"t": "邊聽邊想等下要講的話，沒聽進去", "q": 1, "tag": "◐ 這是「假裝在聽」：耳朵開著，心卻在準備自己的台詞，對方一秒就感覺得到。"}]}, {"h": 4, "text": "爸媽反對你的某個決定，氣氛一觸即發。", "c": [{"t": "急著辯解自己有理，沒問他們為何反對", "q": 2, "tag": "只想被懂、不想懂人，溝通就變成各說各話——你贏了道理，輸了關係。"}, {"t": "摔門大吼說你們不懂我，斷了對話", "q": 3, "tag": "⚠ 把唯一的溝通管道也砸斷，問題不但沒解決，誤會還會越積越深。"}, {"t": "先聽懂他們擔心什麼，再說明自己想法", "q": 0, "tag": "✓ 知彼解己：先理解對方在怕什麼，對話才有空間，你的想法也才聽得進去。"}, {"t": "表面點頭聽，心裡完全沒打算理解", "q": 1, "tag": "◐ 形式上的「聽」騙不了人；沒有真心想懂，點再多頭也通不了。"}]}, {"h": 4, "text": "你聽說某同學在背後說你壞話，越想越氣。", "c": [{"t": "直接向別人轉述，先讓大家站你這邊", "q": 2, "tag": "急著被理解、急著拉幫手，卻散播了還沒查證的事——你可能正在製造真正的傷害。"}, {"t": "找機會私下問清楚，先了解事情全貌", "q": 0, "tag": "✓ 知彼解己：先求理解事實，再下判斷。很多怨恨，都源自一個沒問清楚的誤會。"}, {"t": "當眾翻臉開罵，先發制人不吃虧", "q": 3, "tag": "⚠ 在誤會未明時先發制人，常把假的變成真的，親手撕裂一段本可挽回的友誼。"}, {"t": "心裡先信了一半，見面卻假裝沒事", "q": 1, "tag": "◐ 沒求證就暗自記恨，等於讓謠言替你下了結論——表面平靜，心裡早已築牆。"}]}, {"h": 5, "text": "班會討論活動方案，大家點子不同，場面有點僵。", "c": [{"t": "堅持自己的版本，要大家配合就好", "q": 2, "tag": "用自己的意見壓過所有差異，看似有效率，卻浪費了眾人腦袋裡更好的可能。"}, {"t": "把不同點子整合成一個更好的新方案", "q": 0, "tag": "✓ 統合綜效：1+1 可以大於 2。差異不是阻礙，而是激出更好答案的養分。"}, {"t": "嫌太麻煩，乾脆各做各的誰也不理", "q": 3, "tag": "⚠ 放棄合作，等於把全班的智慧丟進垃圾桶——最後每個人都更累，成果更差。"}, {"t": "直接投票多數決，少數意見就捨棄", "q": 1, "tag": "◐ 投票是妥協，不是綜效；被捨棄的那票，也許正藏著最關鍵的那塊拼圖。"}]}, {"h": 5, "text": "分組時你和一個做事風格完全相反的同學被分在一起。", "c": [{"t": "想辦法讓他照你的方式來做事", "q": 2, "tag": "要對方變成另一個自己，就消滅了差異的價值——綜效要的不是統一，是互補。"}, {"t": "嫌他礙手礙腳，乾脆把他晾一邊", "q": 3, "tag": "⚠ 排斥差異、把人晾著，團隊很快瓦解；你失去的，是他能補上的那一塊。"}, {"t": "找出彼此長處互補，分工發揮所長", "q": 0, "tag": "✓ 統合綜效：尊重彼此的不同，讓差異變成互補，整體就會大於各自相加。"}, {"t": "勉強合作，但各做各的不太交流", "q": 1, "tag": "◐ 這是「合而不作」：人湊在一起，心沒有交流，自然產生不了綜效的火花。"}]}, {"h": 5, "text": "一道難題你怎麼都解不出，旁邊同學剛好擅長這科。", "c": [{"t": "請同學直接講答案，但沒交流為什麼", "q": 1, "tag": "◐ 拿到答案卻沒交流思路，1+1 只等於 1——少了想法的碰撞，就少了綜效。"}, {"t": "自己硬撐到底，怎樣都不肯開口求助", "q": 2, "tag": "一味靠自己硬扛、拒絕協作，看似有骨氣，其實白白錯過了更快更好的可能。"}, {"t": "直接抄同學的答案，不管懂不懂", "q": 3, "tag": "⚠ 抄來的看似解決了，其實既不懂也不誠實，是最空的一種「完成」。"}, {"t": "開口請教並交流想法，一起激出好解法", "q": 0, "tag": "✓ 統合綜效：結合彼此所知，常能想出單靠一個人怎麼都到不了的解法。"}]}, {"h": 6, "text": "為了趕進度你已連續熬夜，頭昏腦脹效率卻越來越差。", "c": [{"t": "灌更多提神飲料，繼續逼自己撐", "q": 2, "tag": "用透支換短效，是借高利貸——眼前撐住了，身體的帳單之後會連本帶利討回。"}, {"t": "安排充足睡眠與休息，恢復後再戰", "q": 0, "tag": "✓ 不斷更新：身體是你最重要的那把鋸子，磨利它，後面才砍得快、砍得久。"}, {"t": "反正爆肝幾天就過，垮了再說吧", "q": 3, "tag": "⚠ 燃燒健康換進度，是最不划算的交易；垮掉一次，要花更長時間才補得回來。"}, {"t": "知道該休息，卻仍邊打瞌睡邊硬撐", "q": 1, "tag": "◐ 道理都懂，卻沒真的停下來——疲勞下的努力，效率低到幾乎等於白做。"}]}, {"h": 6, "text": "你把所有時間塞滿讀書，運動、興趣、朋友全停了，卻越來越鬱悶。", "c": [{"t": "只在累到不行時，才隨便放鬆一下", "q": 2, "tag": "被動的恢復不是更新——等到油盡才加油，車早就走走停停、跑不遠了。"}, {"t": "把娛樂全戒掉，當苦行僧硬撐到底", "q": 3, "tag": "⚠ 只磨一個面向、犧牲其餘，遲早失衡崩潰；繃太緊的弦，斷得最快。"}, {"t": "均衡安排身體、心智、情感各面向更新", "q": 0, "tag": "✓ 不斷更新：身體、心智、情感、心靈四面向都要磨，人才會持久而有活力。"}, {"t": "想找回平衡，卻遲遲沒安排具體時間", "q": 1, "tag": "◐ 有意識是第一步，但不排進行事曆，平衡就永遠只停在「想要」而已。"}]}, {"h": 6, "text": "你學了很多新東西，卻從不回頭整理複習，過陣子幾乎全忘了。", "c": [{"t": "只在考前才臨時抱佛腳惡補一次", "q": 2, "tag": "臨時填鴨不是更新——硬塞進去的，考完就漏光，留不下能用一輩子的東西。"}, {"t": "學完就丟，反正忘了再重學就好", "q": 3, "tag": "⚠ 永遠在原地重學，等於白費前面所有力氣；沒有積累，再勤奮也走不遠。"}, {"t": "想複習卻總被新事物拉走，沒真做", "q": 1, "tag": "◐ 好意沒落實就等於沒有；不刻意排出回顧的時間，它永遠排不進你的日子。"}, {"t": "定期回顧整理，把學過的內化成自己", "q": 0, "tag": "✓ 不斷更新：持續回顧、精進心智這把刀，知識才會從「學過」變成「擁有」。"}]}, {"h": 0, "text": "教室地上散著垃圾，值日生沒清，老師快進來了，大家都當沒看見。", "c": [{"t": "順手撿起來、提醒大家一起整理不計較", "q": 0, "tag": "✓ 主動積極：不糾結是誰的責任，先做自己當下能做的——在影響圈裡先動起來。"}, {"t": "自己垃圾也往地上丟，反正大家都這樣", "q": 3, "tag": "⚠ 隨波逐流看似輕鬆，其實是把自己降到環境的水平——你讓外界決定了你的樣子。"}, {"t": "心想該有人去弄，自己卻也站著沒動", "q": 1, "tag": "◐ 看見了、也認同該做，卻停在念頭——主動的最後一哩，是「身體真的動起來」。"}, {"t": "抱怨值日生太混，等他來再跟他算帳", "q": 2, "tag": "把力氣花在指責別人，地還是髒的——你困在「管不動」的關注圈，沒踏進自己能動手的影響圈。"}]}, {"h": 0, "text": "排隊買午餐，有人大刺刺插到你前面，還一臉無所謂。", "c": [{"t": "推他一把開口罵，給他點顏色瞧瞧", "q": 3, "tag": "⚠ 動手把小事鬧成大事，看似出了氣，卻可能讓自己惹上更大的麻煩。"}, {"t": "不出聲但越想越氣，整頓飯都不開心", "q": 1, "tag": "◐ 沒爆發是好的，但情緒仍被他牽動了一整餐——真正的主動，是把氣轉成平靜的處理。"}, {"t": "也擠回去插別人的隊，扳回這一城", "q": 2, "tag": "用別人的錯來合理化自己的錯，你的行為就被對方決定了——主動的人不被刺激牽著走。"}, {"t": "平靜出聲提醒他請排隊，不動怒也不退", "q": 0, "tag": "✓ 主動積極：在刺激與回應之間，你永遠有選擇——既不爆氣、也不委屈，穩穩守住分際。"}]}, {"h": 0, "text": "某一科你一直學不好，開始覺得「我就是沒天分」想放棄。", "c": [{"t": "把焦點放在能改變的：換方法、找資源、多練", "q": 0, "tag": "✓ 主動積極：不被「天分」這頂帽子定義，把注意力放在自己能調整、能努力的地方。"}, {"t": "乾脆完全放棄這科，反正救不起來", "q": 3, "tag": "⚠ 一句「我沒天分」就棄械投降，等於提早替自己關上門——放棄會變成一種習慣。"}, {"t": "嘴上說要加油，讀書方法卻一成不變", "q": 1, "tag": "◐ 喊加油卻用同一套無效的方法，結果不會變——主動，是真的去換一個做法。"}, {"t": "安慰自己這科本來就難，分數低正常", "q": 2, "tag": "替放棄找一個體面的藉口，聽起來合理，其實是把改變的機會推開——你還沒真的試過所有方法。"}]}, {"h": 0, "text": "你看到同學被幾個人言語霸凌，周圍沒人敢出聲。", "c": [{"t": "怕惹麻煩，跟著起鬨免得被針對", "q": 3, "tag": "⚠ 為了自保而加入欺負的一方，是把恐懼變成幫凶——你縱容了惡，也丟了自己的底線。"}, {"t": "心裡很不忍，卻始終沒做任何事", "q": 1, "tag": "◐ 於心不忍是良知，但只停在心裡，被欺負的人感受不到——主動，是讓善意化成一個動作。"}, {"t": "安慰自己「又不是我的事」轉頭走開", "q": 2, "tag": "用「不關我事」把自己摘乾淨，看似明哲保身，其實是把能幫的責任推掉——沉默也是一種選擇。"}, {"t": "在能力範圍內出聲緩頰，或私下告訴師長", "q": 0, "tag": "✓ 主動積極：不必逞英雄，但在自己能力範圍內負起責任——這正是影響圈裡該做的事。"}]}, {"h": 1, "text": "兩個月的暑假剛開始，你還沒想好要怎麼過。", "c": [{"t": "先想清楚暑假結束時想變成怎樣再排計畫", "q": 0, "tag": "✓ 以終為始：先在心裡看見假期結束時想成為的自己，再回推今天該怎麼安排。"}, {"t": "目標訂超高塞滿每天，根本做不到", "q": 3, "tag": "⚠ 訂一個自己根本撐不住的計畫，三天就崩、徒留挫敗——虛假的宏願比沒計畫更傷。"}, {"t": "列了想做的事，卻沒安排什麼時候做", "q": 1, "tag": "◐ 有清單是看見了終點，但沒排進時間，它就只是願望，不會自己發生。"}, {"t": "走一天算一天，想到什麼就做什麼", "q": 2, "tag": "沒有終點的日子最容易蒸發——兩個月晃眼就過，回頭才發現什麼都沒留下。"}]}, {"h": 1, "text": "老師要交一篇文章，你急著動筆卻不知道想表達什麼。", "c": [{"t": "直接複製網路範文，改幾個字交差", "q": 3, "tag": "⚠ 抄來的是空殼，看似交差了，你卻什麼也沒練到——還賠上了誠實。"}, {"t": "想了主旨卻沒記下，寫著寫著就歪了", "q": 1, "tag": "◐ 腦中有方向是好的，但沒釘住它，寫一寫就偏掉——終點要寫下來才抓得住。"}, {"t": "先拚命湊字數，內容寫到哪算到哪", "q": 2, "tag": "只追求「寫滿」卻沒有方向，寫得再多也是一盤散沙——量填不了沒有終點的空。"}, {"t": "先定下這篇最想傳達的一句話再開始寫", "q": 0, "tag": "✓ 以終為始：先確立最想說的核心，每一段才會朝同一個終點走，文章才有力量。"}]}, {"h": 1, "text": "班上選幹部，你猶豫要不要爭取一個你其實想試的職位。", "c": [{"t": "想清楚自己想從中學到什麼再決定爭取", "q": 0, "tag": "✓ 以終為始：先看自己想藉這個位子練到什麼能力，再決定要不要伸手。"}, {"t": "隨便答應別人推的位子，之後再擺爛", "q": 3, "tag": "⚠ 沒想清楚就接下、之後又敷衍，既誤了班務也壞了信用——這是雙輸的開場。"}, {"t": "有點想做，卻因怕麻煩拖著沒報名", "q": 1, "tag": "◐ 心裡其實有目標，卻被「怕麻煩」蓋過——以終為始，難在抵住當下退縮的拉力。"}, {"t": "看哪個職位最涼最閒就選哪個", "q": 2, "tag": "用「輕鬆」當標準，而不是「我想成長成什麼樣」——選了最涼的，也錯過了想要的歷練。"}]}, {"h": 1, "text": "你學一項才藝或運動一陣子，覺得進步很慢、想放棄。", "c": [{"t": "知道該設目標，卻一直沒具體訂出來", "q": 1, "tag": "◐ 認同要有終點，卻遲遲不肯訂下來——沒釘住的目標，撐不住低潮時的動搖。"}, {"t": "沒目標地亂練，練到膩了就停", "q": 2, "tag": "沒有階段終點的練習，最容易在低谷時放棄——你不知道自己往哪走，自然撐不久。"}, {"t": "重新定一個清楚的階段目標，一步步練", "q": 0, "tag": "✓ 以終為始：把模糊的「變強」拆成看得見的小終點，用它帶你撐過進步緩慢的撞牆期。"}, {"t": "直接放棄，反正本來就只是玩玩", "q": 3, "tag": "⚠ 一遇瓶頸就喊「只是玩玩」收場，半途而廢會慢慢長成一種習慣，什麼都學不深。"}]}, {"h": 2, "text": "段考前一晚，你最愛的遊戲剛好出限時新版本。", "c": [{"t": "先把該複習的讀完，再用剩時間玩", "q": 0, "tag": "✓ 要事第一：先完成重要的事，娛樂就成了獎賞；順序對了，玩起來也安心。"}, {"t": "整晚都在玩，書本完全沒碰", "q": 3, "tag": "⚠ 把要事整個丟掉換一晚痛快，明天考場上的慌張，會把今晚的快樂連本帶利討回。"}, {"t": "一邊讀一邊分心想遊戲，效率很差", "q": 1, "tag": "◐ 想兩全，結果都打折——要事第一的關鍵，是同一時間只專注最重要的一件。"}, {"t": "先玩限時新版，書晚一點再說", "q": 2, "tag": "被「限時」兩個字綁架，把重要的事讓位給緊急的誘惑——這正是要事第一最常見的破口。"}]}, {"h": 2, "text": "同學找你幫忙、社團要你顧攤、家裡要你做事，全擠在同一天。", "c": [{"t": "通通答應，結果一件都沒做好", "q": 3, "tag": "⚠ 來者不拒，心力被撕成碎片，最後每件都做半套——這是沒有排序的必然下場。"}, {"t": "列了清單卻沒分輕重，照順序硬做", "q": 1, "tag": "◐ 有清單卻沒標出哪件最重要，只是把焦慮排成一排——重點是先做哪一件。"}, {"t": "先做最好講話那個人交代的事", "q": 2, "tag": "依「人情」而非「重要性」排序，會被聲音大的人牽著走——真正要緊的事反而被擠到後面。"}, {"t": "排出最重要的先做，婉拒或延後次要", "q": 0, "tag": "✓ 要事第一：分清輕重，對不重要的勇敢說不或延後，才守得住真正關鍵的那件。"}]}, {"h": 2, "text": "你正在做一份重要的長期作業，群組訊息和通知響個不停。", "c": [{"t": "暫時關掉通知，先完成重要的作業", "q": 0, "tag": "✓ 要事第一：主動把干擾擋在門外，守住「重要不緊急」的第二象限，才不會總在救火。"}, {"t": "乾脆聊一整晚，作業留到改天", "q": 3, "tag": "⚠ 一路聊下去，要事無限延後，長期作業最後總在最慌的那一刻被草草補完。"}, {"t": "想專心卻忍不住每則訊息都看一眼", "q": 1, "tag": "◐ 每瞄一眼就斷一次思緒，看似沒耽誤，其實效率被切得稀爛——專注要捨得不看。"}, {"t": "先把所有訊息回完，才開始做作業", "q": 2, "tag": "讓「緊急但不重要」的訊息插隊，等你清完，最該做的事又被往後推了一天。"}]}, {"h": 2, "text": "下週有重要比賽要準備，你卻一直忙著弄一些無關緊要的小事。", "c": [{"t": "知道比賽重要，卻還是先被小事佔住", "q": 1, "tag": "◐ 心裡知道孰輕孰重，行動上卻被小事黏住——要事第一，要敢把次要的先放一邊。"}, {"t": "先清掉一堆小事，享受劃掉的成就感", "q": 2, "tag": "用「劃掉清單」的快感麻痺自己，看似有效率，最重要的比賽卻一直沒真正準備。"}, {"t": "把練習比賽排第一，小事挪空檔再做", "q": 0, "tag": "✓ 要事第一：先把最重要、影響最大的事擺到最前面，其餘填進零碎時間。"}, {"t": "一直拖，到賽前一天才臨時抱佛腳", "q": 3, "tag": "⚠ 把要事拖到最後一刻，準備不足又壓力爆表，等於拿成績去賭——這是延宕的代價。"}]}, {"h": 3, "text": "你和同學想交換各自有的東西、互相幫忙，開始談條件。", "c": [{"t": "騙對方換到爛的，自己暗爽", "q": 3, "tag": "⚠ 用欺騙換一時的好處，贏了東西卻輸了人品與信任——這代價貴得離譜。"}, {"t": "主動讓利讓對方多拿，自己有點吃虧", "q": 1, "tag": "◐ 一味退讓是「我輸你贏」，不是雙贏；長期委屈，合作也走不遠。"}, {"t": "想盡辦法讓自己這邊多佔一點", "q": 2, "tag": "一心只想多撈，是「我贏你輸」的算計——這次佔了便宜，下次沒人想再跟你合作。"}, {"t": "找一個雙方都覺得划算、都受益的方案", "q": 0, "tag": "✓ 雙贏思維：不是把對方榨乾，而是一起把餅做大，找出兩邊都更好的安排。"}]}, {"h": 3, "text": "班遊表演，你和好友都想擔任同一個角色。", "c": [{"t": "一起討論，找出讓兩人都能發揮的安排", "q": 0, "tag": "✓ 雙贏思維：與其搶同一個位子，不如一起想出讓兩人都有舞台的第三種安排。"}, {"t": "偷偷跟老師說他壞話把他排擠掉", "q": 3, "tag": "⚠ 用抹黑把朋友踢開，贏到角色卻毀了友情與自己的品格——這是最虧的買賣。"}, {"t": "直接讓給好友，自己默默退出不爭", "q": 1, "tag": "◐ 退讓有風度，但只做到「我輸你贏」；雙贏是兩人都能上場，不是一方犧牲。"}, {"t": "強調自己比較適合，要他讓給你", "q": 2, "tag": "只想著自己贏、要對方退，是把好友逼到對立面——贏了角色，可能傷了感情。"}]}, {"h": 3, "text": "家裡只有一台電腦，你和弟妹都需要用它做作業。", "c": [{"t": "讓弟妹先用，自己熬夜等到很晚", "q": 1, "tag": "◐ 禮讓很體貼，但自己熬夜硬撐是「損己利人」；雙贏該是兩人作業都做得完。"}, {"t": "用哥哥姊姊的身分壓他先讓你用", "q": 2, "tag": "仗著身分要對方退，是「我贏你輸」——這次贏了電腦，輸掉的是手足之間的信任。"}, {"t": "商量出輪流的時段，讓大家作業都做完", "q": 0, "tag": "✓ 雙贏思維：花點巧思排出時段，看似有限的資源也能讓兩人都用得上。"}, {"t": "把滑鼠藏起來，不讓任何人先用", "q": 3, "tag": "⚠ 寧可大家都用不成也不讓步，是兩敗俱傷——傷得最重的，是這個家的氣氛。"}]}, {"h": 3, "text": "班費要買東西，有人提議的方案明顯只對某些人有利。", "c": [{"t": "乾脆把班費拿去做自己想做的事", "q": 3, "tag": "⚠ 把公共的錢挪作私用，贏了一時、輸了信任，甚至要負責任——這是損公肥私的墮落。"}, {"t": "不想得罪人，勉強同意對方的方案", "q": 1, "tag": "◐ 怕衝突而退讓，看似和氣，其實放任了不公平——雙贏要敢於提出更好的第三案。"}, {"t": "改成只對自己這群人有利的版本", "q": 2, "tag": "以牙還牙、改成只肥自己人，是把零和遊戲玩到底——班級的餅被搶來搶去，誰都沒真的贏。"}, {"t": "提出兼顧大家需求、人人都受惠的用法", "q": 0, "tag": "✓ 雙贏思維：班費是大家的，找一個人人都受惠的用法，才是真正的共贏。"}]}, {"h": 4, "text": "平常開朗的同學今天一句話都不說，臉色很差。", "c": [{"t": "找機會關心，靜靜聽他願不願意說", "q": 0, "tag": "✓ 知彼解己：先給對方空間、用心聽，理解他的感受，遠比急著給意見更重要。"}, {"t": "嫌他擺臉色，也回敬他一張冷臉", "q": 3, "tag": "⚠ 不問緣由就以冷對冷，把一個可能需要幫助的人推得更遠——誤解就是這樣加深的。"}, {"t": "想關心卻怕尷尬，最後沒開口問", "q": 1, "tag": "◐ 有想理解的心是好的，但停在原地，關心就沒送到——有時一句「你還好嗎」就夠了。"}, {"t": "自己猜原因，還到處跟別人討論", "q": 2, "tag": "沒去理解、卻急著臆測與張揚，可能把事情越傳越歪——理解的第一步是「問他」，不是「猜他」。"}]}, {"h": 4, "text": "老師誤會是你做的，當著全班的面責備你。", "c": [{"t": "急著大聲喊冤，沒聽老師把話說完", "q": 2, "tag": "只顧著讓自己被理解、卻不先理解老師的判斷從何而來，溝通就變成各說各話。"}, {"t": "先冷靜聽完，再有禮貌地說明經過", "q": 0, "tag": "✓ 知彼解己：先聽懂對方為什麼這樣想，再清楚說明自己——這樣的澄清才聽得進去。"}, {"t": "摔東西頂撞老師，把場面鬧得更大", "q": 3, "tag": "⚠ 用激烈對抗回應誤會，把可澄清的事鬧成衝突，誤解沒解開，關係先壞了。"}, {"t": "當下憋著不說，回家越想越委屈", "q": 1, "tag": "◐ 忍住沒爆發是好的，但完全不溝通，誤會就留在那裡——理解要雙向才解得開。"}]}, {"h": 4, "text": "你和好朋友因為一件小事吵架，兩人冷戰了好幾天。", "c": [{"t": "想和好卻拉不下臉，繼續僵著冷戰", "q": 1, "tag": "◐ 心裡想和好，卻被面子卡住——理解要有人先跨一步，那一步往往最珍貴。"}, {"t": "到處跟別人說自己有多有道理", "q": 2, "tag": "忙著找人證明「我才對」，是只想被理解、不想理解對方——這只會把裂痕越拉越大。"}, {"t": "主動找他，先試著理解他在氣什麼", "q": 0, "tag": "✓ 知彼解己：放下「誰先低頭就輸」的較勁，先去懂對方的情緒，和好才有起點。"}, {"t": "散播他的糗事，狠狠報復一波", "q": 3, "tag": "⚠ 用報復洩憤，等於親手燒掉這段友情——贏了一時的氣，輸掉一個朋友。"}]}, {"h": 4, "text": "討論事情時，有人提出跟你完全不同的看法。", "c": [{"t": "嘲笑對方的想法很蠢，叫他閉嘴", "q": 3, "tag": "⚠ 用羞辱壓制不同意見，從此沒人敢對你說真話——你關上了所有理解的門。"}, {"t": "表面上在聽，心裡早已想著反駁", "q": 1, "tag": "◐ 這是「假裝在聽」：耳朵開著、心在備稿，對方一秒就感覺得到那份心不在焉。"}, {"t": "馬上打斷，一直講自己的理由", "q": 2, "tag": "急著輸出自己的立場、不給對方說完，是只求被懂——你可能正錯過對方更好的觀點。"}, {"t": "先認真聽懂他為什麼這樣想，再表達", "q": 0, "tag": "✓ 知彼解己：先理解對方立場背後的理由，再說自己的——這樣的交流才有共識的可能。"}]}, {"h": 5, "text": "做專題時，你和組員各有一套完全不同的構想。", "c": [{"t": "把兩套構想的優點融成更好的第三案", "q": 0, "tag": "✓ 統合綜效：差異不是阻礙，而是養分——把兩邊的好揉成一個誰都單獨想不到的方案。"}, {"t": "各做各的，最後硬拼湊在一起交差", "q": 3, "tag": "⚠ 放棄整合、各做各的，成果四不像，還浪費了一起變更好的機會——這是合作的瓦解。"}, {"t": "投票決定用誰的，另一個直接丟掉", "q": 1, "tag": "◐ 投票是妥協、不是綜效；被丟掉的那案，也許正藏著最關鍵的一塊拼圖。"}, {"t": "堅持用自己的版本，要對方配合", "q": 2, "tag": "用自己的方案壓過對方，看似有效率，卻把對方腦中可能更好的點子整個浪費掉。"}]}, {"h": 5, "text": "分組時你和一個你覺得「程度比較弱」的同學一組。", "c": [{"t": "一直挑他毛病，要他全照你的做", "q": 2, "tag": "要對方變成另一個你，等於否定他的差異——綜效要的是互補，不是把人改造成自己的複製品。"}, {"t": "找出他也能貢獻的地方，分工互補", "q": 0, "tag": "✓ 統合綜效：每個人都有自己的長處，看見並善用差異，整體就會大於各自相加。"}, {"t": "嫌他沒用，乾脆把他排除在外", "q": 3, "tag": "⚠ 排斥、晾著隊友，團隊很快崩解——你失去的，正是他原本能補上的那一塊。"}, {"t": "自己包辦所有事，讓他掛名就好", "q": 1, "tag": "◐ 你扛完全部、他只掛名，看似省事，卻沒讓兩人的力量真正咬合，綜效從何而來？"}]}, {"h": 5, "text": "一個大活動需要跟別班同學合作，你不太信任他們。", "c": [{"t": "表面合作但各做各的，幾乎不交流", "q": 1, "tag": "◐ 人湊在一起、心卻沒交流，這是「合而不作」——沒有碰撞，就生不出綜效的火花。"}, {"t": "想主導全局，要對方都聽你指揮", "q": 2, "tag": "凡事都要別人聽你的，是壟斷而非協作——你把對方的長處與主動性都壓了下去。"}, {"t": "主動了解對方專長，協調分工一起完成", "q": 0, "tag": "✓ 統合綜效：先認識彼此能做什麼，再讓不同的人各司其職，合力做出更大的事。"}, {"t": "乾脆自己一手包辦，不跟他們合作", "q": 3, "tag": "⚠ 因不信任就拒絕協作、全攬上身，累垮自己也錯失眾人之力——這是綜效的反面。"}]}, {"h": 5, "text": "班上要想活動點子，你習慣自己埋頭想。", "c": [{"t": "嫌討論浪費時間，自己直接定案", "q": 3, "tag": "⚠ 跳過討論獨斷定案，是把全班的智慧丟掉——省了時間，卻換來大家都沒參與感的方案。"}, {"t": "開會徵詢大家，其實只想要他們點頭", "q": 1, "tag": "◐ 開了會卻只想大家蓋章背書，是「假討論」——人到了、聲音卻沒進來，綜效從何而來？"}, {"t": "只採納跟自己想法一樣的意見", "q": 2, "tag": "只聽得進和自己一樣的聲音，等於把差異全濾掉——少了不同視角，激不出新東西。"}, {"t": "邀大家一起腦力激盪，讓點子互相碰撞", "q": 0, "tag": "✓ 統合綜效：讓不同的想法彼此碰撞，往往能蹦出一個人怎麼想都想不到的好點子。"}]}, {"h": 6, "text": "你最近整天坐著讀書、滑手機，身體越來越僵硬疲累。", "c": [{"t": "固定安排運動時間，讓身體保持活力", "q": 0, "tag": "✓ 不斷更新：照顧身體這個面向，規律運動讓你後面讀得更久、撐得更穩。"}, {"t": "完全不運動，靠提神飲料硬撐著", "q": 3, "tag": "⚠ 用提神飲料壓住疲累、繼續透支，是借高利貸——身體的帳，之後連本帶利討回。"}, {"t": "想運動卻一直找藉口，拖著沒做", "q": 1, "tag": "◐ 知道該動卻總有藉口，更新就停在「想要」——不排進日子，它永遠不會發生。"}, {"t": "只在累到不行時，才隨便動兩下", "q": 2, "tag": "等到油盡才被動地動一下，不是更新——身體這把鋸子，要定期磨，不是壞了才修。"}]}, {"h": 6, "text": "你最近壓力很大，情緒悶在心裡無處宣洩。", "c": [{"t": "靠暴飲暴食、狂滑手機麻痺自己", "q": 2, "tag": "用刺激暫時蓋住情緒，是逃避不是更新——壓力沒被處理，只是被埋得更深。"}, {"t": "主動找健康方式抒發：運動、傾訴、書寫", "q": 0, "tag": "✓ 不斷更新：照顧情感面，主動替情緒找健康的出口，心才不會悶到生病。"}, {"t": "把情緒發洩在身邊的人身上", "q": 3, "tag": "⚠ 拿親近的人當情緒垃圾桶，傷了關係也傷了自己——這不是抒發，是擴大傷害。"}, {"t": "知道該抒發，卻一直憋著沒去做", "q": 1, "tag": "◐ 知道要找出口卻遲遲不動，情緒只會越積越滿——更新心情，也需要刻意去做。"}]}, {"h": 6, "text": "老師教了一套更有效的新讀書法，你卻懶得改、想用舊的。", "c": [{"t": "想學新方法卻一直拖，沒真開始", "q": 1, "tag": "◐ 有意願卻遲遲不行動，新方法永遠停在「聽過」——更新，要真的去用一次。"}, {"t": "只在考差了的時候才勉強想改", "q": 2, "tag": "非得撞牆才被動調整，是把更新拖到最後一刻——主動精進的人，不等失敗才換方法。"}, {"t": "試著學新方法，調整出更好的做法", "q": 0, "tag": "✓ 不斷更新：持續精進心智這把刀，願意嘗試更好的方式，效率才會不斷往上。"}, {"t": "完全排斥，堅持用沒效率的舊法", "q": 3, "tag": "⚠ 拒絕一切新東西、死守舊習慣，等於原地踏步——世界在前進，停下就是退步。"}]}, {"h": 6, "text": "你把每分每秒都塞滿待辦，從不留時間沉澱、反思。", "c": [{"t": "完全不留白，硬撐到情緒爆炸", "q": 3, "tag": "⚠ 把自己塞到一點縫都不留，遲早失衡爆炸——繃太緊的弦，斷得最快。"}, {"t": "想留卻總被其他待辦事項填滿", "q": 1, "tag": "◐ 總把留白排到最後、最後就沒了——不主動守住那段安靜，它一定會被擠掉。"}, {"t": "只在快受不了時，才放空一下", "q": 2, "tag": "撐到瀕臨崩潰才被動喘口氣，不是更新——心靈這口井，要定期取靜，不是乾了才挖。"}, {"t": "每天留一點安靜時間，反思沉澱自己", "q": 0, "tag": "✓ 不斷更新：照顧心靈面，每天留白一點來反思，人才會清醒、不被瑣事淹沒。"}]}, {"h": 0, "text": "隊友失誤害你們輸了比賽，你第一句話說什麼？", "c": [{"t": "「沒關係啦，別想太多」", "q": 1, "tag": "心意是暖的，但少了「我們能改什麼」那一步。"}, {"t": "「下次我們補位再快一點」", "q": 0, "tag": "把焦點放回自己能改變的影響圈——這就是主動積極。"}, {"t": "「以後球都交給我就好」", "q": 3, "tag": "看似扛責任，其實是不信任隊友的獨裁——主動不是搶走別人的球。"}, {"t": "「都怪裁判亂判」", "q": 2, "tag": "把力氣花在管不動的關注圈，比分不會因此改變。"}]}, {"h": 0, "text": "早自習被抽到的打掃區超髒，你？", "c": [{"t": "不是我弄髒的，站著等", "q": 2, "tag": "「不是我的錯」跟「不是我的事」是兩回事。"}, {"t": "把垃圾掃到隔壁班區域", "q": 3, "tag": "眼前乾淨了，品格髒了——這種聰明是陷阱。"}, {"t": "動手先清一塊再找人分工", "q": 0, "tag": "不等條件完美才行動——先做能做的，就是主動。"}, {"t": "等大家到齊再一起掃", "q": 1, "tag": "肯掃，但把開始的權力交給了別人。"}]}, {"h": 0, "text": "連假作業超多，你的第一步是？", "c": [{"t": "抱怨老師出太多，先耍廢", "q": 2, "tag": "抱怨是把遙控器交給別人，你的假期被情緒接管了。"}, {"t": "先借同學的來抄最快", "q": 3, "tag": "省下的時間，是用你的學習和誠信去換的——高利貸。"}, {"t": "列清單，挑今天能做的動工", "q": 0, "tag": "化整為零、立刻開始，主動的人先動手再抱怨（通常就不用抱怨了）。"}, {"t": "訂好完美計畫，明天開始", "q": 1, "tag": "計畫很好——但「明天開始」常常是拖延穿的外衣。"}]}, {"h": 0, "text": "你常遲到。今晚睡前，你為明天做什麼？", "c": [{"t": "鬧鐘放遠一點並提早睡", "q": 0, "tag": "改變上游條件，比早上跟意志力硬拚聰明——這是對自己的人生負責。"}, {"t": "乾脆翹掉早自習補眠", "q": 3, "tag": "用逃避解決遲到，等於用大洞補小洞。"}, {"t": "交代媽媽明天記得挖我起床", "q": 2, "tag": "把自己的責任外包給別人，遲到的劇本不會改。"}, {"t": "心裡發誓明天一響就起", "q": 1, "tag": "有決心沒設計，意志力在被窩前常常敗陣。"}]}, {"h": 1, "text": "社團博覽會要選社，你怎麼選？", "c": [{"t": "選最涼的社，省時間補習", "q": 3, "tag": "看似精明的算計，卻讓三年少了一塊人生拼圖——終點想錯了。"}, {"t": "好朋友選哪個就跟哪個", "q": 2, "tag": "用別人的地圖走自己的路，走再快也到不了你的終點。"}, {"t": "選看起來最有趣的再說", "q": 1, "tag": "興趣是好起點，但差了「這條路通向哪裡」的那層思考。"}, {"t": "想像三年後的自己再選", "q": 0, "tag": "以終為始：先看見想成為的樣子，再決定今天走哪條路。"}]}, {"h": 1, "text": "段考前一週，你的複習從哪開始？", "c": [{"t": "從最喜歡的科目讀起", "q": 1, "tag": "有開始很好，但喜歡的通常不是最需要的。"}, {"t": "只背補習班的猜題就好", "q": 3, "tag": "把終點外包給猜題，賭贏一次，輸掉讀書的能力。"}, {"t": "先看考試範圍和目標分數", "q": 0, "tag": "先立終點再排路線——複習是為了抵達，不是為了安心。"}, {"t": "打開課本從第一頁看起", "q": 2, "tag": "沒有終點的複習像沒有地圖的旅行，走到哪算哪。"}]}, {"h": 1, "text": "班遊由你規劃行程，你先做什麼？", "c": [{"t": "先查最熱門的景點清單", "q": 1, "tag": "方法對了一半——熱門是別人的答案，不一定是你們要的回憶。"}, {"t": "到了再說，隨興才好玩", "q": 2, "tag": "隨興很浪漫，但一車人的期待需要一個方向。"}, {"t": "直接抄別班的行程最省事", "q": 3, "tag": "省了力氣，也放棄了「這是我們的班遊」——複製不出專屬回憶。"}, {"t": "先問大家想留下什麼回憶", "q": 0, "tag": "心中先有那張「回來後的合照」，行程自然知道怎麼排。"}]}, {"h": 1, "text": "有人問你：讀書到底為了什麼？", "c": [{"t": "「爸媽要我讀，沒辦法」", "q": 2, "tag": "人生劇本讓別人執筆，是最可惜的以「別人的終」為始。"}, {"t": "「為了考上理想高中」", "q": 1, "tag": "是目標，但只是中繼站——過了這站呢？"}, {"t": "說出自己想成為的模樣", "q": 0, "tag": "心中有使命宣言的人，讀的每一頁都有座標。"}, {"t": "「讀書就是為了贏過別人」", "q": 3, "tag": "把人生設成排位賽，贏了名次，輸了方向。"}]}, {"h": 2, "text": "回家最想打電動，但明天要交報告。", "c": [{"t": "邊打邊寫，兩個都不耽誤", "q": 2, "tag": "一心二用的結果通常是報告像打的、電動像寫的。"}, {"t": "先做報告，電動當獎勵", "q": 0, "tag": "要事第一，娛樂變獎勵——同樣的電動，滋味完全不同。"}, {"t": "熬夜趕工，反正我抗壓", "q": 3, "tag": "拿健康墊背的效率是負債——產能燒掉了，產出遲早跟著垮。"}, {"t": "先打一場就好再寫", "q": 1, "tag": "「就一場」是時間小偷最愛的暗號。"}]}, {"h": 2, "text": "行程表滿了，好友臨時揪你逛街。", "c": [{"t": "直接放掉原本的計畫", "q": 2, "tag": "誰臨時出現就讓位給誰，你的計畫表形同虛設。"}, {"t": "對照計畫，衝突就誠實改約", "q": 0, "tag": "對要事守信，就是對自己守信；真朋友聽得懂誠實的「改天」。"}, {"t": "謊稱生病，兩邊不得罪", "q": 3, "tag": "用謊言換和平，利息是信任——遲早要還。"}, {"t": "答應但提早離開，兩全", "q": 1, "tag": "看似兩全，其實兩邊都只給了一半。"}]}, {"h": 2, "text": "考前發現 LINE 群聊超熱鬧。", "c": [{"t": "邊讀邊回，訊息不積壓", "q": 1, "tag": "每次切換都要重新暖機，你以為省了時間，其實付了雙倍。"}, {"t": "先聊完這一波再讀", "q": 2, "tag": "群聊的「這一波」沒有結尾，只有下一波。"}, {"t": "掛在群裡等同學傳重點", "q": 3, "tag": "抄來的重點沒經過你的腦子，考卷會誠實告訴你。"}, {"t": "關通知，讀完進度再回", "q": 0, "tag": "急迫的訊息多半不重要，重要的進度從不催你——要事第一。"}]}, {"h": 2, "text": "週末只剩半天空檔，你先排什麼？", "c": [{"t": "全部拿去補眠再說", "q": 3, "tag": "休息是要事沒錯——但「全部拿去」是逃避穿著休息的外衣。"}, {"t": "誰先找我就先陪誰", "q": 2, "tag": "把半天交給運氣排程，要事只能撿剩的。"}, {"t": "先放最重要的「大石頭」", "q": 0, "tag": "先放大石頭，碎石自然找得到縫；反過來就全塞不下了。"}, {"t": "先解決最快完成的小事", "q": 1, "tag": "勾掉小事很療癒，但療癒不等於前進。"}]}, {"h": 3, "text": "分組報告的功勞怎麼掛名？", "c": [{"t": "讓給人緣王掛名換人情", "q": 3, "tag": "拿真貢獻換虛人情，是對自己的損人利己。"}, {"t": "我做最多，當然掛頭牌", "q": 2, "tag": "你贏他輸的排法，這次爽了，下次沒人想跟你同組。"}, {"t": "貢獻寫清楚，大家都露臉", "q": 0, "tag": "雙贏不是平分，是各自的付出都被看見。"}, {"t": "全組並列，不分你我", "q": 1, "tag": "和氣，但讓多做的人吞下委屈——隱形的不公平。"}]}, {"h": 3, "text": "二手參考書要賣學弟，你開價？", "c": [{"t": "查行情，開雙方都划算的價", "q": 0, "tag": "他買得值、你賣得甘——雙贏的交易會帶來下一筆。"}, {"t": "缺頁不說，照原價賣", "q": 3, "tag": "賺到的是差價，賠掉的是名聲——全天下最貴的交易。"}, {"t": "開高一點，等他殺價", "q": 2, "tag": "把交易當攻防，贏了差價，輸了口碑。"}, {"t": "半買半送，當做人情", "q": 1, "tag": "大方可愛，但老是委屈自己的「好人」，遲早心裡不平衡。"}]}, {"h": 3, "text": "你和同學都想當隊長，怎麼辦？", "c": [{"t": "猜拳決定，公平乾脆", "q": 1, "tag": "公平，但把「兩個人才」的牌打成了「一個輸家」。"}, {"t": "談出正副手，各展所長", "q": 0, "tag": "不是你上我下，是把餅做大——雙贏思維的標準答案。"}, {"t": "私下拉票把他比下去", "q": 3, "tag": "贏了選票，輸了那個本來可以並肩的人。"}, {"t": "讓給他，反正我無所謂", "q": 2, "tag": "口說無所謂，心裡的疙瘩會記帳。"}]}, {"h": 3, "text": "限量卡牌只剩一張，你和好友都想要。", "c": [{"t": "找不到雙贏就先不交易", "q": 0, "tag": "「不成交」也是選項——寧可暫緩，不讓任何一方吞輸。"}, {"t": "先搶先贏，手快有", "q": 2, "tag": "搶得到卡，搶不回交情。"}, {"t": "裝不想要，讓他愧疚相讓", "q": 3, "tag": "用愧疚當貨幣，買到卡，賠上真誠。"}, {"t": "一人一半輪流保管", "q": 1, "tag": "妥協是各讓一步，雙贏是各進一步——還差一層。"}]}, {"h": 4, "text": "好友紅著眼眶說想退社，你？", "c": [{"t": "馬上安慰「別難過啦」", "q": 1, "tag": "安慰是糖，但他需要的是有人懂他為什麼苦。"}, {"t": "先聽完他的委屈再說話", "q": 0, "tag": "先診斷再開藥——被聽懂，比被說服更能救人。"}, {"t": "「早叫你別入這社了」", "q": 3, "tag": "馬後炮讓你贏了預言家頭銜，輸了他下次的信任。"}, {"t": "立刻分析退社的利弊", "q": 2, "tag": "他還在說感受，你已經開處方——藥再對也吞不下。"}]}, {"h": 4, "text": "同學誤會你說他壞話，衝來質問。", "c": [{"t": "先聽他從哪聽來、氣什麼", "q": 0, "tag": "先接住情緒再澄清事實——知彼，才有解己的機會。"}, {"t": "急著發誓自己絕沒說過", "q": 1, "tag": "急著自證，火上的人聽不進——順序錯了。"}, {"t": "冷處理，清者自清", "q": 3, "tag": "看似有風度，其實把誤會冷凍保鮮——它不會自己退冰。"}, {"t": "「你憑什麼兇我」吵回去", "q": 2, "tag": "兩把火只會燒出更大的誤會。"}]}, {"h": 4, "text": "爸媽反對你熬夜練球，你先？", "c": [{"t": "先說出他們在擔心什麼", "q": 0, "tag": "能說出對方的擔憂，談判就成功了一半——這就是先知彼。"}, {"t": "假裝早睡，偷偷爬起來練", "q": 3, "tag": "瞞天過海練的不是球，是說謊——被發現那天全部歸零。"}, {"t": "保證成績不掉來交換", "q": 1, "tag": "直接開條件跳過了理解——他們擔心的也許不只成績。"}, {"t": "不吵就好，關門繼續練", "q": 2, "tag": "沒有溝通的和平是假的，帳只是先掛著。"}]}, {"h": 4, "text": "你想給隊友建議，他卻臭著臉。", "c": [{"t": "先問他現在想不想聽", "q": 0, "tag": "建議送達前先敲門——心門沒開，說什麼都是噪音。"}, {"t": "發到群組讓大家評理", "q": 3, "tag": "把私下的話變成公審，建議再對也成了武器。"}, {"t": "換更委婉的說法再講一次", "q": 1, "tag": "修辭變了，順序沒變——還是「我說」優先於「他準備好了嗎」。"}, {"t": "好心被雷劈，不講了", "q": 2, "tag": "從「他不聽」直接跳到「我不說」，中間漏了理解那一步。"}]}, {"h": 5, "text": "隊友的怪點子跟你的方案相衝。", "c": [{"t": "把兩案優點拼出第三案", "q": 0, "tag": "一加一大於二：第三案不是折衷，是兩案都想不到的新路。"}, {"t": "表面採納，實際照舊做", "q": 3, "tag": "假合作是綜效的毒藥——他遲早發現自己的點子進了垃圾桶。"}, {"t": "投票表決，多數決定", "q": 1, "tag": "民主但可惜——表決選出一案，綜效能長出第三案。"}, {"t": "各做各的，最後挑一個", "q": 2, "tag": "平行線不會撞出火花，只會浪費一倍力氣。"}]}, {"h": 5, "text": "組裡有個意見永遠跟你相反的人。", "c": [{"t": "開會前先串通別人壓他", "q": 3, "tag": "用人數輾壓異見，贏了會議，輸了那雙幫你看盲點的眼睛。"}, {"t": "尊重他，但盡量避開同組", "q": 1, "tag": "容忍差異只到一半，慶祝差異才有綜效。"}, {"t": "當寶——他看見我的盲點", "q": 0, "tag": "珍惜差異是綜效的起點：兩個人想的都一樣，其中一個就是多餘的。"}, {"t": "努力說服他跟我同想法", "q": 2, "tag": "把不同磨成相同，團隊只剩一顆腦袋。"}]}, {"h": 5, "text": "合唱比賽有人提議加饒舌橋段。", "c": [{"t": "讓他自己饒舌自己負責", "q": 3, "tag": "切割不是合作——成了不分你功勞，砸了全推給他。"}, {"t": "傳統唱法穩，先求不出錯", "q": 1, "tag": "穩是優點，但「不出錯」的天花板就是平庸。"}, {"t": "試試看，混出新編曲", "q": 0, "tag": "合唱＋饒舌＝可能難聽，也可能是全場唯一的記憶點——綜效敢試。"}, {"t": "合唱就是合唱，別搞怪", "q": 2, "tag": "把「不一樣」當冒犯，就永遠只有一種聲音。"}]}, {"h": 5, "text": "跨班合作，對方流程跟你們完全不同。", "c": [{"t": "嘴上答應，回去照舊", "q": 3, "tag": "最省事的路——也是讓合作變成演戲的路。"}, {"t": "各用各的，最後再整合", "q": 1, "tag": "尊重了差異，卻沒讓差異交手——整合常變成硬拼裝。"}, {"t": "互相觀摩，長出新流程", "q": 0, "tag": "差異是原料不是障礙——混血的流程常常最強。"}, {"t": "要求對方配合我們的做法", "q": 2, "tag": "把合作做成併吞，對方的優點一項也拿不到。"}]}, {"h": 6, "text": "連續大考終於結束，你怎麼充電？", "c": [{"t": "立刻開始預習下一範圍", "q": 2, "tag": "不休息的勤勞是慢性折舊，鋸子越鋸越鈍。"}, {"t": "睡整天，睡飽就是充電", "q": 1, "tag": "身體充了電，腦和心還空著——只磨了一面的鋸子。"}, {"t": "運動、閱讀、聚會換著來", "q": 0, "tag": "身、腦、心輪流保養——四個面向都磨利，鋸子才真的利。"}, {"t": "手遊馬拉松爽到凌晨", "q": 3, "tag": "看似放鬆其實透支——用更累的方式「休息」，是最甜的陷阱。"}]}, {"h": 6, "text": "球技卡關很久，你？", "c": [{"t": "回頭磨基本動作和體能", "q": 0, "tag": "停下來磨鋸子，比咬牙硬鋸快——基本功就是你的鋸齒。"}, {"t": "加倍苦練同一招到會", "q": 1, "tag": "精神可嘉，但用鈍鋸子加倍鋸，只會加倍累。"}, {"t": "天分就這樣，練也沒用", "q": 2, "tag": "把卡關判成天花板，成長型思維直接下線。"}, {"t": "只挑弱隊打，找回信心", "q": 3, "tag": "贏來的爽感是止痛藥，不是治療——關卡原地等你。"}]}, {"h": 6, "text": "你發現自己最近越來越暴躁。", "c": [{"t": "檢查睡眠、運動和心情", "q": 0, "tag": "情緒是儀表板不是敵人——亮燈了，回頭保養四個面向。"}, {"t": "忍住脾氣，不發作就好", "q": 1, "tag": "壓住的火沒有熄，只是改天連本帶利燒。"}, {"t": "是別人太煩，不關我事", "q": 2, "tag": "把儀表板的警示燈貼起來，引擎照樣過熱。"}, {"t": "打遊戲罵隊友紓壓", "q": 3, "tag": "把火倒進別人家——你暫時舒服了，人際存摺被扣款。"}]}, {"h": 6, "text": "朋友約你每天晨跑養習慣。", "c": [{"t": "答應，並約好互相提醒", "q": 0, "tag": "運動練身、承諾練心、同伴暖情——一次磨三面鋸子。"}, {"t": "自己在家跳繩就好", "q": 1, "tag": "能動就好，但少了同伴的力量，習慣常撐不過下雨天。"}, {"t": "早上起不來，直接拒絕", "q": 2, "tag": "還沒開始就投降，更新的門連推都沒推。"}, {"t": "先買齊裝備，改天開始", "q": 3, "tag": "購物車的成就感最會偽裝成進步——裝備到了，人沒到。"}]}, {"h": 0, "text": "全班都在看你。那股火衝到喉嚨。 劍靈低聲說：「注意——刺激跟回應之間，有一個 0.5 秒的空隙。」", "c": [{"t": "故意把筆袋重重一摔，讓老師知道你不爽。", "q": 3, "tag": "⚠ 摔得很大聲。全班都看到了——看到的是「你輸給了那句話」。"}, {"t": "翻白眼小聲嗆回去：「又不是只有我沒聽到。」", "q": 2, "tag": "絲線瞬間收緊。你把今天一整天的心情，交給了老師的一句話。"}, {"t": "深呼吸先把這口氣吞下，決定下課再去說明。", "q": 0, "tag": "✓ 就是這個。你在刺激跟回應之間，按下了那 0.5 秒的暫停鍵。"}, {"t": "低頭不說話，但接下來整節課都在心裡罵。", "q": 1, "tag": "◐ 表面沒事，但你的腦袋被那句話租走了一整節課——而且租金是你付的。"}]}, {"h": 0, "text": "下課鐘響。你走向講桌前的老師。", "c": [{"t": "走過去，但只是想討個說法：「您憑什麼念我？」", "q": 3, "tag": "⚠ 你走對了方向，卻帶錯了武器。「討公道」一開口，台階就變成了戰場。"}, {"t": "回座位跟同學抱怨：「那個老師根本就是針對我。」", "q": 2, "tag": "你開始吐絲了。「針對我」三個字一出口，所有改變的可能都被關掉了。"}, {"t": "「老師，剛我在趕作業沒聽到，不是故意的，跟您說一聲。」", "q": 0, "tag": "✓ 主動說明，不是認錯比賽——你拿回了這個故事的解釋權。"}, {"t": "走到一半轉彎：「算了，反正講了也沒用。」", "q": 1, "tag": "◐ 「反正都這樣」是絲線最愛的台詞之一。你還沒講過，怎麼知道沒用？"}]}, {"h": 0, "text": "拿著這張 58 分，你的第一個念頭是：", "c": [{"t": "拍照傳到群組：「看我考多慘，笑死。」", "q": 3, "tag": "⚠ 把難堪變成梗，是最快的逃。笑完了，那六題你還是不會。"}, {"t": "「這次題目出太難了，老師教得又超爛。」", "q": 2, "tag": "也許有部分是真的。但這句話講完——你的 58 分有動嗎？沒有。絲線+1。"}, {"t": "翻開考卷，看錯的是粗心、不會、還是沒讀到。", "q": 0, "tag": "✓ 你把力氣花在「我能動的事」上面。這個圈，叫做影響圈。"}, {"t": "把考卷塞進抽屜最深處，眼不見為淨。", "q": 1, "tag": "◐ 考卷不會咬你。但下一次段考會。"}]}, {"h": 0, "text": "你發現錯的題目裡，有六題是同一種題型。", "c": [{"t": "決定下次直接背答案，這種題型放棄算了。", "q": 3, "tag": "⚠ 放棄一個題型，省了今晚；賠掉的是往後每一次它出現的分數。古神給你按讚。"}, {"t": "圈起來。今天晚上，先把這一種弄懂就好。", "q": 0, "tag": "✓ 不是「我要發憤圖強」那種大話，是一個今晚就做得到的小承諾。最小的承諾，最有力。"}, {"t": "嘆口氣：「反正我天生就是沒有數學細胞。」", "q": 2, "tag": "這句話最毒——它把「暫時還不會」偷偷改寫成「永遠都不行」。絲線最愛這種永久合約。"}, {"t": "想說下週找個時間，再一次全部補起來。", "q": 1, "tag": "◐ 「下週的我」是個很會躲的傢伙。你大概率找不到他。"}]}, {"h": 0, "text": "討論時你發現，其中一個平常超安靜的組員，做簡報超強。", "c": [{"t": "酸他一句：「這麼厲害，那整份就你做囉？」", "q": 3, "tag": "⚠ 別人的強，被你一句酸話推開了。你親手把唯一的隊友變成對手。"}, {"t": "心想：還好有人會做，那我可以輕鬆翹腳了。", "q": 1, "tag": "◐ 從「被分到爛組」變成「搭便車」⋯⋯方向對了一半，可惜只有一半。"}, {"t": "直接請教他：「這頁版面你會怎麼排？教我一下。」", "q": 0, "tag": "✓ 主動的人，永遠先看到別人的好。這一組沒你想的差。"}, {"t": "還是悶悶的：「跟好朋友一組，一定更高分。」", "q": 2, "tag": "你在用「如果當初」折磨「現在的自己」。那個平行宇宙不存在。"}]}, {"h": 0, "text": "那句「就是那球啦」還在空中。你：", "c": [{"t": "悶著頭走掉，整場午餐都吃不下。", "q": 1, "tag": "◐ 你沒有吐絲。但你讓那句話在肚子裡自己長絲。"}, {"t": "把球往地上一砸：「不打了，輸贏隨便啦。」", "q": 3, "tag": "⚠ 你砸的不是球，是隊友對你的信任。氣消之後，那一砸還在大家心裡。"}, {"t": "立刻回嗆：「你上半場漏接幾顆，要不要算？」", "q": 2, "tag": "互吐絲線。恭喜，球場上誕生了兩個新人偶。"}, {"t": "深吸一口氣：「對，那球我該接的，下次站前面。」", "q": 0, "tag": "✓ 認下自己的那一份，而且只認自己的那一份。這比嗆回去，需要多十倍的力氣。"}]}, {"h": 0, "text": "放學前，那個同學跑來：「欸，剛剛我講太大聲，歹勢啦。」", "c": [{"t": "「沒事啦。欸，下次午休要不要約練接球？」", "q": 0, "tag": "✓ 把一場衝突變成一個邀請。這是主動積極的進階技。"}, {"t": "哼一聲別過頭，不想理他。", "q": 2, "tag": "他遞出來的台階，你一腳踢掉了。爽三秒，虧三週。"}, {"t": "「現在才道歉？早幹嘛去了。」", "q": 3, "tag": "⚠ 他鼓起勇氣走過來，被你一句噎回去。下次他寧可不道歉——你親手教會他的。"}, {"t": "嘴上說「沒事」，心裡決定再也不跟他同隊。", "q": 1, "tag": "◐ 「沒事」如果是假的，絲線就還在——只是改成在心裡織。"}]}, {"h": 0, "text": "那把火又上來了。你：", "c": [{"t": "按暫停：「我滑十分鐘，七點開始寫作業可以嗎？」", "q": 0, "tag": "✓ 你沒有否認自己需要休息——你只是把它變成一個「可以被同意的計畫」。"}, {"t": "一句話也不說，起身甩門進房間。", "q": 1, "tag": "◐ 門關上了，但火還在房間裡燒——燒的是你自己。"}, {"t": "繼續滑，假裝沒聽到，看她能念多久。", "q": 3, "tag": "⚠ 你用沉默宣戰，她用音量回擊。十分鐘的休息，賠上一整晚的低氣壓。"}, {"t": "大聲回嘴：「我才剛回來欸！你每次都這樣！」", "q": 2, "tag": "「每次」「都」一出口，戰爭正式開打。今晚的家裡不會有好空氣了。"}]}, {"h": 0, "text": "媽媽愣了一下：「⋯⋯好，七點喔。」 七點到了。手遊正好打到一半。", "c": [{"t": "「再打完這一場就好」，七點十五才放下。", "q": 1, "tag": "◐ 晚十五分鐘不會死。但「我說到做到」的存款，少了一筆。"}, {"t": "裝忘記，硬是繼續打到被抓包。", "q": 2, "tag": "下次你再說「七點開始」的時候——這句話已經不值錢了。"}, {"t": "跟隊友說聲先退，然後闔上手機。", "q": 0, "tag": "✓ 對自己的小承諾，說到做到——這就是傳說中「30 天挑戰」的第一天。"}, {"t": "心想反正她也沒在看，多打半小時沒差。", "q": 3, "tag": "⚠ 說到做到，從來不是做給別人看的。沒人看的時候，才是真章。"}]}, {"h": 0, "text": "怒氣值瞬間滿格。你：", "c": [{"t": "什麼都不說，默默把他最愛的玩具也弄壞。", "q": 3, "tag": "⚠ 以壞還壞。你贏了一回合，輸掉的是「哥哥」這兩個字的分量。"}, {"t": "直接衝去跟媽媽告狀，吵著一定要他賠。", "q": 1, "tag": "◐ 合理。但你把整件事的處理權外包出去了——連同你的情緒。"}, {"t": "衝過去吼他，把他上個月弄壞的東西全翻出來算。", "q": 2, "tag": "吼完，耳機會復活嗎？不會。但你們的關係，多斷了一邊。"}, {"t": "先離開現場三十秒，去倒杯水，回來再處理。", "q": 0, "tag": "✓ 漂亮。最強的暫停鍵不是「忍住」，是「先走開」。"}]}, {"h": 0, "text": "三十秒後，你冷靜了一點。接下來：", "c": [{"t": "跟他說「這對我很重要，要用先問」，再收到他拿不到的地方。", "q": 0, "tag": "✓ 講清楚界線＋動手防呆。兩件事，都在你的影響圈。"}, {"t": "從此把房門上鎖，東西全藏起來不准他碰。", "q": 3, "tag": "⚠ 防得了耳機，防不了關係。一道鎖關上的，是你們之間原本還能修的那扇門。"}, {"t": "跟他冷戰一整週，看到他就擺臭臉。", "q": 2, "tag": "你在用自己一整週的心情，懲罰一個小孩的三分鐘。這筆帳怎麼算都虧。"}, {"t": "算了，反正跟小孩講了他也聽不懂。", "q": 1, "tag": "◐ 「講了也沒用」是還沒講過的人最愛說的話。"}]}, {"h": 0, "text": "失望是真的，很重。你：", "c": [{"t": "「你每次都這樣啦！說話都不算話！」", "q": 2, "tag": "注意，「每次」又出現了。失望是真的，但這兩個字把它變成了攻擊。"}, {"t": "「我真的很期待欸⋯⋯那改約下週六，我查場次。」", "q": 0, "tag": "✓ 說出失望＋提出新方案。你把「被取消的人」升級成「重新安排的人」。"}, {"t": "「沒關係，反正我早就習慣了。」說完轉身走掉。", "q": 3, "tag": "⚠ 這句話比生氣更傷——它是把刀，捅人之前先捅自己一刀。絲線吃得很飽。"}, {"t": "「喔。」然後一整個晚上都擺著臭臉。", "q": 1, "tag": "◐ 你有失望的權利。但臭臉的意思是「希望他自己猜到」——大人通常猜不到，真的。"}]}, {"h": 0, "text": "爸爸有點愧疚：「好，下週六，一定。」 到了下週五晚上，你：", "c": [{"t": "什麼都不講，他最好記得，不然就是不在乎我。", "q": 1, "tag": "◐ 你偷偷出了一張他不知道的考卷，然後等著他不及格。這個局，沒有人會贏。"}, {"t": "故意不提醒，等他忘了，好證明「你看吧」。", "q": 3, "tag": "⚠ 你設了一個陷阱，只為了贏一句「我早就說了」。贏了道理，輸了一個週末。"}, {"t": "傳訊息：「爸，明天 2:30 那場我查好了，先講喔。」", "q": 0, "tag": "✓ 與其賭他記不記得，不如讓他想忘都忘不掉。這是影響圈玩家的標準操作。"}, {"t": "先預設他會再放鳥，跟同學說「我爸都馬這樣」。", "q": 2, "tag": "事情還沒發生，你已經先吐好絲在那邊等了。古神給你按了個讚。"}]}, {"h": 0, "text": "那句「你呢？」懸在空中。你：", "c": [{"t": "笑笑回：「表哥真的很強，我最近在練籃球。」", "q": 0, "tag": "✓ 你沒有接「比較」這顆球，你丟回了一顆「自己的球」。接得漂亮。"}, {"t": "小聲說「哦，還好」，內心翻騰：關你什麼事。", "q": 1, "tag": "◐ 場面守住了。但那句話鑽進心裡住下了，對吧？下一幕處理它。"}, {"t": "臭著臉拿出手機開始滑，整頓飯都不講話。", "q": 2, "tag": "你的心情遙控器，現在在阿姨手上。她按一個鍵，你癱一頓飯。"}, {"t": "酸回去：「那阿姨您兒子怎麼沒前十啊？」", "q": 3, "tag": "⚠ 嗆贏了餐桌，輸掉了整晚。比較這顆球，你不但接了，還用力砸了回去。"}]}, {"h": 0, "text": "回家的車上，「你呢？」三個字還在腦中重播。", "c": [{"t": "暗自決定：下次段考一定要贏過表哥給她看。", "q": 3, "tag": "⚠ 你把人生的方向盤，交給了一個你根本不想學的人。為了贏他而活，其實還是輸了。"}, {"t": "問自己：我在意的是表哥，還是「我想要的樣子」？", "q": 0, "tag": "✓ 表哥的成績在關注圈，你想成為的樣子在影響圈。寫下來的那一刻，球回到你手上。"}, {"t": "跟媽媽抱怨：「阿姨真的有夠煩的欸。」", "q": 1, "tag": "◐ 可以抱怨，這很正常。抱怨完，記得把球撿回來就好。"}, {"t": "躺上床滑 IG——看大家好像都過得比我好。", "q": 2, "tag": "拿別人的精選輯，比自己的幕後花絮。這場比賽，地球上沒有人贏得了。"}]}, {"h": 0, "text": "你又點開那個「已讀」看了第十次。", "c": [{"t": "開始腦補：他是不是討厭我、在記上次的仇？", "q": 2, "tag": "注意——你正在用「猜出來的劇情」，懲罰「真實的自己」。絲線最肥美的養分。"}, {"t": "再連續傳三個問號過去：「？？？」", "q": 1, "tag": "◐ 壓力是傳過去了。但答案不會因此比較快回來。"}, {"t": "跑去問別的同學：「他是不是有跟你說我壞話？」", "q": 3, "tag": "⚠ 你把一個還沒發生的劇情，傳染給了第三個人。腦補不但沒停，還開了分店。"}, {"t": "把手機蓋下來：他可能在補習在吃飯，先做我的事。", "q": 0, "tag": "✓ 別人何時回訊息＝關注圈。我等待的時候做什麼＝影響圈。教科書級的劃分。"}]}, {"h": 0, "text": "晚上九點，他回了：「哈哈哈靠北 剛剛在補習啦」", "c": [{"t": "「你也太晚回了吧，等有夠久。」", "q": 1, "tag": "◐ 一根小小的刺。他下次已讀你的時候，會想起這根刺，然後更不敢隨便回。"}, {"t": "「我就猜你在補習 哈哈，沒事啦。」", "q": 0, "tag": "✓ 事實證明：三小時的腦補劇場，下檔只需要一秒。記住這次的感覺，下次的三小時會好過很多。"}, {"t": "看到了，故意已讀不回，跟他扯平。", "q": 2, "tag": "你們現在開始玩「誰比較不在乎」大賽了。這個比賽的冠軍獎品，是失去一個朋友。"}, {"t": "「我還以為你不想理我了，嚇死。」帶點情緒勒索。", "q": 3, "tag": "⚠ 把自己的腦補變成他的虧欠。久了，他回你訊息會有壓力——而壓力會推走人。"}]}, {"h": 0, "text": "手指懸在鍵盤上。你：", "c": [{"t": "在群裡開罵：「誰拍的？很好笑嗎？白痴喔？」", "q": 2, "tag": "你一炸，這張照片就從「好笑三分鐘」升級成「事件一星期」。"}, {"t": "截圖傳給爸媽：「你看他們這樣欺負我！」", "q": 3, "tag": "⚠ 一張玩笑照，被你升級成「霸凌通報」。明天進教室的尷尬，會比照片大一百倍。"}, {"t": "二話不說，直接退出班級群組。", "q": 1, "tag": "◐ 退群擋得了通知，擋不了明天的教室。問題只是延到早自習而已。"}, {"t": "先判斷是玩笑還是惡意，回「下次拍我帥的角度」。", "q": 0, "tag": "✓ 幽默是最高級的暫停鍵。這張照片的重量，剛剛被你親手調成了羽量級。"}]}, {"h": 0, "text": "但如果你其實真的不舒服——這完全可以。被拍醜照不爽，不是玻璃心。", "c": [{"t": "忍下來，假裝沒事，當作什麼都沒發生。", "q": 1, "tag": "◐ 如果真的沒事，OK。但如果是「假裝沒事」⋯⋯絲線在心裡織得可勤了。"}, {"t": "私訊拍照的人：「那張刪一下，我不喜歡。」語氣平靜。", "q": 0, "tag": "✓ 不舒服就說。這不是玻璃心，這是界線。主動積極，包含選擇說「不」。"}, {"t": "翻出他以前的醜照，傳上群組反擊回去。", "q": 2, "tag": "以絲還絲，以偶治偶。本層古神看到這操作，感動到快哭了。"}, {"t": "在限動發長文討拍：「原來在你們眼裡我這麼好笑。」", "q": 3, "tag": "⚠ 你把不舒服變成公演。台下的人看戲，台上的你，把小事演成了大事。"}]}, {"h": 0, "text": "又一個自己吃午餐的中午。你：", "c": [{"t": "心想：是他先不理我的，要主動也該他先。", "q": 2, "tag": "「誰先」是深淵裡最古老的陷阱。堅持等對方先動的人，通常等到的是結束。"}, {"t": "直接傳訊：「禮拜五放學一起買手搖？好久沒聊。」", "q": 0, "tag": "✓ 友情這件事，在你影響圈裡的部分只有一塊：你願不願意主動。你剛剛動了。"}, {"t": "發一則 IG 限動：「呵，有些人，變了。」", "q": 1, "tag": "◐ 這種限動只有一個功能：讓事情變得更難收拾。而且他看得懂，別人也看得懂。"}, {"t": "去跟別的同學說他壞話，先把陣營拉起來。", "q": 3, "tag": "⚠ 你怕失去一個朋友，做法卻是再賠掉幾個。絲線繞著你，織得又快又密。"}]}, {"h": 0, "text": "他答應了。但聊天的時候你發現——你們的共同話題，真的變少了。", "c": [{"t": "心裡確定了：他變了，這段友情完蛋了。", "q": 2, "tag": "一次尷尬＝完蛋？八年的友情，你只給它一次五十分鐘的重審機會？"}, {"t": "乾脆挑明：「你是不是不想跟我好了？」逼他表態。", "q": 3, "tag": "⚠ 你想要一個答案，卻問出了一個結局。逼到牆角的關係，通常只會往後退。"}, {"t": "整場努力裝熱絡，笑得很用力，回家累垮。", "q": 1, "tag": "◐ 硬撐場面不是主動，是表演。誠實一點，反而輕鬆一點。"}, {"t": "承認心裡有點感傷，但還是問他最近在迷什麼。", "q": 0, "tag": "✓ 主動積極不保證結局。它只保證一件事：你不會留下「當初連試都沒試」的遺憾。"}]}, {"h": 0, "text": "遲到已成定局。出門的路上，你：", "c": [{"t": "傳訊跟同學說：「幫我跟老師說我肚子痛。」", "q": 3, "tag": "⚠ 為了躲十分鐘，編一個謊。謊要用更多謊去圓——絲線就是這樣愈纏愈多。"}, {"t": "邊走邊想：遲到改不了，我能動的只剩「到校後的態度」。", "q": 0, "tag": "✓ 開局就分圈，高手。遲到在外圈了，態度還在內圈。"}, {"t": "一路狂罵鬧鐘，越想越衰，這什麼爛日子。", "q": 1, "tag": "◐ 罵鬧鐘的這十分鐘，鬧鐘沒感覺，你血壓倒是上來了。"}, {"t": "反正都遲到了，乾脆慢慢走，順便買個早餐。", "q": 2, "tag": "「反正都」三個字一出，遲到十分鐘正在變成遲到三十分鐘。"}]}, {"h": 0, "text": "進教室，被學務處記遲到，導師又補念兩句。", "c": [{"t": "「老師，是我鬧鐘的問題，今天回去我會多設一個。」", "q": 0, "tag": "✓ 承認＋方案，五秒講完。老師最吃這套——不是因為乖，是因為罕見。"}, {"t": "頂回去：「又不是我願意遲到的！」", "q": 2, "tag": "這句話的意思是「我對我的人生沒有控制權」。古神在遠處舉牌給分。"}, {"t": "心想老師故意找碴，整節課都不抄筆記抗議。", "q": 3, "tag": "⚠ 你以為在懲罰老師，其實在懲罰自己的成績。這場抗議，只有你一個人受傷。"}, {"t": "低頭不語，擺出全世界都對不起我的臉。", "q": 1, "tag": "◐ 受難者面具戴久了，會長在臉上。早上就要過完了，你打算幾點摘？"}]}, {"h": 0, "text": "午休，你傳訊約好友放學打球。已讀，不回。 （今天怎麼連他也⋯⋯）", "c": [{"t": "氣到把他從好友刪掉，看他發不發現。", "q": 3, "tag": "⚠ 一個已讀，換你刪一個朋友。今天的爛，被你自己又加重了一級。"}, {"t": "忍不住再傳兩則：「？」「是怎樣」", "q": 1, "tag": "◐ 深呼吸。今天已經夠滿了，別再自己加菜。"}, {"t": "心裡確定了，今天全世界都在針對我。", "q": 2, "tag": "全世界其實沒空針對你——但這句話一說出口，你自己會開始幫全世界蒐集證據。"}, {"t": "蓋上手機，先睡個午覺，醒來再說。", "q": 0, "tag": "✓ 今天的你已經學會了：他的訊息在外圈，你的午覺在內圈。睡。"}]}, {"h": 0, "text": "回到家，媽媽接到學校的遲到通知了。開口就念。", "c": [{"t": "直接爆炸：「我今天夠衰了，你還要念！」", "q": 2, "tag": "最後一關破功。今天累積的所有委屈，剛剛全部變成了媽媽繼續念的理由。"}, {"t": "「嗯。嗯。好。」一路敷衍到她講完。", "q": 1, "tag": "◐ 今天是混過去了。但同一場戲，下週還會重播——因為什麼都沒被解決。"}, {"t": "甩頭進房：「煩死了，這個家沒人懂我！」", "q": 3, "tag": "⚠ 門一甩，今天所有的壞，全被你打包成「都是別人的錯」。古神在門外鼓掌。"}, {"t": "搶在她念完前：「媽，是鬧鐘的問題，我已多設一個。」", "q": 0, "tag": "✓ 方案先行，火就燒不長。這一天的最後一波絲線，被你一刀斬斷。"}]}, {"h": 0, "text": "牠甩出第一波絲線，纏著甜膩的耳語： 「你成績爛，是老師教得爛啊～承認吧，承認了多舒服～」", "c": [{"t": "摀住耳朵大叫：「我不聽！我不聽！」", "q": 1, "tag": "◐ 摀耳朵擋不住絲線。能擋住牠的從來不是抗拒，是「選擇」。"}, {"t": "「老師確實教得不好。而且，我可以決定怎麼補。」", "q": 0, "tag": "✓ 「而且」——你在牠寫好的劇本裡，加了自己的台詞！古神的手晃了一下。"}, {"t": "「你說得對，怪老師最輕鬆了。」", "q": 3, "tag": "⚠ 你嚐到了那股「舒服」。古神笑了——牠賣的就是這種會上癮的輕鬆。"}, {"t": "「⋯⋯對。真的就是老師的問題。」", "q": 2, "tag": "絲線纏上你的脖子。牠說得越貼心，纏得越緊——這就是牠千年來的狩獵方式。"}]}, {"h": 0, "text": "牠提高音量，絲線從四面八方湧來： 「你爸媽偏心！你朋友背叛你！你生不逢時！這些都是真的，對吧？！」", "c": [{"t": "「既然都是真的，那我認命還不行嗎？」", "q": 3, "tag": "⚠ 「認命」聽起來像放下，其實是把方向盤丟了。古神最愛幫認命的人開車。"}, {"t": "「這些事傷過我是真的。但接下來怎麼走，輪不到它們。」", "q": 0, "tag": "✓ 承認痛、又拒絕被操控——兩件事同時做到的瞬間，絲線大片大片地斷裂。"}, {"t": "舉劍拼命亂砍湧上來的絲線。", "q": 1, "tag": "◐ 砍不完的。你越砍牠越多——因為絲線的源頭不在外面。"}, {"t": "「對！都是他們害的！我才是受害者！」", "q": 2, "tag": "你感覺到背後一涼——有絲線從你自己身上長出來了。那是你吐的。"}]}, {"h": 0, "text": "古神俯下身，聲音忽然變得無比溫柔： 「孩子，怪別人沒有錯啊。只要一直怪別人——你就永遠、永遠不用承認自己也有一份。」", "c": [{"t": "「閉嘴！你不要再講話了！」", "q": 1, "tag": "◐ 牠不怕你兇。牠只怕你「選」。"}, {"t": "「承認自己有錯多痛苦，我才不要。」", "q": 3, "tag": "⚠ 你說中了——承認很痛。但這份痛，是唯一能剪斷絲線的刀。你把刀丟了。"}, {"t": "「⋯⋯也對。反正錯的又不只我一個。」", "q": 2, "tag": "牠笑了。好可惜，剛剛只差一步，你就掙脫了。"}, {"t": "「⋯⋯就是這句話，讓這裡吊滿人偶。我的那份，我認。」", "q": 0, "tag": "✓ 古神發出慘叫——「承認自己的那一份」是牠唯一無法消化的東西。"}]}, {"h": 0, "text": "絲線崩解中。古神拼出最後一招——一面鏡子，照出明天的你：照樣賴床、照樣被念、照樣被已讀。 「看啊！明天的你，還是會變回原樣！！」", "c": [{"t": "「不會！我已經徹底改變，再也不一樣了！」", "q": 1, "tag": "◐ 小心，「徹底改變」是另一種絲——它斷一次，人就全盤崩潰。真正的強是「斷了再選」。"}, {"t": "「反正會變回去，那我乾脆別改了。」", "q": 3, "tag": "⚠ 因為會跌倒就不站起來？古神等的就是這句。鏡子裡的你，因此真的定格了。"}, {"t": "「⋯⋯對欸。那我現在努力是在幹嘛？」", "q": 2, "tag": "明天的不完美，不能沒收今天的選擇。站穩，牠就剩這最後一招了。"}, {"t": "「也許我還會被纏住。但我知道絲從哪來，能一次次剪。」", "q": 0, "tag": "✓ 不是「我再也不會抱怨了」這種鬼話——是「我會一次一次地選」。古神聽懂了。牠輸了。"}]}, {"h": 0, "text": "古神跪倒，傀儡的外殼寸寸碎裂—— 裡面站著的，是一個你再熟悉不過的身影。 是你。一個很會說「都是別人害的」的你。 影子朝你伸出手。", "c": [{"t": "嚇得轉頭就跑，頭也不回。", "q": 2, "tag": "跑去哪呢？這裡是你的心裡。最後一步，是回頭面對牠。"}, {"t": "「你根本不是我，我跟你不一樣。」", "q": 3, "tag": "⚠ 否認牠，牠就躲進更深的地方繼續牽線。看見「牠也是我」，才是真正的解脫。"}, {"t": "「我認得你。以後你出聲時，我會聽見——然後由我決定。」", "q": 0, "tag": "✓ 影子點了點頭，化作劍身上的第一道刻紋。牠不會消失，但牠再也不能自動駕駛你的人生。"}, {"t": "「走開！我再也不要看到你了！」", "q": 1, "tag": "◐ 趕不走的——牠是你的一部分。對付影子的方法不是驅逐，是看見牠，然後選擇。"}]}, {"h": 1, "text": "霧開始在教室裡飄。你：", "c": [{"t": "「哪個人最少我就填哪個，比較涼。」", "q": 3, "tag": "⚠ 用「最涼」當羅盤，一年後你會得到一個很涼、但跟你毫無關係的下午。"}, {"t": "「隨便啦，反正社團就是去玩玩的。」", "q": 2, "tag": "「隨便」一出口，指標又全部變成「都可以」了。一年後的你會拿到什麼？大概也是「隨便」。"}, {"t": "先想三十秒：這一年我想多會一點什麼？再挑。", "q": 0, "tag": "✓ 你把「選社團」變成了「選一個版本的自己」。霧退了。"}, {"t": "「你選哪個我就選哪個啊，跟你一起。」", "q": 1, "tag": "◐ 跟朋友同社不是罪。但「因為他選」是他的理由——你的理由呢？霧變濃了一點。"}]}, {"h": 1, "text": "你心裡其實對吉他有點癢癢的——但聽說吉他社要上台表演，有點可怕。 朋友選的是輕鬆的桌遊社。", "c": [{"t": "「上台太可怕了，還是跟朋友去桌遊社。」", "q": 1, "tag": "◐ 避開可怕是人之常情。只是要誠實：你選的是桌遊，還是「逃跑」？這兩個結局不一樣。"}, {"t": "先把單子塞回聯絡簿，明天到了再說。", "q": 2, "tag": "不選，也是一種選——而且是把方向盤丟給「截止日」的那種。"}, {"t": "兩個都勾，到時候再看哪個好玩。", "q": 3, "tag": "⚠ 什麼都想要，等於什麼都沒選。霧最愛這種「先全留著」——留到最後一個都不剩。"}, {"t": "想像學期末：會彈一首歌的我，跟桌遊變強的我，想當哪個？", "q": 0, "tag": "✓ 這就是以終為始：先看見學期末的自己，再決定今天填哪張單。怕，可以帶著怕去。"}]}, {"h": 1, "text": "目標欄空白。你想寫什麼？", "c": [{"t": "先問：這次我想當一個怎麼準備的學生？再回推。", "q": 0, "tag": "✓ 高手。分數是結果，「我想成為哪種準備者」才是你能直接動手的終點。"}, {"t": "「目標就是考完不要哭，平安下莊。」", "q": 3, "tag": "⚠ 把終點設在「不要太慘」，那準備的時候自然也只會「不要太混」。低標養出低標。"}, {"t": "「總分進步，不要再被爸媽念了。」", "q": 1, "tag": "◐ 「不要被念」是逃避型目標——它的終點是別人的嘴，不是你。霧沒退。"}, {"t": "直接抄隔壁的：「進步 10 分」就好。", "q": 2, "tag": "抄來的目標，霧一吹就散。三天後你就會忘記自己寫過它。"}]}, {"h": 1, "text": "你決定認真寫。下面哪一個目標，最有「導航」的功能？", "c": [{"t": "「這次絕對不能再考爛，拜託拜託。」", "q": 3, "tag": "⚠ 祈禱不是計畫。「拜託」喊一百遍，也不會自動變成明天的第一步。"}, {"t": "「全科都要進步，這次一定要拼了！」", "q": 1, "tag": "◐ 氣勢滿分，座標零分。「拼了」的隔天早上，要從哪一步開始拼？"}, {"t": "「數學考好一點。」", "q": 2, "tag": "「好一點」是霧做的目標——它沒有形狀，到了也不知道到了。"}, {"t": "「每晚 8 點算數學例題，考前把錯題本翻兩遍。」", "q": 0, "tag": "✓ 看，這個目標自帶地圖——每天晚上 8 點，你都知道下一步往哪走。"}]}, {"h": 1, "text": "舉手的衝動跟「會出糗吧」的聲音在打架。這時候，該問自己哪個問題？", "c": [{"t": "「畢業時，我想當試過的人，還是台下的人？」", "q": 0, "tag": "✓ 你把鏡頭拉到了終點再回頭看——這一看，眼前的「可怕」忽然變小了。"}, {"t": "「有沒有別人要舉？有的話就算了。」", "q": 1, "tag": "◐ 等別人決定你的選項——方向盤又交出去了。"}, {"t": "「上台有沒有加分？沒有的話幹嘛累。」", "q": 3, "tag": "⚠ 只用「有沒有加分」導航，你會錯過所有不加分、卻會長大你的事。"}, {"t": "「全班會怎麼看我？會不會被笑？」", "q": 2, "tag": "這個問題的答案在別人腦袋裡，你永遠查不到。拿它來做決定，等於讓霧導航。"}]}, {"h": 1, "text": "你決定舉手了。但下一秒又想：萬一上台搞砸呢？", "c": [{"t": "「搞砸就當練到了。我的終點是『敢上台』，不是這次完美。」", "q": 0, "tag": "✓ 終點設對了，連失敗都會變成路上的風景，而不是路的盡頭。"}, {"t": "「那我要寫逐字稿，背到一字不差才安心。」", "q": 1, "tag": "◐ 準備是好事。但「不容許任何意外」這個終點，本身就是個意外製造機。"}, {"t": "「對欸，一定會搞砸。手還是放下好了。」", "q": 2, "tag": "你讓「想像中的失敗」否決了「真實的想要」。霧最愛這招。"}, {"t": "「先舉再說，到時候不行就裝病請假。」", "q": 3, "tag": "⚠ 你舉的不是手，是一張「之後再逃」的票。霧不介意你先答應——它賭你最後會放鳥。"}]}, {"h": 1, "text": "第一格要填什麼？你的腦中閃過好幾個聲音。哪一個值得先聽？", "c": [{"t": "「大家都說那間最好，填它準沒錯啦。」", "q": 1, "tag": "◐ 「大家都說」是別人的地圖。別人的地圖能參考，但你要去的地方得自己標。"}, {"t": "「我做什麼事最忘記時間？從那裡開始想。」", "q": 0, "tag": "✓ 「忘記時間」是興趣留下的腳印。沿著腳印找，比沿著排名找，更接近你的終點。"}, {"t": "「現在想這個太早了，空白交出去算了。」", "q": 2, "tag": "九年級的霧，是八年級的空白養大的。現在不用決定，但可以開始看。"}, {"t": "「填分數剛好能上的就好，穩。」", "q": 3, "tag": "⚠ 用分數倒推志願，你會走到一個「上得了」但「不是你的」地方。穩，不等於對。"}]}, {"h": 1, "text": "你想到自己每次做簡報、排版面的時候最起勁。但設計類的學校，爸媽好像不會喜歡。", "c": [{"t": "上網查哪個科系最好賺，照那個填。", "q": 3, "tag": "⚠ 用「最好賺」當唯一座標，十年後你可能很忙、很累、卻不記得自己為什麼出發。"}, {"t": "「反正最後是爸媽決定，想了也白想。」", "q": 2, "tag": "這句話一說完，方向盤就真的、完全地，不在你手上了——是你自己鬆手的。"}, {"t": "寫一個爸媽會滿意的，自己想的放心裡。", "q": 1, "tag": "◐ 可以理解。但小心：放在心裡又不拿出來看的東西，會被霧慢慢收走。"}, {"t": "先誠實寫下來——這只是初探，又不是簽約。回家再聊。", "q": 0, "tag": "✓ 對。這張單子的終點是「更認識自己」，不是「討好誰」。誠實的座標才能導航。"}]}, {"h": 1, "text": "你放下筷子。第一句話，你說：", "c": [{"t": "「蛤——為什麼都不先問我！」（摔筷子）", "q": 2, "tag": "開戰了。注意：你抗議的是「沒被問」，但聽在媽媽耳裡變成「不想學好」。兩邊都迷航。"}, {"t": "「媽，我先講我的計畫，數學我想補強哪一塊。」", "q": 0, "tag": "✓ 你沒有拒絕補習，你拿出了「自己的地圖」。有地圖的人，才有得談。"}, {"t": "「不要！我就是不去，你逼我也沒用！」", "q": 3, "tag": "⚠ 純拒絕沒有地圖，只有對抗。媽媽看到的不是你的方向，是你的叛逆。霧很開心。"}, {"t": "「⋯⋯喔，好。」（心裡狂翻白眼）", "q": 1, "tag": "◐ 你上了一台別人設定目的地的車。之後每個週三的不甘願，都是這聲「喔」付的利息。"}]}, {"h": 1, "text": "媽媽說：「你自己讀有用的話，需要我幫你報名嗎？」——嗯，這句有點刺，但也有點真。", "c": [{"t": "「好，我去，但我去了不一定會聽。」", "q": 3, "tag": "⚠ 用「人到心不到」報復，最後罰到的是自己的時間。賭氣的座標，通往的全是浪費。"}, {"t": "「那約一個檢查點：這次數學沒到 75 我就去上，不囉嗦。」", "q": 0, "tag": "✓ 漂亮——你把「不想去」升級成「一個有終點、有期限、可驗收的提案」。這已經是大人的談法了。"}, {"t": "「補習就有用嗎？班上補的人也考很爛！」", "q": 1, "tag": "◐ 也許是事實，但這是在攻擊她的地圖，不是在展示你的。吵贏了論點，輸掉了信任。"}, {"t": "「隨便啦，你們要我去我就去。」", "q": 2, "tag": "「隨便」第二次出現了。注意看，霧已經漫到餐桌上了。"}]}, {"h": 1, "text": "腦中重播著剛剛的對話。這時候，霧遞給你三個念頭：", "c": [{"t": "傳訊息跟朋友罵媽媽，罵到睡著為止。", "q": 3, "tag": "⚠ 罵爽了，問題還在原地，明早起來霧更濃。出口從來不在別人的安慰裡。"}, {"t": "先別管誰對誰錯：半年後我想跟媽媽什麼關係？", "q": 0, "tag": "✓ 在最氣的晚上問「我要去哪」，是這一層最高難度的動作。你做到了。"}, {"t": "把她剛剛講的難聽話記下來，下次回敬。", "q": 1, "tag": "◐ 你在為「下一場戰爭」備戰——也就是說，你已經把終點設在「再吵一次」了。"}, {"t": "「明天開始冷戰，看誰先撐不住。」", "q": 2, "tag": "冷戰的終點是什麼？你有想過嗎？沒有終點的戰爭，霧最喜歡了——可以打很久。"}]}, {"h": 1, "text": "你心裡浮出一個畫面：你其實希望可以跟媽媽像朋友一樣講話。 如果那是終點——明天早上的第一步是什麼？", "c": [{"t": "先觀察她臉色，她先對我好我再對她好。", "q": 1, "tag": "◐ 你把第一步外包給她的臉色了。如果她也在等你的臉色呢？兩個人就一起站在原地。"}, {"t": "沒有第一步。時間久了自然就會好。", "q": 2, "tag": "「自然就好」的意思是：讓霧決定你們的關係往哪漂。有時漂回來，有時漂走。"}, {"t": "假裝沒事，但心裡記著這筆，慢慢疏遠。", "q": 3, "tag": "⚠ 表面和平、暗中記帳——這是最濃的霧。關係沒斷，只是被你悄悄設定成「往遠方漂」。"}, {"t": "早餐時說：「昨天我口氣很差，那部分我道歉。」", "q": 0, "tag": "✓ 只認自己的那一份，然後把話題帶回「想法」而不是「輸贏」。這一步，正好踩在通往那個終點的路上。"}]}, {"h": 1, "text": "手遊彈出通知：「限定卡池最後 48 小時！」你：", "c": [{"t": "「先抽再說，反正紅包明年還會有。」", "q": 3, "tag": "⚠ 把未來的紅包先花掉，是霧的記帳法。明年的錢有明年的用途——它不是這次衝動的提款機。"}, {"t": "「都想要⋯⋯先不想了，錢放著再說。」", "q": 2, "tag": "不決定的錢最危險——它會在某個更小的衝動裡，一百、兩百地蒸發掉。"}, {"t": "「最後 48 小時欸！先抽，相機之後再存就好。」", "q": 1, "tag": "◐ 注意「之後再存」這四個字——它是霧的語言。每次都有一個「最後 48 小時」，「之後」永遠不會來。"}, {"t": "比一下終點：有角色的我，跟開始拍片的我，想當哪個？", "q": 0, "tag": "✓ 這不是「存錢就是乖」的說教題——是「哪個終點是你的」。你用終點挑了，這就對了。"}]}, {"h": 1, "text": "假設你真心想了之後，發現你就是超想要那個角色——抽卡讓你快樂。", "c": [{"t": "全梭。快樂最重要，想那麼多幹嘛。", "q": 1, "tag": "◐ 快樂是真的。只是抽完的第三天，那個「想拍片的你」會輕輕問一句：那我呢？"}, {"t": "抽完發現不夠，再偷偷動用相機基金補。", "q": 3, "tag": "⚠ 防線一旦破一次，就沒有防線了。相機基金少一塊，那個終點就遠一步。"}, {"t": "邊抽邊罪惡，抽完更想再抽一次彌補。", "q": 2, "tag": "最虧的就是這種——錢花了，快樂卻被罪惡感折半，然後用更多的花費去補。霧的完美循環。"}, {"t": "那就抽，但設一條線：這次花一千，剩的住進相機基金。", "q": 0, "tag": "✓ 對。以終為始不是禁慾——是「知道自己要去哪，然後有意識地決定在路邊停留多久」。"}]}, {"h": 1, "text": "回想上個暑假的消失之謎。它是怎麼不見的？", "c": [{"t": "「都怪爸媽都不幫我安排活動。」", "q": 2, "tag": "等等，這是第一層的絲線吧？你的假期要別人來規劃？"}, {"t": "「時間過太快，這誰也沒辦法的事。」", "q": 3, "tag": "⚠ 時間對每個人都一樣快。差別在：有人留下了東西，有人只剩「咻一聲」。"}, {"t": "「暑假本來就是拿來耍廢的啊，正常。」", "q": 1, "tag": "◐ 耍廢完全合法！但「選擇耍廢」跟「醒來發現只剩耍廢」是兩種假期——前者爽，後者空。"}, {"t": "「每天起床想說先滑一下，然後就晚上了。」", "q": 0, "tag": "✓ 賓果，你找到兇手了——不是手機，是「沒有任何一天知道自己要幹嘛」。承認這個，是改變的第一步。"}]}, {"h": 1, "text": "這個寒假，你想讓它不一樣。哪種計畫法最不會變成廢紙？", "c": [{"t": "等過幾天有靈感了，再來想要做什麼。", "q": 3, "tag": "⚠ 「等有靈感」是霧的拖字訣。靈感不會自己來敲門，它只回應已經出發的人。"}, {"t": "只定一個終點：「開學想帶一個__回教室」，每天做一點。", "q": 0, "tag": "✓ 一個終點，每天一小步——這種計畫殺不死。學會一首歌、剪出一支影片、讀完一本書，都算。"}, {"t": "不計畫。計畫了也不會照做，何必騙自己。", "q": 2, "tag": "「反正也不會照做」——你直接在假期第一天，幫整個假期蓋了「繞圈」的章。"}, {"t": "排一張精確到每小時的作息表，貼在牆上。", "q": 1, "tag": "◐ 氣勢可嘉——但這種表通常活不過三天，然後你會因為破表而整個放棄。終點太多＝沒有終點。"}]}, {"h": 1, "text": "一週後，你發了新作品。一個陌生帳號留言：「畫這什麼，好醜。」", "c": [{"t": "刪文。果然我不適合發作品。", "q": 2, "tag": "一個陌生人的一句話，就能沒收你三小時的努力＋整個帳號的終點？牠在霧裡笑了。"}, {"t": "從此每張畫都先想：會不會被人嫌醜？", "q": 3, "tag": "⚠ 你把陌生人裝進了腦袋裡當審查官。從此每一筆，都在替他畫，不是替自己。"}, {"t": "想一下：這人在我要去的地方裡嗎？不在，封鎖。", "q": 0, "tag": "✓ 「他在不在我的終點裡」——這是過濾噪音最快的篩子。不在的，連生氣的額度都不用給。"}, {"t": "氣不過，跟他在留言區對罵一整晚。", "q": 1, "tag": "◐ 你今晚的三小時，從「畫下一張」變成了「跟陌生人吵架」。誰偷走的？"}]}, {"h": 1, "text": "你的手指放在鍵盤上。先想什麼？", "c": [{"t": "「不敢去也不敢拒絕⋯⋯先已讀不回。」", "q": 2, "tag": "已讀不回不是選項，是把選擇權交給「最後一刻的壓力」。那時候的你，通常選得最差。"}, {"t": "把兩條路各走到底：去得到什麼、錯過什麼？", "q": 0, "tag": "✓ 兩條路都「走到終點再回頭看」——這個動作不到一分鐘，但它讓選擇變成你的。"}, {"t": "「八個人都去，不去多掃興——先答應再說。」", "q": 1, "tag": "◐ 「大家都」是世界上最濃的霧之一。八個人有八個自己的理由，但你還沒找到你的。"}, {"t": "「翹一次又不會怎樣，課改天補就好。」", "q": 3, "tag": "⚠ 「改天補」跟「之後再存」是同一團霧。改天的課改天有它的事——這次的洞，補不回來。"}]}, {"h": 1, "text": "你想清楚了：這次的數學檢討你真的需要。怎麼回群組？", "c": [{"t": "「我媽不准啦」——推給媽媽，自己不用扛。", "q": 3, "tag": "⚠ 借別人當擋箭牌，當下輕鬆，但你練的是「不敢為自己的選擇負責」。下次還是會被霧困住。"}, {"t": "「明天那堂我得去，你們玩！下週五換我開團。」", "q": 0, "tag": "✓ 拒絕一次邀約，不等於拒絕朋友——你還主動丟回一個新的約。座標清楚的人，連說「不」都不心虛。"}, {"t": "「我看看啦，明天再說。」（其實不想去）", "q": 1, "tag": "◐ 模糊的回答買到一晚安寧，但明天你要嘛被奪命連環 call，要嘛被說「最不乾脆」。"}, {"t": "「好啦好啦我去。」（無奈嘆氣）", "q": 2, "tag": "你用自己的終點，換了一句「夠意思」。這種交易做多了，方向盤上就全是別人的手。"}]}, {"h": 1, "text": "二十五歲的老同學笑著問：「欸！好久不見——你這幾年都在忙什麼啊？」 你希望那時的自己，最想怎麼回答？", "c": [{"t": "「賺很多錢啊，其他的我沒在管。」", "q": 3, "tag": "⚠ 錢可以是終點的一部分，但如果它是「全部」，這場同學會你會聊得很大聲、很空。"}, {"t": "「我在做一件我自己選的事，做得還不錯。」", "q": 0, "tag": "✓ 注意到了嗎？你最在意的不是「多厲害」，是「自己選的」。這就是你的羅盤針。"}, {"t": "「就⋯⋯還行吧，跟大家差不多啦。」", "q": 1, "tag": "◐ 如果十年後的你只敢這樣回答——今天的你，願意幫他改寫這句台詞嗎？"}, {"t": "「不知道欸，到時候再說吧。」", "q": 2, "tag": "連想像中的自己都拿不出答案——這就是霧住進心裡的樣子。再想一次，這裡不限時。"}]}, {"h": 1, "text": "岔路一・星期二下午。 美術老師說下個月有校內漫畫比賽，自由報名。你畫畫不錯，但報名要交三頁完稿，很花時間。", "c": [{"t": "拿鏡子照一下：這件事在不在我要去的方向上？", "q": 0, "tag": "✓ 對，答案不重要，「照鏡子」這個動作才重要。報或不報都可以是好選擇——只要是對著終點選的。"}, {"t": "「太麻煩了，這種比賽跳過就好。」", "q": 3, "tag": "⚠ 用「麻煩」當篩子，你會篩掉所有需要花力氣、卻會長大你的事。霧最愛省事的人。"}, {"t": "「再看看啦，反正還有一個月。」", "q": 2, "tag": "「再看看」＝讓截止日替你選。一個月後你會「來不及」——那不是選擇，是霧的安排。"}, {"t": "問同學要不要報，他報我就報。", "q": 1, "tag": "◐ 又把鏡子借給別人照了。他的終點裡有沒有漫畫，跟你的終點裡有沒有，是兩件事。"}]}, {"h": 1, "text": "岔路二・星期四晚上。 功課寫完還有一小時。手機在桌上發光。", "c": [{"t": "「滑一下就好。」（一小時後：怎麼十一點了）", "q": 1, "tag": "◐ 沒有罪，但請誠實記帳：這一小時是「你選擇的休息」，還是「被收走的時間」？感覺不一樣，你知道的。"}, {"t": "想到鏡子裡的目標——分三十分鐘給它，再滑。", "q": 0, "tag": "✓ 三十分鐘看起來很小。但終點是由一百個星期四的三十分鐘鋪成的，不是一次熱血。"}, {"t": "「今天好累，明天再說。」（連續第四天）", "q": 2, "tag": "累是真的。但「連續第四天」也是真的。霧不會搶你的時間——它只是每天輕輕地說「明天再說」。"}, {"t": "乾脆連功課都先放著，明天早自習趕。", "q": 3, "tag": "⚠ 把今天的洞推給明天的自己——明天的你會同時面對舊洞和新事。霧最會玩這種「延期付款」。"}]}, {"h": 1, "text": "岔路三・星期日早上。 阿嬤打電話來，想找你回去吃午飯。你本來打算耍廢一整天。", "c": [{"t": "想起鏡子裡「身邊的人」那塊——去。晚上再耍廢。", "q": 0, "tag": "✓ 十年後的你，會記得這頓午飯，不會記得那天少滑的三小時。你已經會用終點換算價值了。"}, {"t": "「今天就是要徹底耍廢，誰來都不去。」", "q": 3, "tag": "⚠ 耍廢可以選，但用「誰來都不去」把人擋掉，擋掉的是十年後你最想留住的東西。"}, {"t": "「跟阿嬤說下次啦，反正她常打來。」", "q": 1, "tag": "◐ 可以。只是「下次」這個詞，這一層已經教過你了——它常常是霧的另一個名字。"}, {"t": "已讀媽媽轉達的訊息，裝沒看到。", "q": 2, "tag": "連「下次」都不肯說，是因為說了會內疚吧。看，你心裡其實有鏡子的——只是不敢照。"}]}, {"h": 1, "text": "霧開始滲進你的腦袋。你發現自己漸漸想不起來——剛剛、自己是為了什麼下來的？ 快，做點什麼：", "c": [{"t": "站在原地大喊：「出口到底在哪裡！」", "q": 1, "tag": "◐ 霧親切地回答：「都可以喔～」。問牠是沒有用的——出口不在霧裡，在你身上。"}, {"t": "蹲下來抱頭，等霧自己散去。", "q": 3, "tag": "⚠ 霧不會自己散，它靠的就是你「等等看」。等待，是無向最忠實的食物。"}, {"t": "隨便挑一條路就衝進去。", "q": 2, "tag": "你全力奔跑了很久很久⋯⋯然後撞上了自己的背影。在無向的領域裡，沒有方向的衝刺都是圓。"}, {"t": "拔出劍，掏出終點之鏡。", "q": 0, "tag": "✓ 鏡面亮起，照出你選過的字。霧發出「嘶」的一聲，從鏡光裡退開——牠最怕有座標的人。"}]}, {"h": 1, "text": "鏡光逼退了霧，但「無向」變換了戰術。牠化成你的聲音，在你耳邊說： 「選錯怎麼辦？萬一你選的路，最後是錯的呢？不選，就永遠不會錯喔。」", "c": [{"t": "「那你告訴我哪條對，我就走哪條！」", "q": 1, "tag": "◐ 牠等的就是這句。把「選對的責任」交出去的人，牠最好收編。鏡子還在你手上——自己照。"}, {"t": "「那我每條都走一點，這樣最保險。」", "q": 3, "tag": "⚠ 每條都走一點＝每條都半途而廢。想不選錯而全保留，最後一條都到不了。"}, {"t": "「不選永遠不會錯——也永遠不會到。我選，錯了再修。」", "q": 0, "tag": "✓ 霧劇烈地翻騰起來。「錯了就修」這四個字，拆掉了牠最大的武器——對「選錯」的恐懼。"}, {"t": "「⋯⋯對欸，那我再多想幾年好了。」", "q": 2, "tag": "霧滿意地濃了起來。「多想幾年」在這一層的意思是：在原地，多繞幾年。"}]}, {"h": 1, "text": "空白之鏡布滿裂痕。霧中伸出最後一隻手——溫暖、放鬆、毫無威脅。 「好啦好啦，你贏了。那⋯⋯休息一下總可以吧？路那麼長，先在這裡躺一下，明天再走～」", "c": [{"t": "「也對⋯⋯那就躺一下下好了。」", "q": 2, "tag": "霧裡的「一下下」沒有刻度——很多人躺成了迴廊裡的人影。睜開眼，握緊鏡子！"}, {"t": "「不行！我永遠不能休息，停下就輸了！」", "q": 1, "tag": "◐ 不對，那是另一個極端——把你燒乾，是第七層古神的業務。有方向的人，敢休息。"}, {"t": "「你說得對，先躺著等明天有力氣再走。」", "q": 3, "tag": "⚠ 把出發的條件設成「等有力氣」，霧就有藉口讓你一直沒力氣。它最怕「沒力氣也先走一步」。"}, {"t": "「休息可以——但我躺在『我的路』上，不躺在你的霧裡。」", "q": 0, "tag": "✓ 完美的最後一擊。連「休息」都分得清座標的人，無向再也沒有任何縫隙可鑽了。"}]}, {"h": 1, "text": "空白之鏡轟然碎裂。霧散去——迴廊消失了，眼前只剩一條路：你的。 碎鏡的中央，站著一個小小的影子：是那個說「隨便」「都可以」「再看看」的你。 牠小聲說：「⋯⋯可是選擇好累喔。」", "c": [{"t": "「閉嘴！不准再給我說隨便！」", "q": 1, "tag": "◐ 對影子兇沒有用——牠是你的一部分。承認累，然後拿出鏡子。這才是收服牠的方式。"}, {"t": "「你說得對，選擇太累，我不想長大。」", "q": 3, "tag": "⚠ 不想長大，霧就會永遠替你決定。累，但伸出手——這一步，就是長大本身。"}, {"t": "「⋯⋯真的好累。算了，到這就好。」", "q": 2, "tag": "你已經走到牠面前了——最後一步是伸出手，不是坐下來。再撐三秒。"}, {"t": "「我知道。所以我鑄了鏡子——累的時候照一下就好。」", "q": 0, "tag": "✓ 影子點點頭，化作劍身第二道刻紋。「隨便」不會消失——但從今天起，它只是你累的訊號，不是你的方向。"}]}, {"h": 2, "text": "手機亮起：班群在傳一個超好笑的影片，已經 +47 則了。", "c": [{"t": "「先回個幾句，馬上回來讀。」", "q": 1, "tag": "◐ 「馬上回來」的平均時長是 35 分鐘——這是這一層牆上刻的統計數字。"}, {"t": "「看一下就好，不然等下跟不上話題。」", "q": 2, "tag": "四十分鐘後你還在群裡。「跟上話題」頭上的驚嘆號是貼紙——你撕都沒撕就信了。"}, {"t": "乾脆關掉講義，跟著群組一路滑下去。", "q": 3, "tag": "⚠ 兩題就棄械投降——千急連幻術都不用出，你自己把整個晚上送上門了。"}, {"t": "螢幕朝下調靜音：「九點寫完再當點心看。」", "q": 0, "tag": "✓ 你沒有消滅雜兵，你只是「排程」了牠——這就夠了。雜兵被排程的瞬間就縮小一半。"}]}, {"h": 2, "text": "九點，你真的寫完一回了。這時你想起：自然小考好像也是後天？但今天排的進度只有數學。", "c": [{"t": "「兩科都讀不完了，乾脆都別讀。」", "q": 3, "tag": "⚠ 用「反正都來不及」把自己整個放生——這是焦慮假扮的雜兵裡，最毒的一隻。"}, {"t": "「慘了，數學丟著，現在馬上換讀自然！」", "q": 1, "tag": "◐ 看到了嗎？「後天的小考」剛剛貼上驚嘆號變裝成雜兵，把你正在搬的大石頭撞掉了。"}, {"t": "把七天攤開，每天放一顆大石頭，自然排後天早自習。", "q": 0, "tag": "✓ 你在用「一週」思考，不是用「今晚」思考。千急最怕這種人——牠的幻術只對「只看眼前」的人有效。"}, {"t": "「想到就煩，先躺一下再說。」", "q": 2, "tag": "焦慮沒被處理的時候，最常變成「先躺一下」。然後它會在十一點半準時回來——加倍。"}]}, {"h": 2, "text": "「順便啦～拜託～」他說。你看看作文稿紙，再看看他。", "c": [{"t": "「好，但你也幫我寫一段作文。」", "q": 3, "tag": "⚠ 你把一件雜事換成兩件雜事，作文還被別人代筆。這不是談判，是把自己的時間賤賣。"}, {"t": "「這節我趕作文真的不行，你問小李？」", "q": 0, "tag": "✓ 注意你做的事：拒絕了「事」，沒拒絕「人」，還給了出路。Q3 雜兵就該這樣擋。"}, {"t": "「你自己不會去喔？」（翻白眼）", "q": 2, "tag": "擋是擋掉了，但刀法太糙——你用「傷關係」的方式擋一隻小雜兵，不划算。"}, {"t": "「好啦好啦。」（反正才十分鐘）", "q": 1, "tag": "◐ 十分鐘跑腿＋五分鐘排隊＋十分鐘被別班攔住聊天。你的作文剩最後一節課的二十分鐘了。"}]}, {"h": 2, "text": "他又加碼：「吼——好朋友欸！連這個都不幫？」 （這句話頭上的驚嘆號，特別大顆。）", "c": [{"t": "「好朋友就該幫，那走吧。」（馬上起身）", "q": 3, "tag": "⚠ 「好朋友就該」這頂帽子一戴上，你就交出了所有界線。下次他還會用同一頂。"}, {"t": "不理他，低頭繼續寫自己的。", "q": 1, "tag": "◐ 守住了時間，但已讀不回式的拒絕會留下小疙瘩。多一句話的成本，買得回來。"}, {"t": "「⋯⋯好啦，給我錢，我去。」（嘆氣）", "q": 2, "tag": "這聲嘆氣，是你的時間被搬走的聲音。而且他學到了：加碼那句話，對你有效。"}, {"t": "「就因為是好朋友，我才敢說我在趕。下課陪你去。」", "q": 0, "tag": "✓ 完美拆招。「好朋友」三個字被牠拿來當武器，你把它拿回來當橋。"}]}, {"h": 2, "text": "練團學長問你：「成發前那兩週，你可以每天留下來練嗎？」", "c": [{"t": "「⋯⋯那我退出成發好了，怕影響成績。」", "q": 1, "tag": "◐ 等等，這顆石頭是你「真心想要」的——還記得第二層的鏡子嗎？先別急著丟，先試著排。"}, {"t": "「一三五留下練，二四回家衝進度，歌保證練好。」", "q": 0, "tag": "✓ 你沒有放棄任何一顆大石頭——你給了它們各自的位子。這才叫「裝得下」。"}, {"t": "「兩個都不要了，乾脆都放掉最輕鬆。」", "q": 3, "tag": "⚠ 為了不選而全丟——這不是要事第一，是兩顆大石頭一起棄養。千急最愛這種乾脆。"}, {"t": "「可以！」（先答應，段考的事到時候再想）", "q": 2, "tag": "「到時候再想」＝把兩顆大石頭疊在同一天砸自己。到時候的你，會恨現在的你。"}]}, {"h": 2, "text": "計畫排好了。但執行第三天，朋友揪你練完團再去吃宵夜聊天，「反正都這麼晚了～」", "c": [{"t": "「今天不行，回去還有一回數學。週五我請宵夜！」", "q": 0, "tag": "✓ 計畫不是用來排的，是用來守的。而你守的方式還附了一個更好的約——漂亮。"}, {"t": "「呃⋯⋯」（被拉走了，回家十一點半）", "q": 2, "tag": "沒說出口的「不」，等於「好」。你的二四晚上，剛剛被雜兵搬走一個。"}, {"t": "「去啊，明天的進度再補回來就好。」", "q": 3, "tag": "⚠ 「明天再補」是雜兵的萬用咒——明天有明天的進度，這一夜的洞，補不回來。"}, {"t": "「好啊走！」（計畫是死的，人是活的嘛）", "q": 1, "tag": "◐ 「人是活的」這句話本身沒錯——但連續說三天，計畫就死了。"}]}, {"h": 2, "text": "假設今天沒有考試，是顆普通的下課。隔壁在揪你去走廊看別班吵架，「超精彩的快來！」", "c": [{"t": "每節下課都圍觀＋滑手機，廁所用衝的。", "q": 2, "tag": "一天七個下課＝七十分鐘。一學期下來，你捐了多少時間給「別人的戲」？千急謝謝你的贊助。"}, {"t": "衝過去加入吵架，幫其中一邊嗆聲。", "q": 3, "tag": "⚠ 你不只捐了時間，還把自己捲進別人的戰場——這是 Q3 雜兵最豐盛的一餐。"}, {"t": "覺得脖子好痠，去裝水、伸展、看看窗外。", "q": 0, "tag": "✓ 這也是「要事」喔——身體的保養永遠重要、永遠不緊急。你居然在十分鐘裡搬了一顆 Q2 石頭。"}, {"t": "「喔走啊。」（圍觀十分鐘，吸收了零）", "q": 1, "tag": "◐ 偶一為之，無罪。但「別人的戲」是 Q3 界的大明星——永遠精彩，永遠跟你無關。"}]}, {"h": 2, "text": "你躺下了，手機自動到手上。回過神來——七點四十。晚餐都涼了。", "c": [{"t": "邊吃飯邊滑，想說吃完再算。", "q": 1, "tag": "◐ 你在用「等一下」延長「剛剛」。黑洞的引力就是這樣運作的。"}, {"t": "「兩小時算了，剩三小時搶回一塊是一塊。」", "q": 0, "tag": "✓ 高手心法：不為打翻的時間哀悼，只問「剩下的時間裡，最大的石頭是哪顆」。現在搬。"}, {"t": "「都這時間了，乾脆滑到睡前算了。」", "q": 3, "tag": "⚠ 用「反正已經晚了」把整晚一起賠進去——這是黑洞最後、也最大的一口。"}, {"t": "「算了，今天就這樣，明天再認真。」", "q": 2, "tag": "「今天就這樣吧」是千急的安眠曲。唱三天，一週沒了；唱三週，一個學期沒了。"}]}, {"h": 2, "text": "隔天，你決定研究「沙發黑洞」的破解法。哪一招最有效？", "c": [{"t": "請媽媽五點半準時盯著我讀書。", "q": 1, "tag": "◐ 有效一週。然後你會開始恨被盯，媽媽會開始累。自己設計的流程，才守得久。"}, {"t": "買一張更舒服的沙發，躺得開心一點。", "q": 3, "tag": "⚠ 你不是在破解黑洞，是在升級黑洞。誘惑要繞路，不是鋪紅地毯。"}, {"t": "靠意志力：明天的我一定忍得住。", "q": 2, "tag": "五點半的意志力是全天最低點——拿最弱的兵去守最危險的關口，千急笑而不語。"}, {"t": "改流程：進門書包放桌、手機去客廳充電、先沖澡。", "q": 0, "tag": "✓ 對！別跟黑洞拔河，繞開它。把滑手機變成要多走十步的事，把開始讀變成順路的事——環境贏過意志力。"}]}, {"h": 2, "text": "「五缺一」對上「垃圾車」。你：", "c": [{"t": "「進了進了！」（垃圾⋯⋯應該來得及吧？）", "q": 2, "tag": "九點十分你聽到垃圾車的音樂遠去。那包垃圾會在陽台放兩天——連同你對媽媽的承諾。"}, {"t": "「你們先開，我八點四十五進——有件事先處理。」", "q": 0, "tag": "✓ 十五分鐘的差距而已，但兩顆石頭都進了位子。而且「說到做到」的存款，又進了一筆。"}, {"t": "「垃圾不倒了，明天再說，先打團。」", "q": 3, "tag": "⚠ 直接撕毀承諾去打團——這一局你贏了，媽媽的情感帳戶被你提了一大筆款。"}, {"t": "「我問我媽可不可以明天倒。」（狂傳訊息）", "q": 1, "tag": "◐ 媽媽在加班欸。而且這巷子明天沒收垃圾，你只是想把決定外包出去而已，對吧？"}]}, {"h": 2, "text": "進階題：反過來——你跟朋友約好八點半開團（你答應的），媽媽臨時叫你「現在馬上」去買醬油（其實燉湯十點才用得到）？", "c": [{"t": "「好啦！」（怒氣沖沖出門，整晚臭臉）", "q": 1, "tag": "◐ 事是做了，但你用「受害者模式」做的——成本最高的做法。"}, {"t": "「等一下啦！」（先打完再說，拖到被罵）", "q": 2, "tag": "「等一下」沒講清楚是多久，在大人耳裡＝「不想做」。然後戰爭就開始了。"}, {"t": "「現在很忙啦！」（頭也不抬繼續打）", "q": 3, "tag": "⚠ 對大人的真急用無視回應——就算這次醬油不急，你也示範了「我的遊戲比你重要」。帳，記下了。"}, {"t": "「媽，我九點半下線馬上去買，十點前到家來得及嗎？」", "q": 0, "tag": "✓ 你發現了嗎？大人的「現在馬上」，有時也是貼紙。確認真正的死線，再排位子——對誰都一樣。"}]}, {"h": 2, "text": "這一小時，你打開了一部影集。十一點，正好看完一集——畫面停在超大懸念。 「下一集」的按鈕在發光。", "c": [{"t": "關掉去睡，明天午休跟同學討論這懸念更香。", "q": 0, "tag": "✓ 你贏了一百個編劇。而且「期待明天看」本身也是一種快樂——還免費附贈七小時睡眠。"}, {"t": "「就一集。」（按下去）", "q": 2, "tag": "編劇的薪水就是用來讓你按這個鈕——你在跟一百個專業大人對決，而你已經連輸三天了。"}, {"t": "改成「邊滑短影音邊睡」。", "q": 1, "tag": "◐ 從一個黑洞跳進另一個更碎的黑洞。短影音沒有「一集」的盡頭——它是用「再三十秒」做的流沙。"}, {"t": "「都看到懸念了，整季拚完再睡。」", "q": 3, "tag": "⚠ 一集變一季，一小時變五小時。明天頂著熊貓眼進教室的，是被懸念綁架的你。"}]}, {"h": 2, "text": "劍靈問你：「說真的——你睡前那一小時，最常拿去做什麼？而你『最希望』它拿去做什麼？」", "c": [{"t": "「最常滑手機，最希望看小說、畫圖或好好睡。」", "q": 0, "tag": "✓ 看見落差，就是改變的起點。睡前一小時 × 365 天＝你每年最大的一筆自由時間。它值得一個位子。"}, {"t": "「想那麼多幹嘛，睡前就是要放空。」", "q": 3, "tag": "⚠ 「放空」跟「被牽著走」常常被混為一談——沒選擇的放空，醒來只剩空，沒有放。"}, {"t": "「沒想過。就⋯⋯就過了啊。」", "q": 2, "tag": "「就過了」的時間，一年有三百六十五個小時——等於九個整週的白天。千急把它們吃得連渣都不剩。"}, {"t": "「滑手機就是我最想做的啊。」", "q": 1, "tag": "◐ OK，誠實很好。那就「選擇地滑」——設鬧鐘、滑你真心喜歡的，而不是被推播餵食。選的跟被餵的，是兩種人生。"}]}, {"h": 2, "text": "劍靈丟給你一袋石頭和一袋沙：「罐子就這麼大。先放哪個？」", "c": [{"t": "先把沙倒進去——小事清完才能安心做大事。", "q": 2, "tag": "沙倒進去之後，石頭放不下了。「先清小事」是千古第一陷阱——因為小事永遠清不完。"}, {"t": "石頭沙子全倒進去搖一搖，碰運氣。", "q": 3, "tag": "⚠ 不分先後地全塞，結果就是石頭浮在表面、半數掉出來。週末會在「好像很忙又沒做成什麼」裡蒸發。"}, {"t": "不放了，週末就是耍廢用的，下週再說。", "q": 1, "tag": "◐ 耍廢可以是計畫的一部分（真的），但「全部下週再說」的意思是：下週的你，要扛兩週的石頭。"}, {"t": "大石頭先放：作業、訂正、阿公、剪片，沙填縫。", "q": 0, "tag": "✓ 石頭全進去了，神奇的是——沙子居然也塞得進縫裡。先後順序，就是全部的秘密。"}]}, {"h": 2, "text": "週日上午你正要剪片——表妹一家突然來訪，媽媽喊你出來陪。一坐就快中午了。", "c": [{"t": "躲回房間不出來，假裝在寫作業。", "q": 3, "tag": "⚠ 你既沒陪到人、也沒剪到片，還在阿公阿嬤那邊提了一筆款。三輸，雜兵滿載而歸。"}, {"t": "「計畫毀了！算了，剪片下週再說。」", "q": 2, "tag": "計畫被打亂≠計畫作廢。一次意外就棄船的人，千急根本不用出手。"}, {"t": "陪完客人重排：下棋照舊，剪片改剪三分鐘開頭。", "q": 0, "tag": "✓ 這就是高手跟普通人的差別——計畫被撞歪時，高手「縮小石頭」，普通人「丟掉石頭」。"}, {"t": "全程坐立難安、臭臉滑手機讓全家都知道。", "q": 1, "tag": "◐ 陪也陪了，氣也氣了——兩頭都沒賺到。要嘛好好陪，要嘛好好商量，臭臉是最虧的第三選項。"}]}, {"h": 2, "text": "你正在寫數學（要進入狀況超難那種）。第 11 題寫到一半——震動。同學問：「明天要穿班服嗎？」", "c": [{"t": "秒回，然後順便看了三個群組。", "q": 2, "tag": "為一題三十秒能回的事，你付出：第 11 題重想的五分鐘＋三個群組的十五分鐘。匯率超慘。"}, {"t": "讀書前就把手機設成段落結束才看的勿擾。", "q": 0, "tag": "✓ 最高段。不是「忍住不回」，是打造一個「不需要忍」的環境。專注力是用守的，不是用搶的。"}, {"t": "乾脆把手機放手邊，邊寫邊隨時瞄。", "q": 3, "tag": "⚠ 手機在視線內，你的注意力就在它身上——你以為在寫數學，其實在守著一隻隨時會叫的雜兵。"}, {"t": "不動，寫完這大題（還十分鐘）一次回。", "q": 1, "tag": "◐ 方向對了！再升一級：連「要記得等下回」這個念頭都會耗電——看下一招。"}]}, {"h": 2, "text": "但你心裡那個聲音還在：「不秒回，朋友會不會覺得我很冷淡？」", "c": [{"t": "想想自己：朋友兩小時後才回，我會絕交嗎？", "q": 0, "tag": "✓ 用自己的真實感受，破解想像的恐懼。「晚點回但好好回」的人，評價從來不差。"}, {"t": "「會吧⋯⋯所以還是只能秒回。」", "q": 2, "tag": "你用「想像中的差評」綁架了真實的一天。去問問身邊最受歡迎的人——他秒回嗎？通常不。"}, {"t": "在限動公告：「本人以後不秒回，見諒。」", "q": 1, "tag": "◐ 立意良善，但昭告天下反而把小事變大事。安靜地改變就好——根本沒有人在計時。"}, {"t": "「那我每則都秒回貼圖，至少有回。」", "q": 3, "tag": "⚠ 你為了不冷淡，把一天剁成八百段——貼圖三秒，回神三分鐘，這筆帳一天要付兩百次。"}]}, {"h": 2, "text": "盯著「每日任務 0/5」的畫面，你問自己：", "c": [{"t": "「都 147 天了，斷掉多可惜！」", "q": 2, "tag": "這叫「沉沒成本」——用已經花掉的時間，綁架接下來的時間。賭場和手遊公司最愛這招。"}, {"t": "「我是在玩遊戲，還是在被遊戲玩？」", "q": 0, "tag": "✓ 問出這題，鎖鏈就鬆了一半。「不想玩卻停不下來」的活動，已經不是娛樂——是雜兵的勞役。"}, {"t": "「先做完今天的再想。」", "q": 1, "tag": "◐ 可以。但「邊做邊想」通常做完就忘了想。給自己一個期限：這週末，認真回答一次。"}, {"t": "「想那麼多累，無腦點完就對了。」", "q": 3, "tag": "⚠ 「無腦點完」正是它設計給你的動作——四十分鐘無感蒸發，連快樂都沒換到。"}]}, {"h": 2, "text": "你認真盤點：這遊戲現在帶給你的快樂，大概只剩剛開始的兩成。但朋友都還在玩。", "c": [{"t": "改成「想玩才玩」：刪掉每日任務執念，週末開團再上。", "q": 0, "tag": "✓ 你把遊戲從「老闆」降回「朋友」。真正的玩家玩遊戲，被任務追著跑的是員工——而且沒薪水。"}, {"t": "「朋友都玩我退出多奇怪，跟著玩吧。」", "q": 3, "tag": "⚠ 用「大家都在玩」替一個你已經不快樂的習慣續命——這是雜兵跟從眾古神的聯合套餐。"}, {"t": "「再撐一下，搞不好改版就好玩了。」", "q": 2, "tag": "你在等遊戲公司「把你的快樂修好」。他們在忙著修的是「讓你離不開」的功能喔。"}, {"t": "直接刪 game，跟過去一刀兩斷！", "q": 1, "tag": "◐ 乾脆，但小心反彈——全有全無的戒斷常常一週後加倍奉還。「降級」通常比「戒斷」走得遠。"}]}, {"h": 2, "text": "「限定」兩個字閃著紅光。你：", "c": [{"t": "「跑完啊？三圈二十分鐘，你等我一起去。」", "q": 0, "tag": "✓ 誰說只能二選一？你把「答應自己的」跟「朋友的邀約」排成了一條線。兩個都贏。"}, {"t": "「限定欸！跑步哪天都能跑，先衝！」", "q": 3, "tag": "⚠ 「限定」是雜兵最亮的貼紙——它讓「永遠可以補」的小約，永遠補不回來。"}, {"t": "「好哇走！」（跑步嘛，下週再跑也一樣）", "q": 2, "tag": "注意——「跟自己的約」永遠最先被犧牲，因為它不會抗議。但它會記帳：你又示範了「我的承諾可以不算數」。"}, {"t": "「不行，我要跑步。」（頭也不回）", "q": 1, "tag": "◐ 守住了約，很好！只是補一句「跑完去找你」的成本是三秒——能讓朋友不覺得吃了閉門羹。"}]}, {"h": 2, "text": "第一天（週一）晚上。你攤開七天的空白表格。怎麼排？", "c": [{"t": "最不熟的兩科排前三天，每天留 30 分鐘彈性格。", "q": 0, "tag": "✓ 兩個高手動作：困難的先上（趁力氣最多），還幫「意外」預留了位子——計畫死不了的秘密就是彈性格。"}, {"t": "全部排「複習全部」，反正每天都讀全部。", "q": 3, "tag": "⚠ 「每天讀全部」＝每天什麼都沾一點、什麼都讀不透。沒有取捨的計畫，等於沒有計畫。"}, {"t": "不排了。古神都說活不過第二天，隨機應變吧。", "q": 2, "tag": "牠就是要你這樣想。沒地圖的七天，每一天都會被當下最大聲的事拖著走。"}, {"t": "排好排滿：每天六科各 50 分鐘，精確到分鐘！", "q": 1, "tag": "◐ 很美。美得像標本。第一個意外撞上來，整張表就會碎掉——因為它沒有任何縫。"}]}, {"h": 2, "text": "第三天（週三）。計畫進行中——突然，數學老師加發一張「明天要交」的複習卷（今晚排給英文了）。", "c": [{"t": "「複習卷就是數學複習——跟週五的數學格交換。」", "q": 0, "tag": "✓ 對！這張卷不是「額外的事」，是「換了包裝的原計畫」。換格子，不加格子——表格毫髮無傷。"}, {"t": "「先寫考卷⋯⋯群組在傳答案？看一下⋯⋯」", "q": 2, "tag": "雜兵假扮成「討論功課」混進來了。撕開貼紙：那是聊天，不是讀書。"}, {"t": "「明天的事明天再說，今晚照原計畫讀英文。」", "q": 3, "tag": "⚠ 你假裝沒看到那張要交的卷——它明天早上會變成 Q1 火災，當著全班的面燒你。"}, {"t": "「計畫被毀了！今晚熬夜兩個都做。」", "q": 1, "tag": "◐ 熬夜做完了，但你燒掉的是明天的專注力。先想「能不能換」，再想「要不要加」。"}]}, {"h": 2, "text": "第七天，考前最後一夜，十點半。進度完成了八成五。腦中冒出聲音：「再熬一下！把最後一成五拚完！」", "c": [{"t": "「八成五⋯⋯沒讀完怎麼辦」（焦慮滑手機到一點）", "q": 1, "tag": "◐ 最虧的結局：沒讀、沒睡、沒玩。焦慮是隻假雜兵——牠連體力都不配拿走。"}, {"t": "「乾脆別睡了，通宵讀到進考場。」", "q": 3, "tag": "⚠ 通宵的腦袋連題目都讀不進去。你不是在多讀，是在親手砸爛明天那顆要上場的腦袋。"}, {"t": "收書洗澡，十一點前睡。明天的腦袋比那一成五值錢。", "q": 0, "tag": "✓ 千急最後的詭計就是「考前熬夜」——用 15% 進度，換你 30% 的腦力。你沒上當。作戰成功。"}, {"t": "熬到兩點，拚到 100%！", "q": 2, "tag": "你帶著 100% 的進度和 60% 的腦袋進考場。考卷不考進度，考腦袋。"}]}, {"h": 2, "text": "第一波雜兵海撲來！一百件「小事」同時砸到你面前：回訊息！簽到！幫投票！看一下！就一集！ 劍靈大喊：「記住這一層教你的——！」", "c": [{"t": "不揮劍。任雜兵流過，眼睛鎖定漩渦中心的本體。", "q": 0, "tag": "✓ 雜兵穿過你的身體——原來九成根本是幻影！「不回應」就是對 Q3 最強的劍法。本體露出來了。"}, {"t": "邊擋邊喊：「等我清完這些就去打你！」", "q": 1, "tag": "◐ 塔頂傳來笑聲：「好啊～我等你清完～」——牠等了一千年了，沒有人清完過。"}, {"t": "原地蹲下抱頭，等雜兵海自己退去。", "q": 3, "tag": "⚠ 雜兵不會自己退，牠們靠的就是你的不動。被淹沒的勇者，最後都化成新的驚嘆號。"}, {"t": "揮劍迎戰！一件一件處理完再前進！", "q": 2, "tag": "你殺了一百隻，兩百隻補位。牠們是無限的——這正是千急的設計：讓你「忙到死也到不了牠面前」。"}]}, {"h": 2, "text": "你穿過雜兵海，逼近巨塔。千急改變戰術——牠從塔身抽出幾個「特別的驚嘆號」砸下來： 「你朋友的限動有哭臉！」「群組 99+！」「你的遊戲體力滿了正在浪費！」", "c": [{"t": "停下來一件一件檢查——萬一真有急事呢？", "q": 1, "tag": "◐ 檢查了：哭臉是電影心得、99+ 是貼圖、體力是體力。三分鐘沒了。偶爾檢查可以，「每個都檢查」就是陷阱。"}, {"t": "「我全部回完，回完心裡比較踏實。」", "q": 3, "tag": "⚠ 「回完才踏實」就是牠養你養了一千天的反射——而牠永遠有下一個 99+ 等著你回。"}, {"t": "「真正的急事會打電話來。」劍指巨塔，前進。", "q": 0, "tag": "✓ 正解！你訂出了自己的「真急判準」，從此牠的假警報全部失效。塔身出現第一道裂痕！"}, {"t": "「啊，體力滿了確實有點浪費⋯⋯」", "q": 2, "tag": "你在 Boss 戰裡打開了手遊。塔頂的笑聲大到整層深淵都在震。"}]}, {"h": 2, "text": "巨塔裂開，千急的真身從塔中探出——牠的臉，竟然是一張行事曆，上面密密麻麻寫滿了行程。 「看看你自己！」牠嘶吼，「你也一樣！忙！忙！忙！忙碌的人類最高尚了，不是嗎！」", "c": [{"t": "「忙才有面子，我要排得比誰都滿！」", "q": 3, "tag": "⚠ 把行事曆塞滿當勳章——你剛好戴上了牠的臉。滿，不等於有意義。"}, {"t": "「忙不等於重要。我寧可做成三件真正的事。」", "q": 0, "tag": "✓ 牠的行事曆臉開始燃燒——「忙＝充實」是牠的核心咒語，被你當面拆穿了。"}, {"t": "「我以後什麼都不做了！躺平最大！」", "q": 1, "tag": "◐ 從一個極端盪到另一個極端——千急和流沙是合作關係。要害不是「做多做少」，是「做的是不是你的事」。"}, {"t": "「對⋯⋯我好忙，忙到沒時間想我在忙什麼⋯⋯」", "q": 2, "tag": "牠溫柔地點頭：「對～繼續忙～不要停下來想～」——快醒來，「沒時間想」就是牠要的！"}]}, {"h": 2, "text": "千急的塔身崩塌中。牠射出最後的殺招——一根金色的驚嘆號，直直釘在你面前： 上面寫著：「明天段考！而你現在居然在這裡打我？！快回去讀書啊！！」", "c": [{"t": "「對欸！！」（丟下劍轉身就跑）", "q": 2, "tag": "在終點前一步被自己的焦慮調虎離山——回來！焦慮不是用跑的，是用排的！"}, {"t": "「謝謝提醒。我已排程：打完你，今晚就開始讀。」", "q": 0, "tag": "✓ 致命一擊！連牠本人都被你放進了四象限。當「焦慮」變成「排程」的瞬間，千急失去了所有武器。"}, {"t": "「段考不重要！我不在乎！」", "q": 1, "tag": "◐ 硬撐的否認沒有力量——段考是真的重要。正確答案不是否認它，是給它一個位子。"}, {"t": "「那我邊打你邊用手機讀書好了。」", "q": 3, "tag": "⚠ 一心二用＝兩件都做不好。你既沒打贏牠，也沒讀進去——這正是牠最愛的「瞎忙」結局。"}]}, {"h": 2, "text": "巨塔轟然倒塌。煙塵中站著一個小小的影子——一個轉來轉去、什麼都想做、什麼都沒做完的你。 牠手裡抱著一堆閃亮的小東西，急得快哭：「可是⋯⋯可是每一件看起來都好急⋯⋯我怕漏掉⋯⋯」", "c": [{"t": "「別哭了，那些東西我幫你全部做完。」", "q": 3, "tag": "⚠ 你又跳回去當那個「全部做完」的人了——影子要的不是有人替牠瞎忙，是有人教牠分輕重。"}, {"t": "蹲下幫牠把東西放進四格：「會著火的只有這一件。」", "q": 0, "tag": "✓ 影子看著整理好的格子，第一次安靜下來。牠化作劍上第三道刻紋——你的「急」，從此有了秩序。"}, {"t": "「把那些都丟掉！全部都不重要！」", "q": 1, "tag": "◐ 牠抱得更緊了。對「怕漏掉」的自己，硬搶是沒用的——牠需要的是格子，不是命令。"}, {"t": "「唉，你就是這樣我才會這麼累。」", "q": 2, "tag": "牠就是你啊。罵牠等於罵自己——伸手幫牠整理，這一戰才算真的結束。"}]}, {"h": 3, "text": "明天就要分工確認了。你打算怎麼處理那兩位「隱形人」？", "c": [{"t": "默默把他們的部分也做完，多一事不如少一事。", "q": 3, "tag": "⚠ 「我輸你贏」的標準動作——你累死，他們學到「擺爛就有人收尾」。下次他們連名字都懶得記。"}, {"t": "開會時攤開任務表：「還剩這兩項，你們選哪個？」", "q": 0, "tag": "✓ 不翻舊帳、不貼標籤，直接給「具體的事＋明確的期限＋選擇權」。讓人動起來的，從來不是羞辱，是台階加截止日。"}, {"t": "群組開戰：「有些人是當這組有傭人是不是？」", "q": 2, "tag": "「有些人」三個字一出，對方只剩防衛和反擊兩種選項。你把隊友變成了敵人——規則吃飽了。"}, {"t": "去找老師告狀，要求把他們名字拿掉。", "q": 1, "tag": "◐ 這是「我贏你輸」——出了一口氣，但接下來三週的小組氣氛，會跟結冰的游泳池一樣。先試過直接溝通了嗎？"}]}, {"h": 3, "text": "其中一個小聲說：「我不是不做⋯⋯我是真的看不懂要做什麼。」 （哦？原來不是擺爛，是卡住。）", "c": [{"t": "「看不懂早說啊！資料卡給你，我做範例你照做。」", "q": 0, "tag": "✓ 雙贏解鎖：他從「隱形人」變「生產者」，你從「苦主」變「隊長」。多問一句的成本，換到一個隊友。"}, {"t": "「看不懂？這很難嗎？」", "q": 2, "tag": "他閉嘴了，然後永久隱形。你贏了氣勢，輸了人手——這格競技場上沒有贏家。"}, {"t": "「⋯⋯算了，我自己做比較快。」", "q": 1, "tag": "◐ 短期最快，長期最虧——你教會了全組「擺爛到底就會有人收尾」。這叫「我輸你贏」。"}, {"t": "「看不懂是你的事，自己想辦法。」", "q": 3, "tag": "⚠ 他好不容易說出真話，你一句話把門關上——隱形人從此真的隱形，你也真的得自己扛全部。"}]}, {"h": 3, "text": "投票前，有同學起鬨：「欸你們兩個 PK 啊！輸的退出！」", "c": [{"t": "默默放棄。「人緣比不過他，算了。」", "q": 2, "tag": "這叫「我輸你贏」——表面大方，心裡委屈。之後每次練球你都會有點酸，而沒人知道為什麼。"}, {"t": "先找小傑私下聊：「你想當隊長最想做什麼？」", "q": 0, "tag": "✓ 問「他要什麼」而不是急著「贏過他」——這一問才發現：他想排訓練菜單，你想指揮比賽調度。咦？"}, {"t": "「好啊，PK 就 PK！」", "q": 1, "tag": "◐ 你接受了「必有一方倒下」的劇本。就算贏了，輸的那邊帶著朋友心不甘——你拿到頭銜，丟了半支隊伍。"}, {"t": "私下說小傑壞話，讓大家別投他。", "q": 3, "tag": "⚠ 就算你選上了，這個位子是踩著抹黑爬上去的——隊伍遲早會知道，然後沒有人服你。"}]}, {"h": 3, "text": "聊完發現：他在乎「練習怎麼安排」，你在乎「比賽怎麼打」。根本是兩個職位。", "c": [{"t": "向全班提案：「他管訓練，我管比賽調度。」", "q": 0, "tag": "✓ 看台上的「規則」啞了。原來「只能有一個」是假的——把餅做大之後，兩個人都拿到更適合自己的位子。"}, {"t": "「兩個都當隊長啦，誰管什麼到時候再說。」", "q": 3, "tag": "⚠ 頭銜分了、分工沒分——比賽當天兩個隊長搶著喊調度，隊伍直接亂套。雙贏要拆需求，不是塞頭銜。"}, {"t": "「那⋯⋯猜拳決定誰當，輸的當副的。」", "q": 1, "tag": "◐ 比 PK 文明，但還是在「分一個位子」，而不是「看見兩種才能」。差一步，可惜。"}, {"t": "心想：分權功勞要分一半，還是全拿好。", "q": 2, "tag": "「功勞會變少」是獨贏的數學——牠永遠假設餅只有一塊。但球隊贏球的功勞，是用「整隊變強」算的。"}]}, {"h": 3, "text": "「快啦，好朋友欸。」他把手伸過來。", "c": [{"t": "「你怎麼不去抄別人的？煩欸。」", "q": 1, "tag": "◐ 界線守住了，但刀口太利。拒絕「這件事」不需要連「這個人」一起砍——多的那一刀，是給競技場的供品。"}, {"t": "「抄我不借。哪題卡住我現在教你。」", "q": 0, "tag": "✓ 教科書級的「勇氣＋體諒」：勇氣說不借，體諒給出路。他可能會嘖一聲——但他下次會先試著自己寫。"}, {"t": "默默把作業遞過去。（不想把氣氛弄僵）", "q": 2, "tag": "這不是「人好」，是「我輸你贏」——你付出風險，他學到「戳你就有」。下週同一時間，他還會再來。"}, {"t": "「借你，但你請我喝一週飲料。」", "q": 3, "tag": "⚠ 你把作弊變成交易，還親手定了價——被抓到兩個一起零分，這筆生意虧到底。"}]}, {"h": 3, "text": "他嘖了一聲：「小氣欸，借一下是會怎樣？」 （注意——他在把「你的界線」說成「你的缺點」。）", "c": [{"t": "有點動搖：「⋯⋯好啦，就這一次。」", "q": 2, "tag": "「就這一次」是界線崩塌的標準開場白。被一句「小氣」收買的界線，下次一句「不夠意思」就能再買一次。"}, {"t": "「被抓到兩個都零分。要教可以，抄不行。」", "q": 0, "tag": "✓ 穩。你把「我不爽」翻譯成「具體的後果」，然後重申界線。語氣不兇，立場不動——這就是溫柔而堅定。"}, {"t": "「我小氣？你才⋯⋯你哪次自己寫過！」", "q": 1, "tag": "◐ 你開始反擊人格了——而他要的就是把戰場從「借不借」搬到「你是不是小氣」。別接這個戰場。"}, {"t": "「隨便你怎麼說。」（轉頭不理）", "q": 3, "tag": "⚠ 守住了作業，卻用冷處理回敬——他記住的不是你的界線，是你的臉色。關係的帳，悄悄扣了一筆。"}]}, {"h": 3, "text": "兩派吵到面紅耳赤。身為主席，你：", "c": [{"t": "「我主席決定，就聽我的辦烤肉。」", "q": 3, "tag": "⚠ 用權力壓過討論，桌遊派整批擺爛——你贏得了拍板，輸掉了半個班的參與。"}, {"t": "各派代表輪流講「為什麼想要」，不准評論對方。", "q": 0, "tag": "✓ 高招。把麥克風從「互相攻擊」轉到「說出需求」——內容瞬間從「你們上次⋯⋯」變成「我們其實想要⋯⋯」。"}, {"t": "「吵什麼吵，投票！多數決，輸的閉嘴。」", "q": 1, "tag": "◐ 投票很快，但「51 比 49」的意思是：一半的人帶著輸的感覺參加活動。多數決分勝負，不解心結。"}, {"t": "「不然都不要辦，班費留著，公平。」", "q": 2, "tag": "這叫「雙輸」——為了不讓任何人贏，讓所有人輸。競技場最冷門但最徹底的結局。"}]}, {"h": 3, "text": "輪流發言之後，你聽出來了：烤肉派要的是「期末大家一起玩的回憶」，桌遊派要的是「平常下課有事做」。 咦——一個要「一次性的聚」，一個要「長期的用」。", "c": [{"t": "提案：「兩千辦披薩趴，一千二買桌遊」，兩邊都瘦身保留。", "q": 0, "tag": "✓ 這就是第三選擇的雛形——不是各退一步的妥協，是各自「要的本質」都被滿足。全班通過，規則暗了一半。"}, {"t": "把三千二平分兩派，各自去花各自的。", "q": 3, "tag": "⚠ 看似公平，其實兩邊的錢都不夠成事——烤肉烤不起來、桌遊買不到好的。硬分資源，常常是雙方都做不成。"}, {"t": "「上學期烤肉、下學期桌遊⋯⋯啊錢只有一份。」", "q": 1, "tag": "◐ 方向對（想兩個都顧），但卡在「分資源」而不是「拆需求」。再往下挖一層：他們要的到底是什麼？"}, {"t": "私下跟兇的那派說：「先讓他們，下次都聽你的。」", "q": 2, "tag": "檯面下交易買到的安靜，利息很高——下次他們會來討，而且加倍。"}]}, {"h": 3, "text": "開場白決定一切。你說：", "c": [{"t": "「爸，我懂你擔心睡眠跟成績——我有個提案。」", "q": 0, "tag": "✓ 先說出「對方的擔心」再亮提案——爸爸的盔甲還沒穿上就發現不用穿了。談判桌成立。"}, {"t": "「沒收就沒收，反正你最愛管我。」（擺爛）", "q": 3, "tag": "⚠ 賭氣把談判桌掀了——爸爸的「擔心」沒被處理，只會升級成「更嚴的規定」。雙輸開場。"}, {"t": "表面遵守，實際上躲在棉被裡滑。", "q": 1, "tag": "◐ 短期有效，直到被抓到那天——然後你失去的不只手機，是「談判資格」。信任破產的人，提案沒人聽。"}, {"t": "「為什麼別人都可以，就我不行？你不尊重我！」", "q": 2, "tag": "開場就控訴，對面立刻穿上盔甲。這場談判在第一句話就變成了第一層的怪罪大賽。"}]}, {"h": 3, "text": "爸爸抱著手臂：「好，你說說看。」 你的提案是：", "c": [{"t": "「平日十點半收手機，換週末到十二點，試一個月。」", "q": 0, "tag": "✓ 這提案有三個寶石：你先讓（十點半）、你要的具體（週末）、有試用期（降低他的風險）。這是設計一個兩邊都能贏的制度。"}, {"t": "「你不讓我滑，我就不讀書。」", "q": 2, "tag": "人質談判？你把自己的成績當人質——這場談判裡第一個倒下的，會是你自己。"}, {"t": "「那十一點半，各退一步嘛。」", "q": 1, "tag": "◐ 「各退一步」是妥協——你少滑半小時、他多擔心半小時，兩個人都拿到「比較不滿意」。能接受，但離雙贏還有一層。"}, {"t": "「你說了算，我都沒差。」（放棄提案）", "q": 3, "tag": "⚠ 你把方向盤整個交回去——他訂的版本你一定更不滿意，然後你會偷滑、被抓、信任歸零。不提案的人沒有雙贏。"}]}, {"h": 3, "text": "八點二十五分。妹妹的手和你的手同時伸向遙控器。", "c": [{"t": "「等等——你節目幾點到幾點？我九點才開打。」", "q": 0, "tag": "✓ 把「搶」變成「對時刻表」。情緒退場，資訊上桌——一半的家庭大戰，死於有人先拿出時間表。"}, {"t": "搶先抓住：「我比較大，我先。」", "q": 2, "tag": "你贏得了遙控器，妹妹去跟媽媽哭——三分鐘後你失去遙控器，外加一頓罵。贏一回合，輸一整局。"}, {"t": "直接拔電視插頭：「誰都別想看。」", "q": 3, "tag": "⚠ 為了不讓她贏，連自己的球賽都犧牲——標準的「雙輸」，還附贈一筆對妹妹的提款。"}, {"t": "「好啦給你看。」（憋著氣回房間，門摔有點大力）", "q": 1, "tag": "◐ 你讓了，但摔門聲出賣了你——這不是體諒，是帶著利息的委屈。這筆帳你會在奇怪的時機跟她算。"}]}, {"h": 3, "text": "對完時間：她的偶像表演在八點半到八點五十之間，你的球賽九點開打。但她想看完整集到九點半。", "c": [{"t": "「你手機這麼好，整集都用手機看啦。」", "q": 3, "tag": "⚠ 你把「分配」變成「全推給對方」——她要的就是大電視的現場感，這提案等於叫她單方面全輸。"}, {"t": "「九點前你看，九點換我，你用我手機架接著看。」", "q": 0, "tag": "✓ 她要的核心（看到偶像）完整保留，你要的核心（球賽開打）分毫未損，連配套都備好了。妹妹點頭如搗蒜。"}, {"t": "「一人一半：你看到九點十五，之後換我。」", "q": 1, "tag": "◐ 聽起來公平——但她錯過尾段，你錯過開賽十五分鐘。「公平地各損失一塊」就是妥協的長相。"}, {"t": "「猜拳，贏的全拿。」", "q": 2, "tag": "50% 機率你看不到球賽，100% 機率輸的人擺臭臉一晚上。把家人關係交給猜拳——競技場觀眾很愛看。"}]}, {"h": 3, "text": "最近三十天的明細：求載去補習（提款）、嫌她煮的菜（提款）、要錢買鞋（提款）、生日卡片（存款）、頂嘴×7（提款×7）⋯⋯ 看著這頁紅字，你：", "c": [{"t": "「她對我也有提款啊！她兇我比我頂嘴還多！」", "q": 1, "tag": "◐ 可能是真的。但你只能操作自己這一端——而且神奇的是：一方開始存，另一方的提款通常會自己變少。"}, {"t": "「帳戶歸帳戶，反正她不會真的不幫我。」", "q": 3, "tag": "⚠ 把對方的包容當成永遠不會見底的提款卡——這是帳戶從紅字走到凍結的最後一步。"}, {"t": "「她是媽媽欸，幫小孩本來就應該的吧？」", "q": 2, "tag": "「應該的」是情感帳戶的頭號殺手——它把每筆存款記成零，把每筆提款記成理所當然。帳戶就是這樣被掏空的。"}, {"t": "「⋯⋯原來我一直在提款。難怪借錢時她臉那麼臭。」", "q": 0, "tag": "✓ 看懂了。她臭臉不是「心情差」，是「餘額不足」。每次大請求能不能過，看的都是之前的存款。"}]}, {"h": 3, "text": "你決定開始存款。哪一筆「存款」最有效？", "c": [{"t": "考一次好成績給她看。", "q": 1, "tag": "◐ 有效，但這比較像「定期大額」——間隔太久。帳戶要的是「天天的小額」：一句謝謝、一次主動、一個不頂嘴。"}, {"t": "買一份貴的禮物，一次把紅字補回來。", "q": 3, "tag": "⚠ 大禮像一次性還款，帳戶結構沒變——隔天你照樣嫌菜、頂嘴，餘額立刻再次見紅。存款是習慣，不是補丁。"}, {"t": "明天起連續一週，每天大聲說一百次「我愛你」。", "q": 2, "tag": "她會帶你去看醫生。存款的匯率不看音量，看「對方在乎什麼」——先搞清楚她的幣別。"}, {"t": "觀察她最累的晚餐後，默默把碗洗了，不邀功。", "q": 0, "tag": "✓ 頂級存款：在「她在乎的點」上、用「不求回報」的方式。三天後她沒說什麼，但你開口借錢那天，利率變了。"}]}, {"h": 3, "text": "你挑了她心情不錯的週六下午（時機，學過了）。開口的第一句：", "c": [{"t": "「媽，別人家小孩零用錢都五百起跳欸。」", "q": 2, "tag": "「別人家」三個字，是大人的逆鱗——隱藏台詞是「你不如別人的媽媽」。談判在開場三秒陣亡。"}, {"t": "「不漲零用錢，我就不幫忙做家事。」", "q": 3, "tag": "⚠ 用威脅開場＝直接從帳戶提款談加薪。她記住的是你的要脅，不是你的需求。"}, {"t": "「媽，我列了每週開銷表，你看一下再聊。」", "q": 0, "tag": "✓ 拿出「開銷表」的瞬間，你從「伸手要錢的小孩」變成「帶資料來談的人」。大人對這種轉變毫無抵抗力。"}, {"t": "「我零用錢不夠。」（然後等她自己想辦法）", "q": 1, "tag": "◐ 丟出問題不附提案，等於把作業丟給對方寫——她寫出來的版本，通常不會是你喜歡的。"}]}, {"h": 3, "text": "媽媽看著開銷表，皺眉：「漲可以談。但我怎麼知道你不會亂花？」 （聽出來了嗎？這不是拒絕，是擔心。）", "c": [{"t": "「你不信我就算了，那都別給。」（賭氣）", "q": 3, "tag": "⚠ 她明明說「可以談」，你卻把「擔心」聽成「拒絕」——情緒一上來，到手的調薪自己推掉了。"}, {"t": "「我不會亂花啦！你要相信我！」", "q": 1, "tag": "◐ 「相信我」是全世界最弱的擔保品。她要的不是你的保證，是一個「就算你失控也有煞車」的機制。"}, {"t": "「吼，問那麼多，不給就算了！」（起身走人）", "q": 2, "tag": "談判桌被你自己掀了。下次再開這話題，難度乘以三——而且這次的暴走，已經從帳戶扣款。"}, {"t": "「漲到三百，我每週記帳給你看，兩個月後檢查。」", "q": 0, "tag": "✓ 你把她的擔心（亂花）變成了制度（記帳＋試用期＋退場條款）。她贏得放心，你贏得調薪——還順便學會這輩子最值錢的技能之一。"}]}, {"h": 3, "text": "「拜託啦～我會小心啦～」他拍著你的肩膀。", "c": [{"t": "「呃⋯⋯我密碼忘記了。」", "q": 1, "tag": "◐ 謊言是租來的盾牌，租金超貴——他哪天看到你登入，你失去的就不只帳號的事，是「你說的話還能不能信」。"}, {"t": "「借你，但你也把你帳號借我。」", "q": 3, "tag": "⚠ 你不想借卻拿自己更不想做的事去交換——兩個人的帳號都進了風險，這不是雙贏，是雙輸對賭。"}, {"t": "「⋯⋯好吧，但你不要亂打排位喔。」", "q": 2, "tag": "心裡是「不」，嘴巴說「好」——這個落差接下來一週天天咬你：他每次上線你都提心吊膽。這不是友情，是慢性失血。"}, {"t": "「帳號我不借，借誰都一樣。週末帶你玩分身。」", "q": 0, "tag": "✓ 清楚的「不」＋不針對他（借誰都不借）＋給一條一起玩的路。這就是傳說中的——拒絕了事情，留住了朋友。"}]}, {"h": 3, "text": "「你站哪邊？」這個問題在發光。你回：", "c": [{"t": "「你們兩個我都是朋友，我不罵任何一邊，但我可以聽你說。」", "q": 0, "tag": "✓ 拒絕門票，留下耳朵。「不站隊」不等於「不關心」——你把「選邊」換成了「陪伴」，這是唯一不輸的走法。"}, {"t": "「我當然站你啊！阿哲那樣真的很過分！」", "q": 2, "tag": "三天後他們和好了——而你罵阿哲的截圖還在。選邊站的人，常常是和好之後唯一還站在戰場上的。"}, {"t": "已讀不回。（好可怕，先躲起來）", "q": 1, "tag": "◐ 可以理解，但「已讀」在吵架敏感期會被解讀成「他不挺我」。躲過了表態，躲不過腦補。"}, {"t": "「我站對的那邊，誰有理我就挺誰。」", "q": 3, "tag": "⚠ 聽起來公正，其實還是答應了「分對錯、選一邊」——你已經坐進競技場，只是換了個冠冕堂皇的座位。"}]}, {"h": 3, "text": "小安不太滿意：「蛤～你就是覺得我有錯就對了？」 （看，不站隊也會被翻譯成站隊。）", "c": [{"t": "「好啦好啦你沒錯，他錯。」（先安撫再說）", "q": 2, "tag": "你為了三秒的安寧簽了站隊同意書。這句會被引用：「連你也覺得阿哲錯了！」——恭喜入場。"}, {"t": "「我沒說你錯。我不會在你面前罵他，就像不會在他面前罵你。」", "q": 0, "tag": "✓ 最後半句是王牌——「就像我不會在他面前罵你」。她忽然意識到：這種朋友才是安全的。風向轉了。"}, {"t": "「你很煩欸，我不想管你們的事。」", "q": 1, "tag": "◐ 想退出戰場沒錯，但這句話把「不站隊」說成了「不在乎」——她受傷的點會從阿哲轉移到你身上。"}, {"t": "「不然你們三個一起出來，我當公親。」", "q": 3, "tag": "⚠ 他們氣頭上，你硬辦調解會＝把自己架到雙方火線中間。先各自接住情緒，不是急著開庭。"}]}, {"h": 3, "text": "「八百，要不要？不要我找別人。」他說。", "c": [{"t": "「先問——你是自己要穿嗎？什麼時候要用？」", "q": 0, "tag": "✓ 談價前先問需求——你問出關鍵情報：他下下週校隊選拔要用，而且試穿你這雙剛剛好。情報就是籌碼。"}, {"t": "「⋯⋯好啦八百就八百。」（怕賣不掉）", "q": 2, "tag": "秒答應的瞬間，他反而遲疑了——「這麼快？是不是鞋有問題？」。委屈了自己，還嚇到了對方。"}, {"t": "「八百？這雙穿三次欸！一千四少一毛都不行！」", "q": 1, "tag": "◐ 立場對立場，硬碰硬——他真的轉身走了。也許會回來，也許不會。有更聰明的打開方式。"}, {"t": "「八百？乾脆我送你算了。」（賭氣反話）", "q": 3, "tag": "⚠ 用嘲諷反殺，談判桌瞬間變吵架桌——他掉頭就走，你連一塊都沒賺到。"}]}, {"h": 3, "text": "情報到手：他急著要、尺寸剛好、但預算真的只有一千上下。你：", "c": [{"t": "「一千一⋯⋯可以嗎？拜託？」", "q": 1, "tag": "◐ 價格是對的，姿態是求的。同一個數字，用「提案」說出來值一千一，用「拜託」說出來他還想再砍。"}, {"t": "「不然你開個你覺得 OK 的價。」", "q": 3, "tag": "⚠ 你手上明明握著情報（他急、尺寸剛好），卻把定價權整個讓出去——他當然往一千以下開。籌碼別白白丟掉。"}, {"t": "「你急著要喔？那一千六。」", "q": 2, "tag": "趁人之危抬價——他咬牙買了，然後跟全年級說你是黑心商人。你賺兩百，賠掉商譽，這市場你只能做一次生意。"}, {"t": "「一千一，送你原盒跟鞋帶，明天帶來給你先適應一週。」", "q": 0, "tag": "✓ 成交。你比底價多拿一百，他在預算邊緣拿到「剛好的尺寸＋立即可用＋完整配件」。兩個人都覺得賺到——這就是雙贏交易的手感。"}]}, {"h": 3, "text": "現在，橘子來了。 你跟同學同時抓住最後一顆橘子，誰都不放手。「我先拿到的！」「我比較需要！」 劍靈：「先別搶。該問什麼？」", "c": [{"t": "「一人一半，公平。」", "q": 1, "tag": "◐ 切完之後：他拿到半份皮（不夠做蜜餞），你拿到半份肉（不夠吃）。「公平的一半」常常是「雙方都不夠」的同義詞。"}, {"t": "「猜拳，輸的放手。」", "q": 2, "tag": "輸的人空手而歸，還帶著不甘。而你們到最後都不知道——其實根本不用有人空手。"}, {"t": "「你要橘子做什麼？」", "q": 0, "tag": "✓ 傳說中的那一問。一問之下——他要果皮（做蜜餞），你要果肉（吃）。一顆橘子，兩個人都拿到 100%。"}, {"t": "「誰力氣大誰拿走。」", "q": 3, "tag": "⚠ 用蠻力決定，跟競技場的「必有一方倒下」一模一樣——你又走回了第一關的老路。"}]}, {"h": 3, "text": "終極檢定：下面哪一個是「真雙贏」？其他的都是冒牌貨。", "c": [{"t": "「搞清楚彼此真正要的，找出誰都不委屈的方案，不行就不成交。」", "q": 0, "tag": "✓ 正解，一字不差。注意最後一句——「先不成交」也是雙贏家族的正式成員。"}, {"t": "「各退一步，大家都少拿一點。」", "q": 1, "tag": "◐ 這是妥協——可以接受的備案，但不是雙贏。雙贏是「都拿到要的」，妥協是「都損失得差不多」。"}, {"t": "「我要贏到底，對方認了就好。」", "q": 3, "tag": "⚠ 這是我贏你輸，獨贏古神的親兒子。對方「認了」那一刻，帳戶就開始倒數計時。"}, {"t": "「我讓他贏就好，反正我無所謂。」", "q": 2, "tag": "冒牌貨之一：我輸你贏（討好）。「無所謂」如果是假的，這筆委屈會記在帳上，利滾利。"}]}, {"h": 3, "text": "會議第一分鐘，阿凱開砲：「飲料店是要賺什麼？文青喔？」婷婷反擊：「炸物全校三攤在賣，多沒創意？」 你敲敲桌子，說：", "c": [{"t": "「先別吵。阿凱、婷婷各說最在乎什麼，不准評論對方。」", "q": 0, "tag": "✓ 你把「方案對決」降維成「需求陳列」。阿凱：「我要全校業績第一。」婷婷：「我要拍起來好看、大家記得。」——咦，這兩個衝突嗎？"}, {"t": "「你們別吵了！抽籤決定最快！」", "q": 2, "tag": "抽籤是把「沒人想思考」外包給命運。抽中哪個，另一派都會說「反正不是我選的」，然後看笑話。"}, {"t": "「投票表決，少數服從多數！」", "q": 1, "tag": "◐ 投完：炸物 17 票勝。婷婷派從此擺爛，園遊會當天一半的人「剛好有事」。你贏了會議，輸了攤位。"}, {"t": "「你們兩個有完沒完，閉嘴聽我的。」", "q": 3, "tag": "⚠ 主席用壓的，兩派的火只是轉到地下。你壓住了音量，沒壓住擺爛——當天就會原形畢露。"}]}, {"h": 3, "text": "需求上桌了：賺錢 vs 質感記憶點。這時有人嘀咕：「可是隔壁班賣雞排，炸物正面對決欸⋯⋯」 你忽然靈光一閃：", "c": [{"t": "「那我們去跟學校抗議，不准他們賣雞排！」", "q": 2, "tag": "把力氣花在消滅對手，而不是長出自己——這是獨贏古神的標準教材，恭喜你示範給全班看。"}, {"t": "「隔壁賣雞排是威脅還是情報？排雞排的人最需要什麼？」", "q": 0, "tag": "✓ 全場安靜兩秒，然後炸開：「飲料！！」——雞排攤旁邊的高質感飲料店，不是對手，是稍隊人潮的收割機。連對手都被你變成資源。"}, {"t": "「那就避開，我們也賣別的炸物，賣薯條。」", "q": 1, "tag": "◐ 閃是閃開了，但「別人的決定」還是在主導你們的企劃。差一步——能不能讓他們的雞排，反過來幫你們？"}, {"t": "「乾脆也賣雞排，跟他們拚價錢。」", "q": 3, "tag": "⚠ 正面打價格戰，兩攤一起流血。你把「對手」當成「非贏不可的敵人」，又跳回競技場了。"}]}, {"h": 3, "text": "鏡像衝過來，劍鋒直取你的肩膀！ 看台轟然嘶吼：「砍回去！砍回去！」", "c": [{"t": "格擋，大聲問鏡像：「你贏了會得到什麼？牠跟你說了嗎？」", "q": 0, "tag": "✓ 鏡像的劍停在半空。「⋯⋯得到什麼？」牠從來沒想過這個問題。看台的嘶吼，出現了一秒空白。"}, {"t": "舉劍架住，跟牠拚誰力氣大。", "q": 3, "tag": "⚠ 比力氣＝接受了「必有一方倒下」。你跟鏡像一樣強，這場拚到天荒地老，只會餵飽看台。"}, {"t": "丟下劍：「我不打了！」", "q": 1, "tag": "◐ 你不打，但規則還在——鏡像被規則驅動繼續攻擊。單方面棄劍不是和平，是挨打。要拆的是規則，不是劍。"}, {"t": "全力反擊——這次先砍倒牠再說！", "q": 2, "tag": "你的劍劈中牠的瞬間，你自己口吐鮮血跪倒。忘了嗎？牠是你——在這座場上，每一刀都是自殘。"}]}, {"h": 3, "text": "「別聽他的！」獨贏在王座上咆哮，「贏了你就是第一！第一名只有一個！蛋糕只有一塊！位子只有一個！這是世界的真理！」 牠的天平瘋狂搖晃，金色的「贏」閃閃發光。", "c": [{"t": "「對，所以我要踩著所有人變第一。」", "q": 3, "tag": "⚠ 你把牠的咒語整句吞下去了——踩著別人的第一，站得越高，身邊越空。這正是牠要的。"}, {"t": "「第一名只有一個——但『變強』沒有名額限制。」", "q": 0, "tag": "✓ 天平發出刺耳呻吟——有一種價值無法被放上「輸贏」的兩端，這是牠數學系統的致命漏洞。"}, {"t": "「蛋糕可以做大塊一點啊！」", "q": 1, "tag": "◐ 方向對了，但牠嗤笑：「做大？嘴上談兵。」——你需要更具體的證據。想想園遊會：對手的雞排攤後來變成了什麼？"}, {"t": "「真理⋯⋯好像也對，排名確實只有一個第一⋯⋯」", "q": 2, "tag": "牠笑了：「對吧對吧～」。等等——排名是真的，但「同學＝敵人」是牠偷渡的私貨。別把這兩個包裹一起簽收！"}]}, {"h": 3, "text": "「好⋯⋯好啊，」獨贏的聲音忽然轉甜，「那你們『合作』啊。來，我給你們一個機會——」 牠丟下一把金鑰匙：「出口的鑰匙，一把。你們兩個，誰拿？呵呵⋯⋯合作到這裡就破功了吧？」", "c": [{"t": "「鑰匙折斷算了，誰都別想出去。」", "q": 3, "tag": "⚠ 為了不讓牠看笑話，把唯一的出路毀了——這是雙輸，獨贏最省力的勝利。"}, {"t": "「不然我們猜拳，決定誰拿鑰匙。」", "q": 1, "tag": "◐ 公平，但你沒看穿這題——牠賭的就是你們把「一把鑰匙」當成「只能一個人出去」。先問：鑰匙跟出口，是同一件事嗎？"}, {"t": "看著鏡像：「你開門，我斷後。鑰匙給你留念——我要的是出去。」", "q": 0, "tag": "✓ 你拆開了「鑰匙」跟「出口」——又是立場與需求！鏡像接過鑰匙的瞬間，竟然笑了。天平「贏」的那端，開始生鏽。"}, {"t": "趁牠不注意，搶先撲過去奪鑰匙！", "q": 2, "tag": "你的手碰到鑰匙的瞬間，鏡像的劍也到了你的背後——古神高潮地大笑。差一點，全部重來。"}]}, {"h": 3, "text": "競技場的高牆轟然倒塌，陽光灌進來。鏡像走到你面前，伸出手—— 「欸，」牠說，「出去之後⋯⋯我們還會是對手嗎？段考、球賽、那些排名⋯⋯都還在啊。」", "c": [{"t": "握手：「會。但『對手』不是『敵人』——你變強會逼我變強。」", "q": 0, "tag": "✓ 鏡像大笑，化作光融進你的劍。對手是禮物，敵人是負債——分清楚這兩個詞的人，一輩子不缺隊友。"}, {"t": "「對手太累了，以後各走各的別往來。」", "q": 3, "tag": "⚠ 為了躲開競爭，連這個最懂你的人都推開——你拆了競技場，卻把自己關進另一座空房間。"}, {"t": "「不會，以後都別比了吧，比來比去傷感情。」", "q": 1, "tag": "◐ 鏡像搖頭：「不比，我們都會懶掉。」——雙贏不是取消競爭，是把競爭放進「一起變強」的框架裡。"}, {"t": "「出去之後，我還是非贏過你不可。」", "q": 2, "tag": "鏡像的手垂下去了。繞了一整層，別在最後一步走回競技場——再想想剛剛的四秒。"}]}, {"h": 4, "text": "他瞪著你，等你說話。你的第一句：", "c": [{"t": "「你準備了那麼久還被這樣講——超嘔的吧。」", "q": 0, "tag": "✓ 他愣了一下，肩膀垮下來：「對⋯⋯超嘔。」你沒給意見、沒給安慰，只是把他的感覺說出來——而這正是他要的。"}, {"t": "「我跟你說，我上次報告被罵更慘，那次我⋯⋯」", "q": 3, "tag": "⚠ 他才講一句，麥克風就被你搶去了——搶答古神在旁邊鼓掌。他的氣，只好自己吞回去。"}, {"t": "「沒事啦，老師就那樣，他罵每個人都很兇。」", "q": 1, "tag": "◐ 你想安慰，但「沒事啦」翻譯過來是「你的感覺不重要」。他嘴上說「也是」，心裡把門關小了一半。"}, {"t": "「你哪裡準備不足？開頭真的有點弱，下次你應該⋯⋯」", "q": 2, "tag": "他的臉垮了。他被老師打完分數，你又補了一刀——他現在要的不是第二個評審。"}]}, {"h": 4, "text": "他開始倒苦水，講到一半忽然說：「⋯⋯其實最嘔的是，我練的時候真的覺得自己這次會很好。」 （哦——核心出現了。）", "c": [{"t": "「所以最痛的不是被罵，是期待落空。」", "q": 0, "tag": "✓ 他看著你，安靜了兩秒：「⋯⋯對。就是這個。」被人精準接住的瞬間，人會自己開始好起來——你看著他眼睛裡的火氣退潮。"}, {"t": "「那下次不要期待太高就不會失望啦。」", "q": 1, "tag": "◐ 邏輯正確，溫度零下。道理在情緒還熱的時候進場，只會被當成「你根本不懂」。"}, {"t": "「期待會好是好事啊，你想太多了啦。」", "q": 3, "tag": "⚠ 他剛把最軟的那塊掏出來，你一句「想太多」把它打回去——核心剛露頭就被你封起來了。"}, {"t": "「我懂！我上次數學也覺得會考好結果爆炸⋯⋯」", "q": 2, "tag": "話題被你搶走了。他點點頭聽你講完你的故事，然後說「嗯⋯⋯我先回座位了」。搶答古神給你按讚。"}]}, {"h": 4, "text": "老師說：「你自己說，這篇是不是你寫的？」 你的開場：", "c": [{"t": "「老師，您覺得哪些段落看起來不像我寫的？」", "q": 0, "tag": "✓ 驚人的一手：被指控的人，先聽指控的內容。老師指出兩段——而那兩段你恰好能講出寫作過程。先聽，才知道要解釋哪裡。"}, {"t": "「⋯⋯隨便，你要當我抄的就抄的。」", "q": 1, "tag": "◐ 委屈到放棄溝通——可以理解，但「擺爛式投降」會讓誤會直接定案。你的作文值得你幫它辯護。"}, {"t": "「就是我寫的啊！你憑什麼說我抄！」", "q": 2, "tag": "你是冤枉的，但這句話一出，戰場從「作文是誰寫的」變成「你對老師的態度」——你瞬間從原告變被告。"}, {"t": "「你問別人啊，全班都知道我沒抄！」", "q": 3, "tag": "⚠ 你把球踢給「別人」，自己沒接住這場對話——老師要的是你的回應，不是叫她去問全班。"}]}, {"h": 4, "text": "下課時間，你決定試試。怎麼開場？", "c": [{"t": "「欸，你為什麼都不講話？大家都覺得你很難相處欸。」", "q": 2, "tag": "他的殼瞬間加厚三層。你把「大家的評論」直接砸在他臉上——這不是關心，是轉述攻擊。"}, {"t": "「你是不是有心事？跟我說沒關係，我口風很緊。」", "q": 1, "tag": "◐ 出於好意，但「挖心事」對不熟的人是壓力——他跟你還沒熟到那裡。門要讓他自己開，你只負責讓門口有光。"}, {"t": "不問問題，先從小事開始：「這題你會嗎？我卡超久。」", "q": 0, "tag": "✓ 聰明。對緊閉的殼，「請教」比「關心」溫柔——它不要求對方打開自己，只邀請他伸出一隻手。他真的探頭看了你的題目。"}, {"t": "「大家都說你很孤僻，其實你人不錯吧？」", "q": 3, "tag": "⚠ 你想幫他平反，卻先把「孤僻」這標籤又貼了一次——他聽到的只有前半句。好意，包錯了。"}]}, {"h": 4, "text": "幾次小互動之後，某天他忽然小聲說：「⋯⋯其實我之前的學校，發生了一些事。」然後就停住了，好像在試水溫。", "c": [{"t": "「發生什麼事？！誰欺負你？嚴重嗎？」", "q": 1, "tag": "◐ 你的關心是真的，但連珠炮的問題讓水溫瞬間變燙——他縮回去了：「沒事，沒什麼。」追問會關門，等待才開門。"}, {"t": "「嗯。」（點頭，安靜陪著，讓他決定要不要說下去）", "q": 0, "tag": "✓ 沉默了十秒——然後他自己繼續說了。原來如此⋯⋯他需要的從來不是「被問出來」，是「確定說了也安全」。你給了他安全。"}, {"t": "「哎呀，過去的就讓它過去！新學校新開始！」", "q": 2, "tag": "他點點頭，然後再也沒提過。你用一句正能量，把他遞出來的鑰匙拍掉了。"}, {"t": "「沒關係，你不想講就算了，我也不勉強。」", "q": 3, "tag": "⚠ 聽起來體貼，其實是把他剛探出的頭按回去——他要的不是「不勉強」的台階，是「我在，你慢慢來」的等待。"}]}, {"h": 4, "text": "阿豪講得正起勁。你：", "c": [{"t": "「阿豪你很吵欸，都你在講。」", "q": 2, "tag": "阿豪閉嘴了，臉超臭。你保護了阿芸，但用的是「打斷打斷者」——暴力沒離開教室，只是換了人使用。"}, {"t": "也跟著阿豪一起講，反正大聲的才被聽到。", "q": 3, "tag": "⚠ 你加入了搶話的行列——現在三個人在搶，阿芸更不可能開口了。你成了噪音的幫兇。"}, {"t": "算了，阿豪講的也有道理，讓他講完。", "q": 1, "tag": "◐ 這次討論順利結束了。但阿芸從此在這組只負責點頭——你們失去了一個腦袋，而且沒有人發現。"}, {"t": "「阿豪等一下——阿芸剛講到『問卷』，然後呢？」", "q": 0, "tag": "✓ 你做了兩件高級的事：擋下打斷（不羞辱人），並把麥克風還給她——還附上她剛被吞掉的關鍵字。她驚訝地抬頭，把想法說完了。而且還真的不錯。"}]}, {"h": 4, "text": "討論繼續。阿豪又開始連發，這次他講的方案明顯有個漏洞。你：", "c": [{"t": "私下跟別人說阿豪的方案爛，但當面不講。", "q": 3, "tag": "⚠ 你選了最傷團隊的路——背後說、當面不說，氣氛壞了、問題還在。聽見了就好好說，別繞到背後。"}, {"t": "馬上打斷：「不對不對，你這樣有漏洞——」", "q": 2, "tag": "你變成了阿豪。被打斷的他立刻反擊護航自己的方案——現在有兩個人在搶答，零個人在思考。"}, {"t": "漏洞先不講，反正等報告出包他自己就知道了。", "q": 1, "tag": "◐ 「讓他自己學到教訓」聽起來很酷，但報告是全組的——他出包，你陪葬。聽見問題卻不說，是另一種失職。"}, {"t": "先複誦：「你想用街訪因為快，我有聽對嗎？那下雨怎麼辦？」", "q": 0, "tag": "✓ 先讓他確定「你聽懂了」，他的防禦就卸下了——然後你的質疑聽起來不是攻擊，是幫忙。他想了想：「⋯⋯欸對，要有備案。」"}]}, {"h": 4, "text": "劍靈：「碎念是加密訊息。試著解碼——這串話的『底下』，她真正想說的是什麼？」", "c": [{"t": "「她想控制我的每一分鐘。」", "q": 1, "tag": "◐ 這是最順手的解讀，但再聽一次——「黑眼圈都出來了」——控制狂不會注意你的黑眼圈。再解一次。"}, {"t": "「她今天心情不好，拿我出氣。」", "q": 2, "tag": "有可能，但「預設惡意」是搶答古神的招式——它讓你用最壞的劇本回應，然後最壞的劇本就真的上演。"}, {"t": "「她就是愛念，沒有什麼意思啦。」", "q": 3, "tag": "⚠ 把碎念當「沒意思的噪音」，你就永遠解不開那串加密訊息——而底下那句「我擔心你」就一直沒被收到。"}, {"t": "「⋯⋯她在擔心我，只是包裝成了念。」", "q": 0, "tag": "✓ 解碼成功。大人的「念」九成是「擔心」的方言——而他們自己常常也不知道可以用別的方式說。"}]}, {"h": 4, "text": "解碼完成。現在，回應這句加密訊息：", "c": [{"t": "「知道了啦！很煩欸！」（甩門）", "q": 2, "tag": "你回應了「念」的表層，沒回應「擔心」的底層——於是擔心沒被接住，明天加倍奉還。標準的無限循環入口。"}, {"t": "「妳每次都這樣念，到底要念到什麼時候？」", "q": 3, "tag": "⚠ 你回擊的是「念」這個形式，完全沒碰到底層的擔心——她只會把音量再調高，證明自己「不得不念」。"}, {"t": "「媽，妳擔心我考試跟睡眠齁？功課寫完了，十分鐘就睡。」", "q": 0, "tag": "✓ 你直接回覆了「底層訊息」。媽媽愣住三秒——她的擔心第一次被聽見，碎念引擎熄火了。她居然只說了「⋯⋯好，快睡」就關門了。"}, {"t": "「嗯。」（繼續滑，等她念完自動離開）", "q": 1, "tag": "◐ 已讀模式。今晚是混過去了，但她的擔心持續未接聽——未接來電會累積，然後在某天變成奪命連環 call。"}]}, {"h": 4, "text": "爸爸難得開口講了幾句工作的烏煙瘴氣。講完，餐桌的空氣回暖了。 那⋯⋯週末要錢的事，什麼時候提？", "c": [{"t": "就是現在！「爸，那個，我週末要五百塊。」", "q": 1, "tag": "◐ 唔——時機比早上好，但「剛倒完苦水就被開口要錢」，會讓剛剛的陪伴瞬間變得很像鋪陳。再等等，明天更好。"}, {"t": "今天不提，明天早餐他狀態好時再說。", "q": 0, "tag": "✓ 對。「知彼」也包含「知道現在不是時候」。隔天你一開口，他爽快地答應了——昨晚那碗湯，他記得。"}, {"t": "心想反正他現在心軟，多要一點順便。", "q": 3, "tag": "⚠ 你把他剛吐露的脆弱當成「下手的好時機」——這是把陪伴變算計。被看穿那天，這碗湯就白添了。"}, {"t": "趁他心情回暖，把要錢包裝在超長的活動介紹裡。", "q": 2, "tag": "他聽到一半就皺眉：「所以你要多少？」——大人對「鋪陳超長的請求」有雷達。有事直說，比話術乾淨。"}]}, {"h": 4, "text": "妹妹哭著說：「她們今天午餐故意把位子坐滿，不讓我坐⋯⋯」 你的回應：", "c": [{"t": "「妳一定也有講錯什麼話，先想想自己。」", "q": 3, "tag": "⚠ 她剛被排擠，你又把矛頭轉回她身上——她要的是一個站她這邊的人，不是第二個審判她的人。"}, {"t": "「不理就不理啊，這種朋友不要也罷！」", "q": 1, "tag": "◐ 邏輯上也許對，但對一個小六生，「最好的朋友」就是她的半個世界——你一句「不要也罷」，等於叫她別為半個世界難過。"}, {"t": "「太過分了吧！明天我去你們班找她們算帳！」", "q": 2, "tag": "妹妹嚇得停止哭泣：「不要不要！你去了我更慘！」——你的怒火是替她燒的，但火一大，她反而要回頭來滅你的火。"}, {"t": "「被最好的朋友這樣⋯⋯一定超難過的吧。」遞面紙。", "q": 0, "tag": "✓ 她哭得更大聲——然後漸漸停了。情緒就像浪，被接住的浪會自己退；被堵住的浪，才會變成海嘯。"}]}, {"h": 4, "text": "開口前的準備。你先做什麼？", "c": [{"t": "先想：他們轉移話題時臉上的表情，是在「怕」什麼？", "q": 0, "tag": "✓ 你回想起來了——每次都是「你會不會整天拿來打電動」的眼神。原來他們不是反對筆電，是怕筆電的「用途」。情報到手，戰術全變。"}, {"t": "先上網找哪台筆電最便宜，價錢備好再說。", "q": 3, "tag": "⚠ 你準備的是「規格」，他們卡的是「擔心」——答非所問。價錢再漂亮，也接不住他們真正的那個「怕」。"}, {"t": "直接開口，看他們說什麼再見招拆招。", "q": 2, "tag": "「見招拆招」在沒準備的人身上，叫「被招拆」。他們一句「再說吧」，你就回房間了——跟過去八次一樣。"}, {"t": "準備一份「為什麼我需要筆電」的清單，列十二點背起來。", "q": 1, "tag": "◐ 你準備了「解己」的部分——很完整。但等等，他們轉移話題的原因，你知道了嗎？不知道敵情的進攻，再華麗都是亂槍。"}]}, {"h": 4, "text": "他在電話那頭斷斷續續地講，有時候哭，有時候罵，有時候沉默很久。 沉默的時候，你：", "c": [{"t": "「好啦不要難過了，那種人不值得！下一個更好！」", "q": 2, "tag": "「不要難過」＝叫一個流血的人「不要流血」。他喜歡了一年的人，值不值得，輪不到此刻的你來判。"}, {"t": "「喂？還在嗎？怎麼都不講話，講話啊。」", "q": 3, "tag": "⚠ 你把他正在療傷的沉默，當成「斷線」來催——沉默不是冷場，是他需要的空間。別急著填滿。"}, {"t": "陪著沉默，偶爾「嗯」一聲，讓他知道你還在。", "q": 0, "tag": "✓ 電話兩頭安靜了一分鐘——然後他說：「⋯⋯謝謝你沒有叫我想開一點。」陪伴的最高級形式，有時候是「在場的安靜」。"}, {"t": "急著填滿沉默：「你還好嗎？不要想太多！我講笑話給你聽？」", "q": 1, "tag": "◐ 沉默讓你慌了——但那個沉默是他的，不是你的。他正在裡面整理東西，你一打岔，他又得重新開始。"}]}, {"h": 4, "text": "他講到後來，忽然說：「我是不是很沒用？人家都說國中生的感情不算什麼⋯⋯可是我真的好痛。」", "c": [{"t": "「誰說不算？你認真喜歡了一年——痛，就代表是真的。」", "q": 0, "tag": "✓ 電話那頭哭聲炸開——然後是長長的、鬆掉的呼吸。你做的事叫「幫他的痛苦取得合法資格」。被允許痛的人，才能開始好。"}, {"t": "「別哭了啦，男生（女生）哭成這樣不好看。」", "q": 3, "tag": "⚠ 他最痛的時候，你管的是「哭的樣子」——這句話只會讓他把眼淚和真心一起收起來。你關掉了他唯一的出口。"}, {"t": "「你不會沒用啦！你超好的！是他不會看人！」", "q": 1, "tag": "◐ 護主心切，可愛。但連續罵對方會讓他更亂——他可能還愛著那個人，你每罵一句，他就得在「你」跟「回憶」之間選邊。"}, {"t": "「國中生的感情喔⋯⋯說真的還好啦，以後就覺得很小。」", "q": 2, "tag": "「以後回頭看」也許是真的——但對正在痛的人，這句話的意思是「你的現在不重要」。他輕輕地說「嗯，也是」，然後把心關起來了。"}]}, {"h": 4, "text": "「反正也讀不贏人家。」他又踢了一腳石頭。 你的第一手：", "c": [{"t": "「你三次了齁⋯⋯一直追一直追不到，是會累的。」", "q": 0, "tag": "✓ 他停下腳步看你：「⋯⋯對。我真的好累。」——你沒有反駁「不想讀」，你接住了它底下的「好累」。對話的門，開了。"}, {"t": "「讀不贏就讀不贏啊，幹嘛非要贏人家？」", "q": 3, "tag": "⚠ 你忙著糾正他的觀念，沒聽見他話裡的累——道理也許對，但他要的是被懂，不是被指正。"}, {"t": "「不讀是要幹嘛？你爸媽會殺了你欸。」", "q": 2, "tag": "他本來想講心裡話，你用「現實恐嚇」把門撞上了。他聳聳肩：「開玩笑的啦。」——但你知道不是。"}, {"t": "「不要這樣想啦！你只是還沒找到方法！一起加油！」", "q": 1, "tag": "◐ 正能量灑下去，他笑了笑說「嗯，好啊」——然後話題結束了。加油打氣沒有錯，只是太快了：傷口還沒被看過，就被貼了OK繃。"}]}, {"h": 4, "text": "0 個人回應的限動。你：", "c": [{"t": "私訊：「我看到了，我在。要聊聊嗎？不聊也沒關係。」", "q": 0, "tag": "✓ 兩分鐘後，她回了一個哭的貼圖，然後是長長的一段話。那則限動是一個瓶中信——47 個人看過，你是唯一打開的。"}, {"t": "「唉，深夜 emo 文而已，明天就好了。」滑過去。", "q": 2, "tag": "也許真的只是 emo。但「如果我消失了」這種句子，賭不起「也許」。寧可多看一眼，不要事後回想這一眼。"}, {"t": "截圖傳到別的群組問大家：「她怎麼了？」", "q": 3, "tag": "⚠ 你把她最脆弱的求救，變成了群組八卦——她要的是被一個人接住，不是被一群人圍觀。"}, {"t": "按一個「哭哭」的表情回應，表示我看到了。", "q": 1, "tag": "◐ 比沉默好一點。但深夜發那種話的人，需要的是「一個人」，不是「一個表情符號」。多打一行字的勇氣，可能就是今晚的差別。"}]}, {"h": 4, "text": "她跟你聊了很多——家裡的事、班上被排擠的感覺。最後她說：「不要跟別人講喔，連老師也不要。」 但有幾句話讓你不放心——她講到「不想活」的念頭不只一次。", "c": [{"t": "嚇到了，已讀，慢慢減少回覆，假裝忙。", "q": 1, "tag": "◐ 會怕很正常——這本來就不是你該獨自扛的。但「淡出」會讓她確認「果然沒有人」。把不安帶去找大人，這不是背叛，是求援。"}, {"t": "「妳想太多了啦，不會有事的，早點睡。」", "q": 3, "tag": "⚠ 她講了「不想活」，你用「想太多」帶過——這不是安慰，是把紅燈關掉假裝沒看到。該升級，不是安撫。"}, {"t": "「妳的事我不八卦。但『不想活』我接不住——我得找輔導老師。」", "q": 0, "tag": "✓ 這是這整層最難的一題：「保密」與「保命」衝突的時候，保命贏。真正的傾聽不是當樹洞到底——是知道什麼時候，該牽著她去找更有力的手。"}, {"t": "答應她：「好，我誰都不說。」——畢竟都答應人家了嘛。", "q": 2, "tag": "你的義氣是真的，但這個秘密超重，重到不該由兩個國中生獨自扛。有些承諾，愛她的方式恰恰是不遵守它。"}]}, {"h": 4, "text": "終極題：同理聽的正確發動方式是——", "c": [{"t": "聽的時候想著「我等下要給什麼建議」，聽完馬上給。", "q": 2, "tag": "這是「裝填式傾聽」——本層第 1 關就教過：邊聽邊上膛，就是噪音的原料。"}, {"t": "先聽完，複誦對方的意思＋接住感受，再問「需要意見嗎？」", "q": 0, "tag": "✓ 滿分。最後那一問是隱藏王牌——有時候人家只要被聽，不要被修理。問了才知道。"}, {"t": "對方講什麼，你都先回一句「我懂我懂」就對了。", "q": 1, "tag": "◐ 「我懂」說太快反而可疑——你都還沒複誦過，懂從哪來的？「懂」是要被驗證的，不是宣告的。"}, {"t": "默默聽完，什麼都不回應，讓他自己消化。", "q": 3, "tag": "⚠ 全程零回應，對方會覺得「他根本沒在聽吧」。同理聽不是當塊石頭——要讓對方知道，你接到了。"}]}, {"h": 4, "text": "第一層。他邊投籃邊說：「學校超煩的。老師都嘛只會管人，講什麼都被罵。」", "c": [{"t": "「最近確實看你一直被釘⋯⋯你以前不太這樣，發生什麼事了嗎？」", "q": 0, "tag": "✓ 你沒有評論「嗆老師對不對」，你指出了「你變了」這個觀察——他運球的手停了一下。第一道鎖，開了。"}, {"t": "「對啊老師超煩！尤其那個誰，我也看他不爽！」", "q": 2, "tag": "一起罵很爽，但你把他的「訊號彈」當成「同樂會」——他要說的不是老師的事，現在說不出口了。"}, {"t": "「老師管人也是為你好啦，你別太計較。」", "q": 3, "tag": "⚠ 他才剛開口，你就站到老師那邊勸他——他要的是被聽，不是被勸。門「啪」一聲關緊了。"}, {"t": "「你也真的比較衝啦，上次那樣嗆是有點過。」", "q": 1, "tag": "◐ 你說的是事實，但太快了——他剛把門打開一條縫，你塞了一張評分表進去。門又關回去一半。"}]}, {"h": 4, "text": "第二層。他沉默地投了幾球，忽然說：「⋯⋯我爸最近都不回家。我媽每天哭。」 （來了。真正的事。）", "c": [{"t": "「蛤？！他們要離婚喔？那你怎麼辦？你會跟誰？」", "q": 2, "tag": "連珠炮的問題像記者會——他還在流血，你在採訪。他把球抱緊：「不知道啦。」門快關上了。"}, {"t": "「家家有本難念的經啦⋯⋯大人的事讓大人處理。」", "q": 1, "tag": "◐ 想幫他「放下」，但他根本還沒「放上」過——這句話讓他剛遞出來的重量，懸在半空中沒人接。"}, {"t": "停下撿球的手，走到他旁邊：「⋯⋯這件事，你自己扛多久了？」", "q": 0, "tag": "✓ 他看著籃框很久，說：「兩個月。」眼眶紅了。「你扛多久了」這五個字的意思是：我看見的不是你的家事，是你這個人。第二道鎖，開了。"}, {"t": "「真假？那你家是不是要搬走？你會轉學嗎？」", "q": 3, "tag": "⚠ 你的好奇蓋過了他的痛——他講的是「我媽每天哭」，你關心的卻是「會不會轉學」。他要的不是被打聽。"}]}, {"h": 4, "text": "牠搶先開砲，音浪幾乎掀翻你：「你那些什麼傾聽！沒用的！這世界誰大聲誰贏！誰先講誰贏！你說是不是！是不是！！」 （牠在等你反駁——反駁就是餵食。）", "c": [{"t": "大聲反駁回去：「才不是！傾聽才是最強的武器！」", "q": 2, "tag": "牠狂喜地咆哮：「來了來了！辯論來了！」你們對吼的每一句，都讓牠膨脹一圈。這是牠的主場——退出來！"}, {"t": "搗住耳朵，鼓起勇氣硬衝過去砍牠！", "q": 1, "tag": "◐ 音浪把你掀飛出去。第 1 關就試過了——在這一層，劍跟吼叫都會被彈回來。武器是耳朵。"}, {"t": "比牠更大聲地吼回去，壓過牠的音量！", "q": 3, "tag": "⚠ 你選了牠最擅長的戰場——比大聲。牠笑了：「對嘛！這才像話！」你越吼，牠長得越高。"}, {"t": "不反駁。等牠喊完，平靜複誦：「你說，誰大聲誰贏。」", "q": 0, "tag": "✓ 巨嘴僵住了。牠吼了一萬年，第一次有人「複誦」牠的話——而不是搶著回嘴。風暴的轉速，慢了下來。"}]}, {"h": 4, "text": "巨嘴的轉速越來越慢。牠忽然用很小、很小的聲音說： 「⋯⋯如果我不先講話，就不會有人理我。如果我不大聲，我說的話就會不見。」 （核心，浮出來了。）", "c": [{"t": "「不會啊，你很大聲，大家都注意到你了。」", "q": 2, "tag": "牠苦笑：「注意到⋯⋯然後呢？有人聽過嗎？」——被注意跟被聽見，是兩回事。你安慰錯了地方。"}, {"t": "「那你不要搶不就好了，很簡單啊。」", "q": 3, "tag": "⚠ 牠怕的是「不搶就消失」，你卻丟給牠一句「別搶就好」——等於叫一個怕黑的人「把燈關了就好」。沒接到核心。"}, {"t": "「所以你才一直搶——因為你怕安靜下來，就等於消失。」", "q": 0, "tag": "✓ 整層深淵，瞬間，完全，安靜。一萬年來的第一次。巨嘴的輪廓開始溶解——牠說的每句搶話，原來都是同一句話：「看看我。」而你看見了。"}, {"t": "「原來你也有自卑的一面喔。」", "q": 1, "tag": "◐ 你聽到了，但你把它「標籤化」了——「自卑」兩個字像釘子，把活的感受釘成了標本。牠縮了一下。換成「接住」的說法再試一次。"}]}, {"h": 4, "text": "最後，影子問了一個問題： 「⋯⋯那以後，如果我想說的話，跟想聽的心打架怎麼辦？兩個都是我啊。」", "c": [{"t": "「順序而已。先聽，聽懂再說——你會發現你的話反而更有人聽。」", "q": 0, "tag": "✓ 影子笑了。「先聽，再說。」牠複誦了一次——這次不是搶答，是真的收到了。第五層，完全通關。"}, {"t": "「打架就讓它打架啊，看最後哪一邊會贏。」", "q": 2, "tag": "內戰沒有贏家——這題其實這一層已經給過答案了。提示：是個順序問題。"}, {"t": "「以後都不要說了，只要安安靜靜地聽就好。」", "q": 1, "tag": "◐ 影子歪頭：「那我不就又消失了？」——對，知彼「解己」，後半段是要把自己說清楚的。傾聽不是閉嘴的刑罰，是說話的入場券。"}, {"t": "「就哪一邊聲音比較大，你就聽哪一邊啊。」", "q": 3, "tag": "⚠ 你又用回「大聲決定一切」的舊邏輯——那正是搶答古神的咒語。答案不是比大聲，是排順序。"}]}, {"h": 5, "text": "戰況膠著。你深吸一口氣，決定換個走法：", "c": [{"t": "「你們吵你們的，我先把簡報做完。」", "q": 3, "tag": "⚠ 你直接退出討論自己幹——這是把「整合」換成「我做我的」。阿樂的點子、全組的腦力，全被你一個人的進度條輾過去了。"}, {"t": "「影片太花時間了啦，聽我的準沒錯。」", "q": 2, "tag": "你用「經驗」碾壓了「熱情」。報告如期完成，四平八穩，老師的評語是：「中規中矩。」——灰霧的最愛。"}, {"t": "「別吵了，直接投票，少數服從多數。」", "q": 1, "tag": "◐ 簡報派 3:2 獲勝。阿樂從此在小組裡只出一張嘴。投票切的是輸贏，不是問題——而且把最有創意的那個人，切到了輸的那邊。"}, {"t": "「先暫停。阿樂，你最想要影片帶來的『什麼』？我先聽。」", "q": 0, "tag": "✓ 第五層的耳朵上場了。阿樂想了想：「⋯⋯我要的是大家看到開頭就『哇』出來。」哦——他要的不是影片，是「開場的驚豔」。"}]}, {"h": 5, "text": "需求出土：「第一眼高級」＋「有我們的故事」。第三案徵集中——", "c": [{"t": "「兩種風格各做一塊板子，到時候誰好看用誰。」", "q": 3, "tag": "⚠ 你把「合作」改成「淘汰賽」——做輸的那派整週白忙，還結下樑子。綜效是合鑄，不是PK。"}, {"t": "「極簡為主，照片印小小的貼角落點綴。」", "q": 1, "tag": "◐ 回憶派勉強點頭，但心裡知道自己是「點綴」。能用，能交差——但那個「都沒想到的更好」，擦肩而過了。"}, {"t": "「照片牆為主啦，人多的那派贏。」", "q": 2, "tag": "人數=正義？質感派整個佈置週「剛好都很忙」。你用多數決省了十分鐘討論，賠上了一半的人力。"}, {"t": "「黑白灰幾何框架當底，框格裡放全班照片『轉黑白』再印。」", "q": 0, "tag": "✓ 兩派同時安靜了三秒，然後同時炸出「可以欸！！」。黑白照片配極簡框架——比任何一派的原案都高級，也比任何一派的原案都動人。這就是 1+1>2 的長相。"}]}, {"h": 5, "text": "第一次討論，他果然遲到十分鐘，還邊滑手機邊聽。你：", "c": [{"t": "先訂規矩：「醜話說前面，你再擺爛我就跟老師拆組。」", "q": 1, "tag": "◐ 界線是該有的（第四層教的），但「開場就亮刀」會讓他整個專題都在防你。刀可以有，先別出鞘——先找找他的顏色。"}, {"t": "壓住白眼，先丟個問題：「這主題你有沒有哪部分其實有興趣？」", "q": 0, "tag": "✓ 他抬起頭：「⋯⋯訪談那部分吧。我蠻會跟人聊天的。」——欸？你最害怕的就是訪談陌生人。這個你最不對盤的人，剛好長在你的短板上。"}, {"t": "回他一句「你遲到欸」，然後全程臭臉開會。", "q": 3, "tag": "⚠ 你用臭臉開了場，他用敷衍回敬——兩週都在比誰更不爽。連他會不會訪談，你都沒機會發現。"}, {"t": "「果然。」把全部工作攬下：「算了我做就好，你掛名。」", "q": 2, "tag": "灰霧的耳語你全文照辦了。你接下來兩週爆肝，他全程納涼——而且你永遠不會知道：這個人身上有沒有你沒有的東西。"}]}, {"h": 5, "text": "爸爸開始講「全家就是要一起活動」，媽媽開始講「每次都聽你的」，戰雲密布。你：", "c": [{"t": "「我都可以啦。」（其實只想回家）", "q": 2, "tag": "「都可以」是同化古神的母語。全家去爬了山，你全程臭臉，爸爸問「帶你出來還不開心？」——都可以的代價，是沒有人開心。"}, {"t": "「你們去你們的，我留家裡，互不相欠。」", "q": 1, "tag": "◐ 可行，有時候分開行動是對的。但「每次都這樣」的話，全家會慢慢變成住同一間房子的室友。今天先試試別的解法？"}, {"t": "「等等——先各自講『那個行程裡你最想要的部分』。爸先說？」", "q": 0, "tag": "✓ 十四歲的你主持了家庭會議，爸媽都愣了。答案出土：爸要「流汗＋全家一起」，媽要「買到那雙鞋＋順便吃好的」，你要「下午有自己的耍廢時間」。"}, {"t": "「吵什麼吵，丟銅板決定啦，省得煩。」", "q": 3, "tag": "⚠ 丟銅板＝放棄思考。三個願望被一枚銅板決定，無論落哪面，都有兩個人整天不開心。先把需求攤開再說。"}]}, {"h": 5, "text": "「可點擊地圖」上線測試，效果驚人。但新問題來了：美術擔當小米說地圖醜，想全部重畫；阿光說重畫要重切座標，工程翻倍。兩個專業，對撞。", "c": [{"t": "「小米最想改哪三處？阿光哪種改法不重切座標？找雙方交集。」", "q": 0, "tag": "✓ 二十分鐘後他們回報：換配色＋重畫圖示（不動底圖）＝視覺升級 80%，工程量 10%。兩個專業對撞的火花，不是災難——是免費的能量，只要有人幫他們搭橋。"}, {"t": "「你們兩個各做一版，最後挑好的那版。」", "q": 3, "tag": "⚠ 你把「對齊」變成「淘汰賽」——做輸的那個白做，還傷感情。兩個專業是要合鑄成一把劍，不是互相比刀。"}, {"t": "「不要改了啦，能動就好，先交出去再說。」", "q": 2, "tag": "「能動就好」是灰霧的口頭禪。網頁能動，也僅止於能動——兩個專業者的火花，被你一句話澆熄了。"}, {"t": "「美觀最重要，這次小米說了算，阿光配合。」", "q": 1, "tag": "◐ 單邊裁決——地圖變美了，阿光重切座標切到半夜，從此再也不提新點子。你贏了這頁網頁，輸了下一個點子。"}]}, {"h": 5, "text": "最後一題，誠實之問：如果流程都跑完了，第三選擇還是生不出來——怎麼辦？", "c": [{"t": "「沒綜效就隨便挑一個用，反正都差不多。」", "q": 3, "tag": "⚠ 「隨便挑、都差不多」是同化的語氣——你把好不容易攤開的需求又一鍵掃進垃圾桶了。沒綜效也要好好挑，不是亂挑。"}, {"t": "「繼續開會！今天不散會，開到生出來為止！」", "q": 2, "tag": "凌晨兩點的會議室裡不會有綜效，只有想回家的人質。硬擠出來的「共識」，明天就會被推翻。"}, {"t": "「承認這次沒有——退回雙贏備案：好的妥協，或好好地不成交。」", "q": 0, "tag": "✓ 滿分。這是綜效大師跟綜效狂熱者的差別：大師知道它不是百發百中。誠實面對「這次沒有」，比硬掰一個假綜效高級得多。"}, {"t": "「那就回到投票，少數服從多數決吧。」", "q": 1, "tag": "◐ 可以——但記得第 11 關的教訓：宣布投票前，最後再問一次「兩邊要的到底是什麼」。很多死局在這最後一問才解開。"}]}, {"h": 6, "text": "眼皮 vs 影片。你：", "c": [{"t": "看影片。「笑一笑也是休息啊。」", "q": 1, "tag": "◐ 半小時後：影片看了八支，眼睛更酸，腦袋更脹。「好笑」跟「休息」是兩回事——前者是刺激，後者是修復。你下午會用瞌睡付這筆帳。"}, {"t": "「先撐著，撐到放學回家再一次睡飽。」", "q": 3, "tag": "⚠ 下午四節課用一顆鉛腦撐——上課全滑過去，等於沒上。眼前二十五分鐘不睡，賠掉的是整個下午的吸收率。"}, {"t": "「考完再傳我！」趴下，設好二十五分鐘的鬧鐘。", "q": 0, "tag": "✓ 二十五分鐘的午睡是合法外掛——下午的你像換了一顆腦袋。紅泉的最低消費，回報率全宇宙最高。"}, {"t": "「不能睡，把握時間複習數學！」硬撐著翻講義。", "q": 2, "tag": "你用 30% 電量的腦袋讀了半小時——讀進去的東西趨近於零，第八節考試時電量歸零。「拿休息時間讀書」常常是最虧的交易。"}]}, {"h": 6, "text": "劍靈追問：「昨晚十二點半睡——是作業真的多到那個時間,還是⋯⋯？」", "c": [{"t": "「⋯⋯九點半就寫完了。後面三小時在滑手機。」", "q": 0, "tag": "✓ 誠實。這現象有個名字叫「報復性熬夜」——白天被安排滿了，夜裡捨不得放掉唯一的自由。但你用「明天的電量」買「今晚的自由」，利息是兩倍。"}, {"t": "「晚睡才有效率啊，夜深人靜讀得進去。」", "q": 3, "tag": "⚠ 「夜深人靜效率高」是熬夜者的安慰劑——你犧牲的睡眠，隔天會用兩倍的恍神討回來。深夜讀的，白天大半留不住。"}, {"t": "「作業真的就是寫到十二點半啊。」", "q": 1, "tag": "◐ 如果是真的，那問題在第三層（要事第一）——回想一下：傍晚那三小時，雜兵有沒有來過？"}, {"t": "「熬夜怎麼了嗎？大家不都這樣？」", "q": 2, "tag": "「大家都這樣」不會讓你的黑眼圈變淡。國中生需要 8 到 10 小時的睡眠——這不是建議，是你大腦的硬體規格。"}]}, {"h": 6, "text": "腦袋當機中。但下一節是重要的理化課。你：", "c": [{"t": "「撐住！把筆記抄好，回家再消化！」", "q": 1, "tag": "◐ 你抄了滿滿三頁筆記——晚上翻開，完全想不起來上課在講什麼。抄寫不等於吸收；當機的腦袋，抄的是字，不是知識。"}, {"t": "下課繼續趕別科作業，能省一點是一點。", "q": 2, "tag": "你把唯一的散熱時間也拿去運轉了。週五，陀螺出現了異音：你對著一題簡單的數學，莫名其妙地想哭。那是過熱警報。"}, {"t": "趴著硬睡兩分鐘，被鐘聲驚醒更暈。", "q": 3, "tag": "⚠ 兩分鐘的硬睡來不及進入修復，只會打斷你本來就稀薄的精神——醒來更鈍。要嘛睡滿二十分鐘，要嘛起來走動，別卡在中間。"}, {"t": "下課離開座位、走廊看遠方、深呼吸、裝杯水，什麼都不想。", "q": 0, "tag": "✓ 就這麼簡單的十分鐘，理化課你居然聽懂了。腦袋跟肌肉一樣——不是操越久越強，是「收縮跟放鬆交替」才會強。"}]}, {"h": 6, "text": "週五晚上，整週的疲勞滾成一顆雪球。明天是週六。你打算：", "c": [{"t": "睡到自然醒＋下午打球＋晚上看自己想看的小說。", "q": 0, "tag": "✓ 週日早上的你，電量錶亮回 90%——而且寫作業的速度是平常的 1.5 倍。「主動的休息」跟「癱著的休息」，充電效率差了五倍。"}, {"t": "「先補半天眠，剩下半天排滿讀書當補償。」", "q": 3, "tag": "⚠ 半天睡、半天罰自己讀書——身體剛回一點血又被榨乾。週六的設計目標是「滿血迎接下週」，不是「贖罪」。"}, {"t": "「終於可以耍廢了——躺床滑手機十二小時！」", "q": 1, "tag": "◐ 週六晚上你檢查電量：躺了一整天，卻好像更累？因為滑手機是「低耗電待機」不是「充電」——身體沒動、腦袋沒停、心情沒亮。四座泉，一座都沒泡到。"}, {"t": "「不行，週六要排滿讀書，下週還有考試。」", "q": 2, "tag": "你看著書，書看著你，一天「假讀」了十小時，吸收兩成。連續運轉十三天的陀螺不會變勤勞——只會變鈍。"}]}, {"h": 6, "text": "空窗第三天。明天開始發考卷、上新進度。今晚你：", "c": [{"t": "「最後一夜！熬到三點才對得起假期！」", "q": 2, "tag": "你用假期的最後一夜，預支了開學第一週的電——隔天的你頂著時差上課，新進度的第一章直接糊掉。最後的瘋狂，最貴。"}, {"t": "十一點前睡，把生理時鐘調回上學模式。", "q": 0, "tag": "✓ 收假的前一晚早睡，是給明天的自己最好的禮物。隔天全班都在當殭屍的時候，你是教室裡唯一的活人。"}, {"t": "開始焦慮明天發考卷，越想越睡不著。", "q": 1, "tag": "◐ 考卷已經寫完了——分數此刻在關注圈（第一層教的）。今晚能做的只有一件在影響圈的事：睡飽，讓明天的自己有力氣面對任何分數。"}, {"t": "再多放縱一晚，反正明天才收心。", "q": 3, "tag": "⚠ 「明天才收心」的意思是：明天頂著爛狀態上學。收假前一晚的早睡，效益是整個第一週——這一晚別賣掉。"}]}, {"h": 6, "text": "第五次「看完這個就睡」。你忽然意識到一件事——你其實不快樂，只是停不下來。", "c": [{"t": "「再十分鐘，湊整數一點半。」", "q": 2, "tag": "一點半變兩點十分。「湊整數」是拖延的萬能藉口——時間永遠有下一個整數。"}, {"t": "「反正都這麼晚了，乾脆滑到天亮。」", "q": 3, "tag": "⚠ 用「已經很晚」當理由把整夜賠進去——這是熬夜的最後一道滑坡。一點半睡跟天亮睡，明天差的是一整顆腦袋。"}, {"t": "「都怪演算法太強，我也沒辦法。」", "q": 1, "tag": "◐ 演算法確實強——但「我也沒辦法」是第一層的絲線喔。演算法在關注圈，「手機放哪裡充電」在影響圈。"}, {"t": "記下這瞬間：「滑不停跟開心是兩回事。」手機放書桌，回床。", "q": 0, "tag": "✓ 你抓到了短影音的商業機密：它的設計目標不是「讓你快樂」，是「讓你無法離開」。看穿這個的人，才有得選。"}]}, {"h": 6, "text": "隔天，你決定動手術。哪一招對「凌晨的螢幕」最有效？", "c": [{"t": "立規則：手機十一點後放客廳充電——物理隔離，不靠意志力。", "q": 0, "tag": "✓ 對。凌晨一點的你是全天意志力最弱的你——別派他上戰場。讓「拿手機」變成要下床走十步的事，戰爭在開打前就結束了。"}, {"t": "下載「自律 App」，設定使用時間提醒。", "q": 1, "tag": "◐ 有幫助，但提醒跳出來的時候，按掉它的還是凌晨一點的你——那個最不可靠的傢伙。軟體防線不如物理防線。"}, {"t": "「今天起我要靠意志力！我發誓！」", "q": 2, "tag": "這個誓言的平均壽命是兩天——第 1 關荒原上的勇者們都發過。環境設計贏過意志力，這一層的鐵律。"}, {"t": "把螢幕調暗一點，這樣比較不傷眼也比較好睡。", "q": 3, "tag": "⚠ 調暗只是讓你滑得更舒服、更久——問題不是亮度，是「手機在手上」。動的是位置，不是亮度。"}]}, {"h": 6, "text": "第三次拿起那本書。你想起劍靈說過「藍泉是『自己選的學習』」——", "c": [{"t": "「看這個又不會考，浪費錢浪費時間。」", "q": 2, "tag": "「會不會考」是學校的計分板，不是大腦的。只用「考不考」餵大的腦袋，畢業那天就會停止進食——而那才是真正的浪費。"}, {"t": "買。這是我自己選的——自選的知識吸收率是被逼的三倍。", "q": 0, "tag": "✓ 你抱著書回家，三天讀完——比任何一本課本都快。藍泉的秘密：大腦不討厭學習，大腦討厭「被指定」。自選的學習是充電，被塞的學習才耗電。"}, {"t": "「先拍幾頁回家看就好，幹嘛花錢。」", "q": 3, "tag": "⚠ 拍幾頁回家，那股「翻了半小時停不下來」的興致，到家就涼了——藍泉怕的不是花錢，是把「眼睛發光的當下」一拖再拖。"}, {"t": "放回去。「先衝段考，考完再買。」", "q": 1, "tag": "◐ 聽起來自律——但「考完」之後還有下一個考。給你一個折衷案：買回去，規定自己「只能當讀書的中場休息看」。它會從誘惑變成獎勵。"}]}, {"h": 6, "text": "低氣壓中的你，第一個動作：", "c": [{"t": "打開手機，用短影音把這種感覺蓋過去。", "q": 1, "tag": "◐ 蓋是蓋掉了——兩小時後手機一放，低氣壓原封不動地在那裡等你，還加贈「浪費了一晚」的懊悔。麻痺不是充電，是欠帳。"}, {"t": "找人吵一架，把這股悶氣發洩出去。", "q": 3, "tag": "⚠ 把沒來由的低氣壓倒在別人身上——悶氣沒消，還在情感帳戶提了一大筆款（第四層）。明天你要花更多力氣去修。"}, {"t": "承認它：「我今天就是低。」然後做件小小喜歡的事。", "q": 0, "tag": "✓ 「承認＋小事」是金泉的標準充電流程。神奇的是：不跟低氣壓打架之後，它反而走得比較快——情緒是天氣，會過境的。"}, {"t": "「我幹嘛心情差？沒理由啊！振作一點！」（自我訓話）", "q": 2, "tag": "對低氣壓喊話，像對下雨的天空生氣——雨不會停，你還多了「連心情都管不好」的二次傷害。心情不需要理由，也不需要被罵。"}]}, {"h": 6, "text": "今晚的餐桌，照例安靜。你決定試著開機。怎麼開？", "c": [{"t": "扒完飯就回房間，反正聊不起來。", "q": 3, "tag": "⚠ 你連開機鍵都沒按就關了電源——綠泉乾掉不是因為沒水源，是因為沒人去打水。明天那汪泉，還在餐桌對面等。"}, {"t": "「媽，妳國中都在玩什麼啊？那時候沒手機，你們很無聊吧？」", "q": 0, "tag": "✓ 媽媽愣了一下，然後笑出來：「無聊？我們那時候——」接下來二十分鐘，你聽到了媽媽翹課被阿嬤追打的傳說。問「他們的故事」，是重啟大人最快的開關。"}, {"t": "等他們先開口。他們是大人，要聊應該他們起頭吧。", "q": 1, "tag": "◐ 他們也在等你——大人面對青春期的小孩，其實跟你一樣不知道怎麼開口。這場「誰先講話」的對峙，先動的人先贏（第一層教過的）。"}, {"t": "「沒什麼好聊的啊，聊了又要被念。」", "q": 2, "tag": "「開口=被念」確實是歷史經驗——但你選的話題是「成績」以外的話題嗎？大人的念是預設模式，你得主動換頻道。"}]}, {"h": 6, "text": "聊開之後，爸爸難得多講了幾句。他說：「你長大了，都不知道你在想什麼。」語氣有點落寞。", "c": [{"t": "「知道啊，你們也不知道要跟我聊什麼啊。」", "q": 2, "tag": "句子內容是事實，語氣是反擊——爸爸點點頭不說話了。同一句話換個說法：「對欸，那我們來互相更新一下？」就是橋而不是牆。"}, {"t": "「哪有，我就⋯⋯都馬一樣。」（尷尬地扒飯）", "q": 1, "tag": "◐ 門開了一條縫，你輕輕把它帶上了。沒關係，今晚已經前進很多——但記住這個落寞的語氣，它是爸爸版的「已讀不回很難受」。"}, {"t": "「那以後一週吃一次『不准講功課』的晚餐？誰提考試誰洗碗。」", "q": 0, "tag": "✓ 爸爸大笑：「好啊，一言為定。」——你發明了一個家庭儀式。綠泉的維護不靠大和解，靠這種固定的、小小的、有點好笑的儀式。"}, {"t": "「長大本來就會這樣啊，正常啦。」", "q": 3, "tag": "⚠ 你用一句「正常啦」把他的落寞輕輕推開——他要的不是道理，是你接住那句「想多認識你」。橋遞到面前，別轉身。"}]}, {"h": 6, "text": "今晚九點，小美的電話又來了。螢幕亮著，你：", "c": [{"t": "嘆口氣接起來，被她講到半夜十一點半。", "q": 2, "tag": "金泉乾涸警報。第五層教你傾聽，但沒教你「無限傾聽」——一個乾掉的樹洞，最後會連「嗯」都說得心不在焉，那對朋友也不公平。"}, {"t": "不接，已讀她的訊息，明天裝沒事。", "q": 1, "tag": "◐ 躲得了今晚躲不了明早——而且「突然消失的樹洞」會讓她腦補一百種劇情。比起無聲的失蹤，一句「我今天沒電了，明天聊」誠實得多，也溫柔得多。"}, {"t": "接起來：「我聊到九點半，之後要留給自己。這段我認真聽。」", "q": 0, "tag": "✓ 她愣了一下：「⋯⋯好喔，那我撿重點講。」神奇的是，有時限的傾聽反而更有品質。界線不是拒絕——是讓「我願意聽」這件事能夠永續。"}, {"t": "接起來，但邊聽邊滑手機放空。", "q": 3, "tag": "⚠ 人在線、心不在——這是「假裝聽」（第五層第二層次）。她感覺得到，你也沒真的休息到。兩個人的時間一起浪費。"}]}, {"h": 6, "text": "劍靈問了一個尖銳的問題：「這些朋友裡——有誰，是你心情低的時候，你會打給他的？」", "c": [{"t": "「我不需要跟別人倒啦，我自己消化就好。」", "q": 1, "tag": "◐ 「都自己消化」聽起來很強，但第五層你學過——每個搶答的人背後都有沒被聽過的童年。別讓自己變成「幫全世界充電、自己卻沒有充電線」的人。"}, {"t": "「有吧⋯⋯應該有吧⋯⋯」（其實想不出名字）", "q": 2, "tag": "想不出名字，就是答案。這不丟臉——這是盤點。從今天起留意：誰聽你說話的時候，眼睛是認真的？那個人就是候選人。"}, {"t": "「當樹洞才有價值啊，倒給別人多沒面子。」", "q": 3, "tag": "⚠ 「示弱沒面子」正是讓你乾涸的咒語——只進不出的帳戶會破產，只供不充的樹洞會枯。開口求助不是沒面子，是讓友情雙向。"}, {"t": "「⋯⋯我數了一下。好像，沒有。我都是聽的那個。」", "q": 0, "tag": "✓ 看見了嗎——你的綠泉是「單向供水」。健康的友情要雙向流動：下次你心情低的時候，試著開口一次。真朋友會接住你；接不住的，你也該知道。"}]}, {"h": 6, "text": "怎麼開口才不會像爸媽上身？", "c": [{"t": "「你最近氣色超差欸，要多運動啦！熬夜很不好！」", "q": 2, "tag": "阿哲：「⋯⋯你是我媽喔？」對話結束。你說的全對——而「全對的說教」是全世界最沒用的東西，第五層就教過了。"}, {"t": "算了，各人造業各人擔，他想睡他的。", "q": 1, "tag": "◐ 尊重他的選擇沒有錯。但「邀請」跟「說教」是兩回事——邀請被拒絕也不傷人。朋友快沒電的時候，遞一次充電線，是綠泉公民的義務。"}, {"t": "把講運動好處的長文章轉給他自己看。", "q": 3, "tag": "⚠ 他連看都不會點開——道理用「轉貼」送達，比當面說教更冷。人會為「一起做的邀約」動，不會為一篇文章動。"}, {"t": "「我跑完都去吃鹹酥雞，你陪我跑最後一圈，再一起吃？」", "q": 0, "tag": "✓ 鹹酥雞 > 健康講座。他來了——為了吃。三週後他默默從「走一圈」變「跑兩圈」。拉人充電的秘訣：把泉水包在他想要的東西裡。"}]}, {"h": 6, "text": "六週後，阿哲跑出興趣了，反過來揪你參加路跑。但比賽那天早上下大雨，他傳訊息：「下雨欸⋯⋯不然算了？」", "c": [{"t": "「你想算了就算了，反正我自己會跑。」", "q": 3, "tag": "⚠ 你把他推回了沙發——一句帶刺的「隨便你」，剛萌芽的習慣就斷在這裡。拉人下水的最後一哩，是給台階，不是給臉色。"}, {"t": "「蛤——是你揪我的欸，自己先落跑？」", "q": 2, "tag": "指責讓他更不想去了。他需要的不是罪惡感，是一個「雨天也想去」的理由——給理由，別給壓力。"}, {"t": "「好喔，那算了。」（其實有點失落）", "q": 1, "tag": "◐ 取消了。也沒怎樣——只是你心裡知道，剛萌芽的習慣最怕「第一次找到藉口」。下次的雨，會變成風；再下次,變成「有點累」。"}, {"t": "「小雨而已，裝備多帶一套。跑完去吃熱湯，搞不好還破紀錄。」", "q": 0, "tag": "✓ 你們在雨裡跑完全程，狼狽得像兩條落水狗，笑得像兩個白痴。多年後你們都會記得這場雨——共同的傻事，是綠泉最高純度的泉水。"}]}, {"h": 6, "text": "戰鬥開始。牠不動如山，但整片荒原開始抽取你的電量——站著就在掉電。 你的電量錶：87%。", "c": [{"t": "把四座泉的水一次喝光，灌滿電再硬拚。", "q": 3, "tag": "⚠ 泉水一次喝光就乾了——它要的是「輪流、持續」地補，不是一口氣灌爆。你灌滿那刻很爽，接下來無泉可回，正中牠下懷。"}, {"t": "完全不攻擊，躲在泉邊死守。", "q": 1, "tag": "◐ 守住了電量，但牠也毫髮無傷——而牠比你能等。「只充電不做事」跟「只做事不充電」是同一枚硬幣的兩面：都到不了終點。"}, {"t": "趁電量還滿，衝上去搶攻！速戰速決！", "q": 2, "tag": "三分鐘的猛攻，你的電量掉到 40%，牠掉了 2%。「趁有電拚一波」就是牠千年來的捕獵機制——急著燒完自己的人，燒得最快。"}, {"t": "穩住節奏：攻擊三回合，退到紅泉喝一口再上。", "q": 0, "tag": "✓ 你攻、退、充、再攻——電量穩定維持在 70% 以上。枯磨的眉頭第一次動了：牠的獵物從來不懂「節奏」這個字。"}]}];
